const fetchFitbitData = async (accessToken: string): Promise<{ sleepScore: number; steps: number; restingHeartRate: number } | null> => {
  try {
    const today = new Date().toISOString().split("T")[0];
    const [heartRes, sleepRes, activityRes] = await Promise.all([
      fetch("https://api.fitbit.com/1/user/-/activities/heart/date/today/1d.json", {
        headers: { Authorization: "Bearer " + accessToken },
      }),
      fetch(`https://api.fitbit.com/1.2/user/-/sleep/date/${today}.json`, {
        headers: { Authorization: "Bearer " + accessToken },
      }),
      fetch(`https://api.fitbit.com/1/user/-/activities/date/${today}.json`, {
        headers: { Authorization: "Bearer " + accessToken },
      }),
    ]);
    const heartData = heartRes.ok ? await heartRes.json() : null;
    const sleepData = sleepRes.ok ? await sleepRes.json() : null;
    const activityData = activityRes.ok ? await activityRes.json() : null;
    const restingHeartRate = heartData?.["activities-heart"]?.[0]?.value?.restingHeartRate ?? 0;
    const sleepScore = sleepData?.sleep?.[0]?.efficiency ?? 0;
    const steps = activityData?.summary?.steps ?? 0;
    if (!restingHeartRate && !sleepScore && !steps) return null;
    return { sleepScore, steps, restingHeartRate };
  } catch { return null; }
};

const refreshFitbitToken = async (refreshToken: string, clientId: string): Promise<{ access_token: string; refresh_token: string } | null> => {
  try {
    const res = await fetch("https://api.fitbit.com/oauth2/token", {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
        Authorization: "Basic " + btoa(clientId + ":"),
      },
      body: new URLSearchParams({ grant_type: "refresh_token", refresh_token: refreshToken }),
    });
    if (!res.ok) return null;
    return await res.json();
  } catch { return null; }
};
    
    const fetchWhoopRecovery = async (accessToken: string): Promise<{ recovery: number; strain: number; sleep: number } | null> => {
      try {
        const today = new Date().toISOString().split("T")[0];
        const yesterday = new Date(Date.now() - 86400000).toISOString().split("T")[0];
        const res = await fetch(`https://api.prod.whoop.com/developer/v1/recovery?start=${yesterday}&end=${today}`, {
          headers: { Authorization: "Bearer " + accessToken },
        });
        if (!res.ok) return null;
        const data = await res.json();
        const record = data?.records?.[0];
        if (!record) return null;
        return {
          recovery: Math.round(record.score?.recovery_score ?? 0),
          strain: Math.round((record.score?.strain ?? 0) * 10) / 10,
          sleep: Math.round(record.sleep?.score?.sleep_performance_percentage ?? 0),
        };
      } catch { return null; }
    };
    
    const refreshWhoopToken = async (refreshToken: string, clientId: string): Promise<{ access_token: string; refresh_token: string } | null> => {
      try {
        const res = await fetch("https://api.prod.whoop.com/oauth/oauth2/token", {
          method: "POST",
          headers: { "Content-Type": "application/x-www-form-urlencoded" },
          body: new URLSearchParams({ grant_type: "refresh_token", refresh_token: refreshToken, client_id: clientId, scope: "offline read:recovery read:sleep read:workout" }),
        });
        if (!res.ok) return null;
        return await res.json();
      } catch { return null; }
    };
    
    const loadWearableData = async (uid: string, profile: any, setUserProfile: (fn: any) => void) => {
      const todayStr = new Date().toDateString();
      if (profile?.wearableLastFetch === todayStr) return;
      const whoopRefresh = profile?.whoopRefreshToken;
      const whoopAccess = profile?.whoopAccessToken;
      const fitbitRefresh = profile?.fitbitRefreshToken;
      const fitbitAccess = profile?.fitbitAccessToken;
      if (!whoopRefresh && !whoopAccess && !fitbitRefresh && !fitbitAccess) return;
      let wearableData: any = profile?.wearableData || {};
      let token = whoopAccess;
      if (!token && whoopRefresh) {
        const refreshed = await refreshWhoopToken(whoopRefresh, WHOOP_CLIENT_ID);
        if (refreshed) {
          token = refreshed.access_token;
          await saveUserProfile(uid, { whoopAccessToken: refreshed.access_token, whoopRefreshToken: refreshed.refresh_token });
        }
      }
      if (!token) return;
      if (token) {
        const whoopData = await fetchWhoopRecovery(token);
        if (whoopData) wearableData = { ...wearableData, whoop: whoopData };
      }
      let fitbitToken = fitbitAccess;
      if (!fitbitToken && fitbitRefresh) {
        const refreshed = await refreshFitbitToken(fitbitRefresh, FITBIT_CLIENT_ID);
        if (refreshed) {
          fitbitToken = refreshed.access_token;
          await saveUserProfile(uid, { fitbitAccessToken: refreshed.access_token, fitbitRefreshToken: refreshed.refresh_token });
        }
      }
      if (fitbitToken) {
        const fitbitData = await fetchFitbitData(fitbitToken);
        if (fitbitData) wearableData = { ...wearableData, fitbit: fitbitData };
      }
      const updates = { wearableData: { ...wearableData, fetchedAt: new Date().toISOString() }, wearableLastFetch: todayStr };
      await saveUserProfile(uid, updates);
      setUserProfile((prev: any) => ({ ...prev, ...updates }));
    };
    
    const getWorkoutModifier = (profile: any): { setModifier: number; toneContext: string; bannerText: string; source: string } | null => {
      const whoop = profile?.wearableData?.whoop;
      const fitbit = profile?.wearableData?.fitbit;
      if (whoop) {
        const recovery = whoop.recovery;
        if (recovery >= 70) return null;
        if (recovery >= 40) return {
          setModifier: -1,
          toneContext: `User's Whoop recovery score is ${recovery}% today (moderate). Acknowledge this briefly and naturally — one sentence max. Adjust tone toward quality over intensity. Don't make it clinical.`,
          bannerText: `Whoop recovery at ${recovery}% — training smart today. Full intensity resumes when you're recovered.`,
          source: "Whoop",
        };
        return {
          setModifier: -1,
          toneContext: `User's Whoop recovery score is ${recovery}% today (low). Open with a one-sentence acknowledgment — warm, not alarming. Frame today as intentional recovery training, not a reduced workout. Never say "reduced."`,
          bannerText: `Whoop says recovery is at ${recovery}% today — we've adjusted to keep you moving without digging a hole.`,
          source: "Whoop",
        };
      }
      if (fitbit) {
        const sleepScore = fitbit.sleepScore;
        const rhr = fitbit.restingHeartRate;
        const isLowSleep = sleepScore && sleepScore < 70;
        const isElevatedHR = rhr && rhr > 68;
        if (!isLowSleep && !isElevatedHR) return null;
        if (isLowSleep) return {
          setModifier: -1,
          toneContext: `User's Fitbit sleep efficiency was ${sleepScore}% last night (low). Acknowledge this briefly and naturally — one sentence max. Frame today as quality over quantity.`,
          bannerText: `Fitbit shows sleep efficiency at ${sleepScore}% — keeping today's session controlled and quality-focused.`,
          source: "Fitbit",
        };
        return {
          setModifier: -1,
          toneContext: `User's Fitbit resting heart rate is elevated at ${rhr} bpm today. Factor this into your coaching tone — lean toward controlled effort over max output.`,
          bannerText: `Fitbit shows elevated resting heart rate today — training at controlled intensity.`,
          source: "Fitbit",
        };
      }
      return null;
    };
    
    const handleOAuthCallback = async (setUserProfile: (fn: any) => void) => {
      const url = new URL(window.location.href);
      const code = url.searchParams.get("code");
      const state = url.searchParams.get("state");
      const path = url.pathname;
      if (!code || !state) return;
    
      // Whoop callback
      if (path.includes("whoop-callback") || url.href.includes("whoop-callback")) {
        try {
          const res = await fetch("https://api.prod.whoop.com/oauth/oauth2/token", {
            method: "POST",
            headers: { "Content-Type": "application/x-www-form-urlencoded" },
            body: new URLSearchParams({
              grant_type: "authorization_code",
              code,
              client_id: WHOOP_CLIENT_ID,
              redirect_uri: window.location.origin + "/whoop-callback",
            }),
          });
          if (res.ok) {
            const tokens = await res.json();
            await saveUserProfile(state, {
              whoopAccessToken: tokens.access_token,
              whoopRefreshToken: tokens.refresh_token,
              wearableLastFetch: null,
            });
            setUserProfile((prev: any) => ({
              ...prev,
              whoopAccessToken: tokens.access_token,
              whoopRefreshToken: tokens.refresh_token,
              wearableLastFetch: null,
            }));
          }
        } catch (e) {
          console.error("Whoop callback error:", e);
        }
        window.history.replaceState({}, "", "/");
      }
    
      // Fitbit callback
      if (path.includes("fitbit-callback") || url.href.includes("fitbit-callback")) {
        try {
          const res = await fetch("https://api.fitbit.com/oauth2/token", {
            method: "POST",
            headers: {
              "Content-Type": "application/x-www-form-urlencoded",
              Authorization: "Basic " + btoa(FITBIT_CLIENT_ID + ":"),
            },
            body: new URLSearchParams({
              grant_type: "authorization_code",
              code,
              redirect_uri: FITBIT_REDIRECT_URI,
            }),
          });
          if (res.ok) {
            const tokens = await res.json();
            await saveUserProfile(state, {
              fitbitAccessToken: tokens.access_token,
              fitbitRefreshToken: tokens.refresh_token,
              wearableLastFetch: null,
            });
            setUserProfile((prev: any) => ({
              ...prev,
              fitbitAccessToken: tokens.access_token,
              fitbitRefreshToken: tokens.refresh_token,
              wearableLastFetch: null,
            }));
          }
        } catch (e) {
          console.error("Fitbit callback error:", e);
        }
        window.history.replaceState({}, "", "/");
      }
    };
    
