const sanitizeForFirestore = (obj: any): any => {
  if (Array.isArray(obj)) return obj.map(sanitizeForFirestore);
  if (obj && typeof obj === "object") {
    const clean: any = {};
    for (const key of Object.keys(obj)) {
      const val = obj[key];
      if (val !== undefined) clean[key] = sanitizeForFirestore(val);
    }
    return clean;
  }
  return obj ?? null;
};
const saveWorkoutSession = async (uid: string, session: any, sessionId?: string) => {
  try {
    const today = new Date().toISOString().split("T")[0];
    // Find today's existing session doc written by per-group saves
    let existingId: string | null = null;
    let existingWeights: Record<string, any> = {};
    try {
      const sessSnap = await getDocs(query(collection(db, "workoutSessions"), where("uid", "==", uid), where("date", "==", today)));
      if (!sessSnap.empty) {
        existingId = sessSnap.docs[0].id;
        existingWeights = sessSnap.docs[0].data()?.weightsLogged || {};
      }
    } catch {}
    const id = existingId || sessionId || `${uid}_${Date.now()}`;
    const mergedWeights = { ...existingWeights, ...(session.weightsLogged || {}) };
    await setDoc(doc(db, "workoutSessions", id), {
      uid,
      ...session,
      weightsLogged: mergedWeights,
      sessionId: id,
      date: today,
      completedAt: serverTimestamp(),
    });
    return id;
  } catch (e) {
    console.error("saveWorkoutSession error:", e);
    return null;
  }
};

// Fetch the user's full workout session history from Firestore
const fetchWorkoutHistory = async (uid: string): Promise<any[]> => {
  try {
    // Simple collection fetch — no index required, sort client-side
    const snap = await getDocs(query(collection(db, "workoutSessions"), where("uid", "==", uid)));
    return snap.docs
      .map(d => ({ id: d.id, ...d.data() }))
      .filter((s: any) => s.uid === uid)
      .sort((a: any, b: any) => {
        const aTime = a.completedAt?.toMillis ? a.completedAt.toMillis() : new Date(a.completedAt || 0).getTime();
        const bTime = b.completedAt?.toMillis ? b.completedAt.toMillis() : new Date(b.completedAt || 0).getTime();
        return bTime - aTime;
      });
  } catch (e) {
    console.error("fetchWorkoutHistory error:", e);
    return [];
  }
};

// ─── Invite Code System ───────────────────────────────────────────────────────

// Generate a cryptographically opaque invite code — AF-XXXXXX format
// 6 random alphanumeric chars (uppercase, no ambiguous chars like 0/O, 1/I)
// 36^6 = ~2.1 billion combinations — brute force is not viable
const INVITE_CODE_CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"; // no 0,O,1,I
const generateInviteCode = (): string => {
  let code = "AF-";
  for (let i = 0; i < 6; i++) {
    code += INVITE_CODE_CHARS[Math.floor(Math.random() * INVITE_CODE_CHARS.length)];
  }
  return code;
};

// Generate a batch of unique codes for a building
// Each code is stored in Firestore under inviteCodes/{code}
const generateBuildingCodes = async (buildingId: string, buildingName: string, units: {unitNumber: string}[]): Promise<{code: string, unit: string}[]> => {
  const generated: {code: string, unit: string}[] = [];
  try {
    for (const unit of units) {
      let code = generateInviteCode();
      // Ensure uniqueness — regenerate if collision (extremely unlikely)
      let attempts = 0;
      while (attempts < 10) {
        const existing = await getDocs(query(collection(db, "inviteCodes")));
        const codes = existing.docs.map(d => d.id);
        if (!codes.includes(code)) break;
        code = generateInviteCode();
        attempts++;
      }
      await setDoc(doc(db, "inviteCodes", code), {
        code,
        buildingId,
        buildingName,
        unitNumber: unit.unitNumber,
        status: "active", // active | deactivated
        createdAt: serverTimestamp(),
        usedBy: [], // array of uids that have used this code
      });
      generated.push({ code, unit: unit.unitNumber });
    }
  } catch (e) {
    console.error("generateBuildingCodes error:", e);
  }
  return generated;
};

// Validate an invite code at onboarding — returns code data or null
const validateInviteCode = async (code: string): Promise<any | null> => {
  if (!code || !code.startsWith("AF-") || code.length !== 9) return null;

  // ── DEV TEST CODE ──────────────────────────────────────────────────────────
  // AF-TEST01 always works for testing — remove before production launch
  if (code.trim().toUpperCase() === "AF-TEST01") {
    return {
      id: "AF-TEST01",
      buildingId: "test-building",
      buildingName: "AmenityFit Test Building",
      unitNumber: "101",
      status: "active",
      buildingEquipment: ["dumbbells", "barbell", "bench", "squat-rack", "cables", "cable-machine", "smith-machine", "kettlebells", "pull-up-bar", "leg-press", "leg-curl", "leg-extension", "chest-press-machine", "chest-fly-machine", "seated-row-machine", "treadmill", "bike", "elliptical", "stairmaster", "rowing-machine", "jump-rope", "resistance-bands", "trx", "swiss-ball", "medicine-balls", "bosu-ball"],
    };
  }
  // ──────────────────────────────────────────────────────────────────────────

  try {
    const codeRef = doc(db, "inviteCodes", code.trim().toUpperCase());
    const codeSnap = await getDoc(codeRef);
    if (!codeSnap.exists()) return null;
    const data = codeSnap.data();
    if (data.status !== "active") return null; // deactivated codes rejected
    let buildingEquipment: string[] = [];
    if (data.buildingId) {
      try {
        const buildingSnap = await getDoc(doc(db, "buildings", data.buildingId));
        if (buildingSnap.exists()) {
          const buildingData = buildingSnap.data();
          // Block churned buildings — code is structurally valid but building is inactive
          if (buildingData.subscription === "churned") return null;
          buildingEquipment = buildingData.equipment || [];
        }
      } catch (e) {
        console.error("validateInviteCode building fetch error:", e);
      }
    }
    return { id: codeSnap.id, ...data, buildingEquipment };
  } catch (e) {
    console.error("validateInviteCode error:", e);
    return null;
  }
};

// Mark a code as used by a uid (called after successful account creation)
const markCodeUsed = async (code: string, uid: string): Promise<void> => {
  try {
    const ref = doc(db, "inviteCodes", code);
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const usedBy = snap.data().usedBy || [];
      if (!usedBy.includes(uid)) {
        await setDoc(ref, { usedBy: [...usedBy, uid] }, { merge: true });
      }
    }
  } catch (e) {
    console.error("markCodeUsed error:", e);
  }
};

