const SplashScreen = ({ onFinish, onSecretAdmin }) => {
  const [tapCount, setTapCount] = useState(0);
  const tapTimer = React.useRef<any>(null);
  const finishTimer = React.useRef<any>(null);

  useEffect(() => {
    finishTimer.current = setTimeout(onFinish, 2500);
    return () => {
      clearTimeout(finishTimer.current);
      clearTimeout(tapTimer.current);
    };
  }, []);

  const handleLogoTap = () => {
    // Reset the auto-advance timer on each tap to give time to complete sequence
    clearTimeout(finishTimer.current);
    finishTimer.current = setTimeout(onFinish, 4000);

    const newCount = tapCount + 1;
    setTapCount(newCount);
    if (tapTimer.current) clearTimeout(tapTimer.current);
    if (newCount >= 5) {
      setTapCount(0);
      clearTimeout(finishTimer.current);
      onSecretAdmin();
      return;
    }
    tapTimer.current = setTimeout(() => setTapCount(0), 3000);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100vh", background: `linear-gradient(145deg, ${COLORS.background} 0%, ${COLORS.card} 100%)`, fontFamily: "'Inter', sans-serif" }}>
      <div onClick={handleLogoTap} style={{ marginBottom: 24, boxShadow: `0 20px 60px ${COLORS.primary}40`, width: 100, height: 100, borderRadius: 22, overflow: "hidden", cursor: "pointer", userSelect: "none" as const }}>
        <img src="https://res.cloudinary.com/dk5g9itw8/image/upload/Logo_rkq0cv" alt="AmenityFit" style={{ width: "120%", height: "120%", display: "block", objectFit: "cover", marginLeft: "-10%", marginTop: "-10%" }} />
      </div>
      <h1 style={{ color: COLORS.white, fontSize: 32, fontWeight: 800, margin: 0, letterSpacing: -1 }}>AmenityFit</h1>
      <p style={{ color: COLORS.textSecondary, fontSize: 14, marginTop: 8, letterSpacing: 2, textTransform: "uppercase" }}>Your Building. Your Gym. Your Plan.</p>
      {tapCount > 0 && (
        <p style={{ color: "transparent", fontSize: 10, marginTop: 40, userSelect: "none" as const }}>{tapCount}</p>
      )}
    </div>
  );
};

