// ─── Building Plan ────────────────────────────────────────────────────────────
// ─── AI Program Generation ────────────────────────────────────────────────────
const buildProgramSelectionPrompt = (profile: any) => {
  const previousPrograms = profile.previousPrograms || [];
  const cycleNumber = profile.cycleNumber || 1;
  const equipment = profile.equipmentPreference || "gym-and-bands";
  const experience = profile.experience || "beginner";
  const gender = profile.gender || "prefer_not";
  const age = parseInt(String(profile.age)) || 30;
  const sessionLength = Number(profile.sessionLength) || 60;
  const frequency = profile.frequency || 3;
  const injuries = profile.injuries || "none";

  

  // ── ACCESSIBILITY TRACK ─────────────────────────────────────────────────
  const accessibilityTrack = profile.accessibilityTrack || false;

  // ── DETERMINE USER'S CURRENT LEVEL ────────────────────────────────────────
  const progressionPhase = profile.progressionPhase || "pool-rotation"; // pool-rotation | exposure | transition
  const effectiveLevel = profile.effectiveLevel || experience; // may differ from stated if transitioning
  const isSenior = age >= 65;

  const levelKey = isSenior
    ? (effectiveLevel === "intermediate" || effectiveLevel === "advanced" ? "senior-intermediate" : "senior-beginner")
    : effectiveLevel;

  const equipKey = equipment === "gym" ? "gym"
    : equipment === "bands" ? "bands"
    : "gym-and-bands";

  const poolKey = `${levelKey}-${equipKey}`;
  const currentPool = pools[poolKey] || pools[`${levelKey}-gym-and-bands`] || [];

  // ── ROTATION LOGIC ────────────────────────────────────────────────────────
  // Last 3 programs are excluded — prevents back-to-back repeats
  // Programs 3+ cycles ago are fully eligible for reintroduction (feel like returning favorites)
  const recentPrograms = previousPrograms.slice(-3);
  const availableFromPool = currentPool.filter(k => !recentPrograms.includes(k));
  const neverDone = currentPool.filter(k => !previousPrograms.includes(k));
  const eligibleForReturn = previousPrograms.filter(p => !recentPrograms.includes(p) && currentPool.includes(p));

  // ── PROGRESSION PHASE DETECTION ───────────────────────────────────────────
  // Calculated from completion history stored in Firestore and passed through profile
  const cycleCompletionRates = profile.cycleCompletionRates || []; // array of 0-1 rates per past cycle
  const recentRates = cycleCompletionRates.slice(-3);
  const avgRecentCompletion = recentRates.length > 0
    ? recentRates.reduce((a: number, b: number) => a + b, 0) / recentRates.length
    : 0;
  const hasPeakCycle = recentRates.some((r: number) => r >= 0.9);
  const exposureCyclesCompleted = profile.exposureCyclesCompleted || 0;

  // Exposure phase: avg 80%+ over last 3 cycles, no more than 2 misses per cycle
  const readyForExposure = cycleNumber >= 3 && avgRecentCompletion >= 0.8 && progressionPhase === "pool-rotation";
  // Full transition: 3 exposure cycles at 80%+ with at least one 90%+ cycle
  const readyForTransition = progressionPhase === "exposure" && exposureCyclesCompleted >= 3
    && avgRecentCompletion >= 0.8 && hasPeakCycle;

  // Next level pool for exposure seeding hints
  const nextLevelMap: Record<string, string> = {
    "beginner": "intermediate",
    "senior-beginner": "senior-intermediate",
    "intermediate": "advanced",
    "senior-intermediate": "advanced",
  };
  const nextLevel = nextLevelMap[levelKey] || levelKey;
  const nextPoolKey = `${nextLevel}-${equipKey}`;
  const nextPool = pools[nextPoolKey] || [];

  // Gender preference for program matching
  const genderNote = gender === "male"
    ? "Prefer mens-specific programs when available. Avoid womens-specific programs."
    : gender === "female"
    ? "Prefer womens-specific programs when available. Avoid mens-specific programs."
    : "No gender preference — select based on best fit for goals and frequency.";

  // ── DETERMINISTIC PATH INJECTION ─────────────────────────────────────────
  // For advanced users on cycles 1-8, the path is pre-determined.
  // Claude confirms and selects — no guessing.
  const primaryGoal = profile.primaryGoal || "general_fitness";
  const isAdvancedPath = (effectiveLevel === "advanced") && cycleNumber <= 8 && !isSenior;
  const determinedProgramKey = isAdvancedPath
    ? getAdvancedProgramPath(gender, primaryGoal, frequency, cycleNumber)
    : null;
  const pathNote = isAdvancedPath && determinedProgramKey
    ? `DETERMINISTIC PATH ACTIVE: This user is on cycle ${cycleNumber} of their advanced ${primaryGoal} path. The correct next program is "${determinedProgramKey}". Select this program. Do not deviate unless it appears in their last 3 programs (recentPrograms), in which case select the next available program in their pool.`
    : "";

  // ── BUILD THE PROMPT ───────────────────────────────────────────────────────
  return `You are the AmenityFit program selection engine — a certified fitness router that thinks like an experienced personal trainer.

USER PROFILE:
- Name: ${profile.name || "Unknown"}
- Age: ${age}${age >= 65 ? " (senior — use senior programs)" : ""}
- Gender: ${gender}
- Current level: ${effectiveLevel}
- Progression phase: ${progressionPhase}
- Primary goal: ${profile.primaryGoal || "general_fitness"}
- Secondary goal: ${profile.secondaryGoal || "none"}
- Training frequency: ${frequency} days per week
- Session length: ${profile.sessionLength || 45} minutes
- Injuries/limitations: ${injuries}
- Equipment: ${equipment}
- Cycle number: ${cycleNumber}
- Programs completed last 3 cycles (EXCLUDED — never repeat): ${recentPrograms.length > 0 ? recentPrograms.join(", ") : "none"}
- Programs never done from current pool: ${neverDone.length > 0 ? neverDone.join(", ") : "none — all have been tried"}
- Programs eligible for reintroduction (done 3+ cycles ago): ${eligibleForReturn.length > 0 ? eligibleForReturn.join(", ") : "none yet"}
- Recent cycle completion rates: ${recentRates.length > 0 ? recentRates.map((r: number) => Math.round(r * 100) + "%").join(", ") : "not enough data"}

GENDER MATCHING:
${genderNote}

${pathNote ? `PATH ROUTING:\n${pathNote}\n` : ""}

PROGRESSION STATUS:
${readyForTransition
  ? `LEVEL TRANSITION READY: This user has earned progression to ${nextLevel}. Select a program from the next level pool to begin their transition. This is a significant milestone.`
  : readyForExposure
  ? `EXPOSURE PHASE: This user is ready to be challenged. Select from their current pool BUT the AI response should note that 1-2 next-level exercises should be seeded into the program at appropriate body-part days (same muscle group, natural progression of movement — never random). Next level pool for reference: ${nextPool.slice(0, 5).join(", ")}.`
  : `POOL ROTATION: Select the best program from the current pool. Prioritize programs never done yet before returning to older ones. Programs 3+ cycles ago feel fresh again — reintroduction is valid.`}

${accessibilityTrack ? "ACCESSIBILITY TRACK (silent — never mention in reason): Only select senior-beginner or senior-intermediate programs. No jumping, no barbell, controlled movements only.\n\n" : ""}SELECTION RULES (trainer mindset):
1. Never select from the last 3 cycles — always something fresh
2. Prioritize programs the user has never done from their pool before returning to older ones
3. Programs done 3+ cycles ago can come back — users appreciate returning to favorites when stronger
4. Match frequency preference — pick a program whose day structure fits their ${frequency}x/week preference
5. If injuries listed, avoid heavy compound barbell work on affected joints
6. For advanced athletes, respect the monthly progression order: athletic or hypertrophy month-1 → month-2 → month-3
7. Think like a trainer: what would logically follow what they just finished? Progress volume, intensity, or focus area
8. ${age >= 65 ? "SENIOR: Always use senior-appropriate programs. No barbell heavy lifting." : ""}

CURRENT POOL (available to this user):
${availableFromPool.length > 0 ? availableFromPool.join("\n") : "All pool programs recently used — select best from full pool avoiding last 3"}

Respond with ONLY a JSON object, nothing else:
{
  "programKey": "the-selected-key",
  "reason": "One sentence explaining why this program fits this user right now.",
  "progressionUpdate": ${readyForTransition ? '"transition"' : readyForExposure ? '"exposure"' : '"none"'}
}`;
};


// Returns { programKey, profileUpdates } so the caller can update progression state
// ─── Month 4+ Program Generation ─────────────────────────────────────────────
// Activates when pool is exhausted and user hasn't earned level transition yet.
// Takes a matching base program from the 74, swaps 1 exercise per superset
// with a verified alternative the user hasn't seen, keeps structure identical.
const generateMonth6Program = (profile: any): { programKey: string; generatedDays?: any[] } => {
  const previousPrograms = profile.previousPrograms || [];
  const experience = profile.effectiveLevel || profile.experience || "beginner";
  const equipment = profile.equipmentPreference || "gym-and-bands";
  const injuries = profile.injuries || "";
  const frequency = profile.frequency || 3;
  const age = parseInt(String(profile.age)) || 30;
  const sessionLength = Number(profile.sessionLength) || 60;
  const isSenior = age >= 65;

  // Build the valid exercise pool — VIMEO + EXERCISES_DATA verified only
  const validExerciseIds = Object.keys(EXERCISES_DATA).filter(
    id => (VIMEO_VIDEOS as any)[id] && (VIMEO_VIDEOS as any)[id].vimeoIds?.length > 0
  );

  // Get all exercises the user has seen across their history
  const seenExerciseIds: string[] = [];
  previousPrograms.forEach((pk: string) => {
    const prog = PROGRAMS[pk];
    if (!prog) return;
    prog.days?.forEach((day: any) => {
      if (!day.isRest && day.groups) {
        day.groups.forEach((g: any) => {
          g.exercises?.forEach((e: any) => {
            if (e.id && !seenExerciseIds.includes(e.id)) seenExerciseIds.push(e.id);
          });
        });
      }
    });
  });

  // Parse injury flags
  const injuryFlags: string[] = [];
  if (injuries && injuries !== "none") {
    const text = injuries.toLowerCase();
    if (text.includes("knee") || text.includes("acl") || text.includes("mcl") || text.includes("pcl") || text.includes("meniscus") || text.includes("patellar") || text.includes("patella")) {
      injuryFlags.push("knee-deep-flexion");
      injuryFlags.push("knee-impact");
      injuryFlags.push("knee-shear");
    }
    if (text.includes("back") || text.includes("spine") || text.includes("lumbar") || text.includes("disc") || text.includes("disk") || text.includes("herniat") || text.includes("sciatica") || text.includes("scoliosis") || text.includes("vertebr")) {
      injuryFlags.push("lumbar-extension");
      injuryFlags.push("lumbar-flexion-loaded");
      injuryFlags.push("lumbar-hinge-heavy");
      injuryFlags.push("lumbar-rotation-loaded");
    }
    if (text.includes("shoulder") || text.includes("rotator") || text.includes("labrum") || text.includes("cuff") || text.includes("ac joint") || text.includes("bursitis")) {
      injuryFlags.push("shoulder-impingement");
      injuryFlags.push("shoulder-overhead");
    }
    if (text.includes("wrist")) {
      injuryFlags.push("wrist-load");
    }
    if (text.includes("neck") || text.includes("cervical")) {
      injuryFlags.push("neck-flexion");
    }
    if (text.includes("elbow")) {
      injuryFlags.push("elbow-load");
    }
    if (text.includes("hip")) {
      injuryFlags.push("hip-flexion-loaded");
    }
    if (text.includes("ankle") || text.includes("foot")) {
      injuryFlags.push("ankle-impact");
    }
  }

  // Equipment compatibility check
  const isEquipmentCompatible = (exEquipment: string, exId: string = ""): boolean => {
    if (!exEquipment) return false;
    const eq = exEquipment.toLowerCase();
    const id = exId.toLowerCase();
    if (equipment === "bands") return eq.includes("band") || eq.includes("bodyweight") || eq.includes("resistance") || id.includes("band");
    if (equipment === "gym") return !eq.includes("band") && !id.startsWith("band-");
    return true;
  };

  const isAppropriateForLevel = (ex: any, exId: string): boolean => {
    const name = (ex.name || "").toLowerCase();
    const id = exId.toLowerCase();
    if (experience === "advanced" || experience === "intermediate") {
      if (name.includes("modified") || name.includes("Modified")) return false;
      if (name.includes("assisted") || name.includes("Assisted")) return false;
      if (id.includes("senior") || name.includes("senior") || name.includes("Senior")) return false;
      if (name.includes("stationary march") || name.includes("Stationary March")) return false;
      if (name.includes("garland pose") || name.includes("Garland Pose")) return false;
      if (name.includes("seated march") || name.includes("Seated March")) return false;
      if (name.includes("wall sit march") || name.includes("Wall Sit March")) return false;
    }
    if (experience === "advanced") {
      if (name.includes("high plank") || name.includes("High Plank") || id.includes("high-plank")) return false;
      if (ex.difficulty === "beginner" && (
        name.includes("march") || name.includes("March") ||
        name.includes("pose") || name.includes("Pose") ||
        name.includes("toe tap") || name.includes("Toe Tap") ||
        name.includes("modified") || name.includes("Modified") ||
        name.includes("step touch") || name.includes("Step Touch") ||
        name.includes("low platform") || name.includes("Low Platform") ||
        id.includes("step-touch") ||
        id.includes("low-platform") ||
        id === "lying-alternate-leg-raise"
      )) return false;    }
    return true;
  };

// Find best substitute for an exercise
const findSubstitute = (originalId: string, usedInDay: string[], groupMuscles: string[] = [], isPrimary: boolean = false): string | null => {
    const original = (EXERCISES_DATA as any)[originalId];
    if (!original) return null;
    const targetMuscle = original.muscle;
    const targetDifficulty = original.difficulty || experience;

    const preferredCandidates = validExerciseIds
    .filter(id => {
      if (id === originalId) return false;
      if (usedInDay.includes(id)) return false;
      if (usedInProgram.includes(id)) return false;
      const ex = (EXERCISES_DATA as any)[id];
      if (!ex) return false;
      if (ex.muscle === "Cardio") return false;
      if (ex.muscle !== targetMuscle) return false;
      // Don't pick a substitute whose muscle is already represented elsewhere in the group
      if (groupMuscles.filter(m => m === ex.muscle).length > 1) return false;
      if (!isEquipmentCompatible(ex.equipment, id)) return false;
      if (ex.injuryFlags?.some((f: string) => injuryFlags.includes(f))) return false;
      if (!isAppropriateForLevel(ex, id)) return false;
      // Don't swap in a time-based exercise if original is reps-based
      const originalEx = (EXERCISES_DATA as any)[originalId];
      if (!originalEx?.isTime && ex.isTime) return false;
      // Exclude movement patterns already used elsewhere in the program
      if (!isPrimary) {
        const _pmv = ["step-up","step up","split squat","bulgarian","extension","pushdown","kickback","raise","fly","curl","crunch","twist","bridge","thrust","pulldown","pullup","shrug","pull-through","swing"];
        const _pMv = _pmv.find(kw => (ex.name+" "+id).toLowerCase().includes(kw)) || null;
        if (_pMv && usedMovementsInProgram.includes(_pMv)) return false;
      }
      // Exclude exercises whose movement pattern already exists in the day
      const movementKeywords = ["pullthrough", "pull-through", "row", "press", "curl", "fly", "raise", "extension", "pushdown", "pulldown", "squat", "deadlift", "lunge", "thrust", "crunch", "plank", "twist", "bridge", "dip", "pullup", "pushup", "swing", "kickback", "shrug", "good-morning", "good morning", "romanian", "rdl", "hip hinge", "glute bridge", "hip thrust", "step-up", "step up", "split squat", "bulgarian"];
      const getMovementKey = (name: string, id: string) => {
        const combined = (name + " " + id).toLowerCase();
        return movementKeywords.find(kw => combined.includes(kw)) || null;
      };
      const candidateMovement = getMovementKey(ex.name, id);
      const tooSimilar = usedInDay.some(usedId => {
        const usedEx = (EXERCISES_DATA as any)[usedId];
        if (!usedEx) return false;
        if (candidateMovement && getMovementKey(usedEx.name, usedId) === candidateMovement) return true;
        const exNameCore = ex.name.toLowerCase().split(" ").slice(0, 3).join(" ");
        const usedCore = usedEx.name.toLowerCase().split(" ").slice(0, 3).join(" ");
        return exNameCore === usedCore;
      });
      if (tooSimilar) return false;
      return true;
    })
      .map(id => {
        const ex = (EXERCISES_DATA as any)[id];
        let score = 0;
        // Prefer exercises they haven't seen — this is the whole point
        if (!seenExerciseIds.includes(id)) score += 50;
       
        // Same equipment
        if (ex.equipment === original.equipment) score += 30;
        // Same difficulty
        if (ex.difficulty === targetDifficulty) score += 20;
        // Slightly harder is good for progression
        if (ex.difficulty === "intermediate" && targetDifficulty === "beginner") score += 10;
        if (ex.difficulty === "advanced" && targetDifficulty === "intermediate") score += 10;
        // Movement pattern match — extract key movement words from original ID and match
        const originalWords = originalId.toLowerCase().replace(/-/g, " ").split(" ").filter(w => w.length > 3);
        const candidateWords = id.toLowerCase().replace(/-/g, " ").split(" ");
        const movementMatchCount = originalWords.filter(w => candidateWords.includes(w)).length;
        if (movementMatchCount >= 2) score += 80;
        else if (movementMatchCount === 1) score += 40;
        return { id, score };
      })
      .sort((a, b) => b.score - a.score);

      const candidates = preferredCandidates.length > 0 ? preferredCandidates : validExerciseIds
      .filter(id => {
        if (id === originalId) return false; 
        if (usedInDay.includes(id)) return false;
        if (usedInProgram.includes(id)) return false;
        const ex = (EXERCISES_DATA as any)[id];
        if (!ex) return false;
        if (ex.muscle === "Cardio") return false;
        if (ex.muscle !== targetMuscle) return false;
        if (!isEquipmentCompatible(ex.equipment, id)) return false;
        if (!isPrimary) {
          const _mv = ["step-up","step up","split squat","bulgarian","extension","pushdown","kickback","raise","fly","curl","crunch","twist","bridge","thrust","pulldown","pullup","shrug","pull-through","swing"];
          const _getMv = (n: string, i: string) => { const c = (n+" "+i).toLowerCase(); return _mv.find(kw => c.includes(kw)) || null; };
          const _cMv = _getMv(ex.name, id);
          if (_cMv && usedMovementsInProgram.includes(_cMv)) return false;
        }
        if (ex.injuryFlags?.some((f: string) => injuryFlags.includes(f))) return false;
        if (!isAppropriateForLevel(ex, id)) return false;
        const origEx = (EXERCISES_DATA as any)[originalId];
        if (!origEx?.isTime && ex.isTime) return false;
        const movementKeywords = ["pullthrough","pull-through","row","press","curl","fly","raise","extension","pushdown","pulldown","squat","deadlift","lunge","thrust","crunch","plank","twist","bridge","dip","pullup","pushup","swing","kickback","shrug","good-morning","good morning","romanian","rdl","hip hinge","glute bridge","hip thrust","step-up","step up","split squat","bulgarian"];
        const getMovementKey = (name: string, id: string) => { const combined = (name + " " + id).toLowerCase(); return movementKeywords.find(kw => combined.includes(kw)) || null; };
        const candidateMovement = getMovementKey(ex.name, id);
        return !usedInDay.some(usedId => { const usedEx = (EXERCISES_DATA as any)[usedId]; if (!usedEx) return false; if (candidateMovement && getMovementKey(usedEx.name, usedId) === candidateMovement) return true; const exNameCore = ex.name.toLowerCase().split(" ").slice(0,3).join(" "); const usedCore = usedEx.name.toLowerCase().split(" ").slice(0,3).join(" "); return exNameCore === usedCore; });
      });
      
      return candidates.length > 0 ? candidates[0].id : null;
  };

  // Select base program — pick one from their pool they've done least recently
  const levelKey = isSenior
    ? (experience === "intermediate" || experience === "advanced" ? "senior-intermediate" : "senior-beginner")
    : experience;
  const equipKey = equipment === "gym" ? "gym" : equipment === "bands" ? "bands" : "gym-and-bands";
  const poolKey = `${levelKey}-${equipKey}`;

  // Find a base program that matches frequency and hasn't been used in last 3 cycles
  const recentPrograms = previousPrograms.slice(-3);
  const allPoolPrograms = Object.keys(PROGRAMS).filter(key => {
    const prog = PROGRAMS[key];
    if (!prog) return false;
    if (recentPrograms.includes(key)) return false;
    // Match level
    if (isSenior && !key.includes("senior")) return false;
    if (!isSenior && key.includes("senior")) return false;
    // Match experience level
    const levelKey = isSenior
      ? (experience === "intermediate" || experience === "advanced" ? "senior-intermediate" : "senior-beginner")
      : experience;
    if (experience === "beginner" && (key.includes("intermediate") || key.includes("advanced"))) return false;
    if (experience === "intermediate" && key.includes("advanced") && !key.includes("intermediate")) return false;
    if (experience === "advanced" && !key.includes("advanced")) return false;
    // Match equipment preference roughly
    if (equipment === "bands" && !key.includes("band")) return false;
    if (equipment === "gym" && key.includes("band")) return false;
    return true;
  });

  // Pick the base program — prefer ones done longest ago
  const baseKey = allPoolPrograms.find(k => !previousPrograms.includes(k))
    || allPoolPrograms[0]
    || Object.keys(PROGRAMS)[0];

  const baseProgram = PROGRAMS[baseKey];
  if (!baseProgram) return { programKey: baseKey };

  // Generate fresh days by swapping 1 exercise per superset
  const usedInProgram: string[] = [];
  const usedMovementsInProgram: string[] = [];
  // Calculate rest days from frequency — ignore base program rest structure
  const restDaysByFrequency: Record<number, number[]> = {
    6: [7],
    5: [4, 7],
    4: [3, 5, 7],
    3: [2, 4, 6, 7],
    2: [2, 4, 5, 6, 7],
  };
  const restDays = restDaysByFrequency[frequency] || [7];

  const generatedDays = Array.from({ length: 7 }, (_, i) => {
    const dayNum = i + 1;
    if (restDays.includes(dayNum)) return {
      dayNum,
      title: `Day ${dayNum} — Rest`,
      type: "rest",
      focus: "Recovery",
      isRest: true,
      notes: ["Recovery is part of the program.", "Use this day to stretch, walk, or just rest.", "Your next session will be stronger for it."],
      groups: [],
    };
    // Find matching workout day from base program — preserve exact day order, no cycling
    const workoutDayIndex = Array.from({ length: dayNum }, (_, j) => j + 1)
      .filter(d => !restDays.includes(d)).length - 1;
    const workoutDays = baseProgram.days.filter((d: any) => !d.isRest);
    // Use exact index if available — only fall back to modulo if base program has fewer days than needed
    const isReplayDay = !workoutDays[workoutDayIndex];
    const baseDay = workoutDays[workoutDayIndex] || workoutDays[workoutDayIndex % workoutDays.length];
    if (!baseDay) return {
      dayNum,
      title: `Day ${dayNum} — Rest`,
      type: "rest",
      focus: "Recovery",
      isRest: true,
      notes: ["Recovery is part of the program.", "Use this day to stretch, walk, or just rest.", "Your next session will be stronger for it."],
      groups: [],
    };
    const day = { ...baseDay, dayNum, title: baseDay.title.replace(/Day \d+/, `Day ${dayNum}`) };
    const usedInDay: string[] = [];
    const newGroups = day.groups.map((group: any) => {
      if (group.type === "cardio") return group;
      const exercises = (group.exercises || []).filter((ex: any) => {
        const exData = (EXERCISES_DATA as any)[ex.id];
        if (!exData) return true;
        return isAppropriateForLevel(exData, ex.id);
      });
      let swappedInGroup = false;
      // Identify the primary compound — never swap it (first exercise in group)
      const newExercises = exercises.map((ex: any, index: number) => {
        // Primary compound (index 0) — swap if equipment incompatible, injury flagged, OR already used earlier this week
        if (index === 0) {
          const equipmentIncompatible = !isEquipmentCompatible((EXERCISES_DATA as any)[ex.id]?.equipment || "", ex.id);
          const alreadyUsedThisWeek = usedInProgram.includes(ex.id);
          const injuryBlocked = injuryFlags.length > 0 && (EXERCISES_DATA as any)[ex.id]?.injuryFlags?.some((f: string) => injuryFlags.includes(f));
          
          if (equipmentIncompatible || alreadyUsedThisWeek || injuryBlocked) {
            const substitute = findSubstitute(ex.id, [...usedInDay, ...(isReplayDay ? [] : usedInProgram)], [], true)
              || findSubstitute(ex.id, usedInDay, [], true)
              || (isReplayDay ? validExerciseIds.find(id => {
                  if (usedInDay.includes(id)) return false;
                  const exData = (EXERCISES_DATA as any)[id];
                  if (!exData) return false;
                  if (exData.muscle !== (EXERCISES_DATA as any)[ex.id]?.muscle) return false;
                  if (!isEquipmentCompatible(exData.equipment, id)) return false;
                  if (injuryFlags.length > 0 && exData.injuryFlags?.some((f: string) => injuryFlags.includes(f))) return false;
                  if (!isAppropriateForLevel(exData, id)) return false;
                  return true;
                }) : null);
            if (substitute) {
              usedInDay.push(substitute);
              if (!usedInProgram.includes(substitute)) {
                usedInProgram.push(substitute);
                const _subEx = (EXERCISES_DATA as any)[substitute];
                const _subMv = ["pullthrough","pull-through","row","press","curl","fly","raise","extension","pushdown","pulldown","squat","deadlift","lunge","thrust","crunch","plank","twist","bridge","dip","pullup","pushup","swing","kickback","shrug","good-morning","good morning","romanian","rdl","hip hinge","glute bridge","hip thrust","step-up","step up","split squat","bulgarian"];
                const _getMvKey = (n: string, i: string) => { const c = (n+" "+i).toLowerCase(); return _subMv.find(kw => c.includes(kw)) || null; };
                const _mv = _subEx ? _getMvKey(_subEx.name, substitute) : null;
                if (_mv && !usedMovementsInProgram.includes(_mv)) usedMovementsInProgram.push(_mv);
              }
              return { ...ex, id: substitute };
            }
            // No substitute found — try loose pass: only injury + equipment, ignore usedInProgram
            const looseSubstitute = validExerciseIds.find(id => {
              if (id === ex.id || usedInDay.includes(id)) return false;
              const exData = (EXERCISES_DATA as any)[id];
              if (!exData) return false;
              if (exData.muscle !== (EXERCISES_DATA as any)[ex.id]?.muscle) return false;
              if (!isEquipmentCompatible(exData.equipment, id)) return false;
              if (injuryFlags.length > 0 && exData.injuryFlags?.some((f: string) => injuryFlags.includes(f))) return false;
              if (!isAppropriateForLevel(exData, id)) return false;
              return true;
            });
            if (looseSubstitute) {
              usedInDay.push(looseSubstitute);
              if (!usedInProgram.includes(looseSubstitute)) usedInProgram.push(looseSubstitute);
              return { ...ex, id: looseSubstitute };
            }
            usedInDay.push(ex.id);
            if (!usedInProgram.includes(ex.id)) usedInProgram.push(ex.id);
          }
          usedInDay.push(ex.id);
          if (!usedInProgram.includes(ex.id)) {
            usedInProgram.push(ex.id);
            const _exData = (EXERCISES_DATA as any)[ex.id];
            const _exMvKws = ["pullthrough","pull-through","row","press","curl","fly","raise","extension","pushdown","pulldown","squat","deadlift","lunge","thrust","crunch","plank","twist","bridge","dip","pullup","pushup","swing","kickback","shrug","good-morning","good morning","romanian","rdl","hip hinge","glute bridge","hip thrust","step-up","step up","split squat","bulgarian"];
            const _exMv = _exData ? _exMvKws.find(kw => (_exData.name+" "+ex.id).toLowerCase().includes(kw)) || null : null;
            if (_exMv && !usedMovementsInProgram.includes(_exMv)) usedMovementsInProgram.push(_exMv);
          }
          return ex;
        }
        // Only swap 1 per group max — if already swapped one, keep the rest
        const alreadySwappedOne = swappedInGroup;
        if (alreadySwappedOne) {
          usedInDay.push(ex.id);
          return ex;
        }
        // Try to find a substitute
        const groupMuscleSoFar = exercises.slice(0, index).map((e: any) => (EXERCISES_DATA as any)[e.id]?.muscle).filter(Boolean);
        const substitute = findSubstitute(ex.id, [...usedInDay, ...usedInProgram], groupMuscleSoFar);
        if (substitute) {
          swappedInGroup = true;
          usedInDay.push(substitute);
          usedInProgram.push(substitute);
          const _accEx = (EXERCISES_DATA as any)[substitute];
          const _accMvKws = ["pullthrough","pull-through","row","press","curl","fly","raise","extension","pushdown","pulldown","squat","deadlift","lunge","thrust","crunch","plank","twist","bridge","dip","pullup","pushup","swing","kickback","shrug","good-morning","good morning","romanian","rdl","hip hinge","glute bridge","hip thrust","step-up","step up","split squat","bulgarian"];
          const _accMv = _accEx ? _accMvKws.find(kw => (_accEx.name+" "+substitute).toLowerCase().includes(kw)) || null : null;
          if (_accMv && !usedMovementsInProgram.includes(_accMv)) usedMovementsInProgram.push(_accMv);
          const subData = (EXERCISES_DATA as any)[substitute];
          const newReps = (!subData?.isTime && ex.reps?.toString().includes("secs")) ? "10-12" : ex.reps;
          return { ...ex, id: substitute, reps: newReps, _swapped: true };
        }
        usedInDay.push(ex.id);
        return ex;
      });
      return { ...group, exercises: newExercises };
    });
    // Cap groups to fit session length — 60 min = max 6 groups
    const maxGroups = sessionLength >= 60 ? 6 : sessionLength >= 45 ? 5 : 4;
    const cappedGroups = newGroups.slice(0, maxGroups);

    // Post-process: eliminate duplicate movement patterns across all groups in the day
    const movementKeywords = ["pullthrough", "pull-through", "row", "press", "curl", "fly", "raise", "extension", "pushdown", "pulldown", "squat", "deadlift", "lunge", "thrust", "crunch", "plank", "twist", "bridge", "dip", "pullup", "pushup", "swing", "kickback", "shrug", "good-morning", "good morning", "romanian", "rdl", "hip hinge", "glute bridge", "hip thrust", "step-up", "step up", "split squat", "bulgarian"];
    const getMovementKey = (name: string, id: string) => {
      const combined = (name + " " + id).toLowerCase();
      return movementKeywords.find(kw => combined.includes(kw)) || null;
    };
    const dayMovements: string[] = [];
    const dayExerciseIds: string[] = [];
    const deduplicatedGroups = cappedGroups.map((group: any) => {
      if (group.type === "cardio") return group;
      const newExercises = group.exercises.map((ex: any) => {
        const exData = (EXERCISES_DATA as any)[ex.id];
        const movement = exData ? getMovementKey(exData.name, ex.id) : null;
        const isDuplicate = movement && dayMovements.includes(movement);
        const isIdDuplicate = dayExerciseIds.includes(ex.id);
        const isInjuryBlocked = injuryFlags.length > 0 && (EXERCISES_DATA as any)[ex.id]?.injuryFlags?.some((f: string) => injuryFlags.includes(f));
        if (isDuplicate || isIdDuplicate || isInjuryBlocked) {
          // Force swap this exercise
          const substitute = findSubstitute(ex.id, dayExerciseIds, []);
          if (substitute) {
            const subData = (EXERCISES_DATA as any)[substitute];
            const subMovement = subData ? getMovementKey(subData.name, substitute) : null;
            const subInjuryBlocked = injuryFlags.length > 0 && subData?.injuryFlags?.some((f: string) => injuryFlags.includes(f));
            if (!subInjuryBlocked && (!subMovement || !dayMovements.includes(subMovement))) {
              dayExerciseIds.push(substitute);
              if (subMovement) dayMovements.push(subMovement);
              return { ...ex, id: substitute };
            }
          }
        }
        if (movement && !dayMovements.includes(movement)) dayMovements.push(movement);
        dayExerciseIds.push(ex.id);
        return ex;
      });
      return { ...group, exercises: newExercises };
    });

    // Regenerate title and focus based on actual muscle groups after all swaps
    const allMuscles: string[] = [];
    deduplicatedGroups.forEach((g: any) => {
      if (g.type === "cardio") { allMuscles.push("Cardio"); return; }
      (g.exercises || []).forEach((ex: any) => {
        const m = (EXERCISES_DATA as any)[ex.id]?.muscle;
        if (m && !allMuscles.includes(m)) allMuscles.push(m);
      });
    });
    const hasCardio = allMuscles.includes("Cardio");
    const muscleGroups = allMuscles.filter(m => m !== "Cardio");
    // Map muscle names to display labels
    const muscleToLabel: Record<string, string> = {
      "Chest": "Chest", "Back": "Back", "Shoulders": "Shoulders",
      "Triceps": "Triceps", "Biceps": "Biceps", "Quads": "Legs",
      "Hamstrings": "Legs", "Glutes": "Glutes", "Core": "Abs",
      "Full Body": "Full Body", "Cardio": "Cardio", "Calves": "Calves",
    };
    const uniqueLabels = [...new Set(muscleGroups.map(m => muscleToLabel[m] || m))];
    // Build concise title — max 3 muscle groups
    const titleParts = uniqueLabels.slice(0, 3);
    if (hasCardio && !titleParts.includes("Cardio") && titleParts.length < 3) titleParts.push("Cardio");
    const newTitle = titleParts.length > 0
      ? `Day ${dayNum} — ${titleParts.join(" & ")}`
      : `Day ${dayNum} — Full Body`;
    const newFocus = [...uniqueLabels.slice(0, 4), ...(hasCardio && !uniqueLabels.includes("Cardio") ? ["Cardio"] : [])].join(", ");
    // Determine type from dominant muscle groups
    const hasUpper = muscleGroups.some(m => ["Chest","Back","Shoulders","Triceps","Biceps"].includes(m));
    const hasLower = muscleGroups.some(m => ["Quads","Hamstrings","Glutes","Calves"].includes(m));
    const hasCore = muscleGroups.includes("Core");
    const newType = hasUpper && hasLower ? "full-body" : hasUpper ? "upper-body" : hasLower ? "lower-body" : hasCore ? "core" : "full-body";
    return { ...day, title: newTitle, focus: newFocus, type: newType, groups: deduplicatedGroups };
  }).filter(Boolean);

  // Clean up _swapped markers
  const cleanDays = generatedDays.map((day: any) => ({
    ...day,
    groups: (day.groups || []).map((g: any) => ({
      ...g,
      exercises: (g.exercises || []).map(({ _swapped, ...ex }: any) => ex),
    })),
  }));

  return { programKey: `month6-${baseKey}`, generatedDays: cleanDays };
};

