const generateAIProgram = async (profile: any): Promise<{ programKey: string; profileUpdates?: any; generatedDays?: any[] }> => {
  // ── Cycles 1-5: use deterministic goal-based routing ─────────────────────
  // Cycle 6+ activates Month 6+ AI generation
  const cycleNumber = profile.cycleNumber || 1;
  if (cycleNumber < 6) {
    const deterministicKey = selectProgram(profile);
    if (deterministicKey) return { programKey: deterministicKey };
  }

  // ── Month 6+ check ────────────────────────────────────────────────────────
  // Activates when pool is exhausted and user hasn't earned level transition
  const previousPrograms = profile.previousPrograms || [];
  const progressionPhase = profile.progressionPhase || "pool-rotation";
  const experience = profile.effectiveLevel || profile.experience || "beginner";
  const equipment = profile.equipmentPreference || "gym-and-bands";
  const age = parseInt(String(profile.age)) || 30;
  const sessionLength = Number(profile.sessionLength) || 60;
  const isSenior = age >= 65;

  // Injury-aware level key — steer structurally incompatible programs away at assignment time
  // Heavy knee injuries avoid lower-body dominant programs at advanced level
  // Heavy back injuries avoid hinge-heavy programs
  const injuryText = (profile.injuries || "none").toLowerCase();
  const hasKneeInjury = injuryText.includes("knee") || injuryText.includes("acl") || injuryText.includes("mcl") || injuryText.includes("meniscus");
  const hasBackInjury = injuryText.includes("back") || injuryText.includes("lumbar") || injuryText.includes("disc") || injuryText.includes("herniat") || injuryText.includes("sciatica");
  const hasShoulderInjury = injuryText.includes("shoulder") || injuryText.includes("rotator") || injuryText.includes("labrum");

  // Programs to avoid by injury type — exercise filter still runs as secondary protection
  const injuryAvoidKeys: string[] = [];
  if (hasKneeInjury) {
    injuryAvoidKeys.push(...[
      "sporty", "athletic", "hypertrophy",
    ].map(s => Object.keys(PROGRAMS).filter(k => k.includes(s))).flat());
  }
  if (hasBackInjury) {
    injuryAvoidKeys.push(...Object.keys(PROGRAMS).filter(k =>
      k.includes("iron-fist") || k.includes("strive-for-more")
    ));
  }
  if (hasShoulderInjury) {
    injuryAvoidKeys.push(...Object.keys(PROGRAMS).filter(k =>
      k.includes("athletic") || k.includes("sporty")
    ));
  }

  const levelKey = isSenior
    ? (experience === "intermediate" || experience === "advanced" ? "senior-intermediate" : "senior-beginner")
    : experience;
  const equipKey = equipment === "gym" ? "gym" : equipment === "bands" ? "bands" : "gym-and-bands";
  const poolKey = `${levelKey}-${equipKey}`;
  const currentPool = (pools as any)[poolKey] || [];
  const availableFromPool = currentPool.filter((k: string) =>
    !previousPrograms.includes(k) && !injuryAvoidKeys.includes(k)
  );
  const poolExhausted = availableFromPool.length === 0;
  const readyForTransition = progressionPhase === "exposure"
    && (profile.exposureCyclesCompleted || 0) >= 3
    && (profile.cycleCompletionRates?.slice(-3).reduce((a: number, b: number) => a + b, 0) / 3 || 0) >= 0.8
    && profile.cycleCompletionRates?.slice(-3).some((r: number) => r >= 0.9);

  // If ready for level transition, always transition first — even if pool is exhausted
  // This reopens a fresh pool at the new level and keeps users progressing correctly
  if (readyForTransition) {
    const levelMap: Record<string, string> = {
      beginner: "intermediate",
      intermediate: "advanced",
      "senior-beginner": "senior-intermediate",
      "senior-intermediate": "advanced",
    };
    const currentLevel = profile.effectiveLevel || profile.experience || "beginner";
    const newLevel = levelMap[currentLevel] || currentLevel;
    const newLevelKey = isSenior
      ? (newLevel === "intermediate" || newLevel === "advanced" ? "senior-intermediate" : "senior-beginner")
      : newLevel;
    const newPoolKey = `${newLevelKey}-${equipKey}`;
    const newPool = (pools as any)[newPoolKey] || [];
    const freshProgram = newPool[0] || selectProgram({ ...profile, experience: newLevel });
    return {
      programKey: freshProgram,
      profileUpdates: {
        effectiveLevel: newLevel,
        progressionPhase: "pool-rotation",
        exposureCyclesCompleted: 0,
        programSwaps: {},
      },
    };
  }

  if (cycleNumber >= 6) {
    // Alternate between pool programs and Month 6+ generation
    // Even cycles (6, 8, 10...) use remaining pool programs
    // Odd cycles (7, 9, 11...) use Month 6+ generation
    // Once pool is exhausted, permanently use Month 6+
    const isEvenCycle = cycleNumber % 2 === 0;
    if (isEvenCycle && availableFromPool.length > 0) {
      // Pick next unused pool program
      const nextProgram = availableFromPool[0];
      return {
        programKey: nextProgram,
        profileUpdates: { programSwaps: {} },
      };
    }
    // Odd cycle or pool exhausted — use Month 6+ generation
    const month6Result = generateMonth6Program(profile);
    return {
      programKey: month6Result.programKey,
      generatedDays: month6Result.generatedDays,
      profileUpdates: { programSwaps: {} },
    };
  }

  try {
    const response = await fetch(ANTHROPIC_PROXY_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-proxy-secret": "af-proxy-2026-xK9mQ3rL",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 300,
        system: "You are a fitness program selection engine. You respond only with valid JSON, no markdown, no explanation outside the JSON.",
        messages: [{ role: "user", content: buildProgramSelectionPrompt(profile) }],
      }),
    });
    const data = await response.json();
    const text = data.content?.[0]?.text || "";
    const clean = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);

    if (parsed.programKey && PROGRAMS[parsed.programKey]) {

      // Validate that AI-selected program is appropriate for user's current level
      // Prevents Claude from assigning an advanced program to a beginner
      const selectedProgram = PROGRAMS[parsed.programKey];
      const selectedLevel = selectedProgram?.level || selectedProgram?.difficulty || "";
      const userLevel = profile.effectiveLevel || profile.experience || "beginner";
      const levelRank: Record<string, number> = {
        beginner: 1,
        "senior-beginner": 1,
        intermediate: 2,
        "senior-intermediate": 2,
        advanced: 3,
      };
      const userRank = levelRank[userLevel] || 1;
      const selectedRank = levelRank[selectedLevel] || 1;

      // If AI selected a program more than one level above user, fall back to pool selection
      if (selectedRank > userRank + 1) {
        console.warn(`AI selected ${parsed.programKey} (${selectedLevel}) for ${userLevel} user — falling back to pool`);
        return { programKey: availableFromPool[0] || selectProgram(profile), profileUpdates: { programSwaps: {} } };
      }

      // Handle progression phase updates
      let profileUpdates: any = {};
      if (parsed.progressionUpdate === "transition") {
        // Full level transition — bump effectiveLevel
        const levelMap: Record<string, string> = {
          beginner: "intermediate",
          intermediate: "advanced",
          "senior-beginner": "senior-intermediate",
          "senior-intermediate": "advanced",
        };
        const currentLevel = profile.effectiveLevel || profile.experience || "beginner";
        profileUpdates = {
          effectiveLevel: levelMap[currentLevel] || currentLevel,
          progressionPhase: "pool-rotation",
          exposureCyclesCompleted: 0,
        };
      } else if (parsed.progressionUpdate === "exposure") {
        profileUpdates = {
          progressionPhase: "exposure",
          exposureCyclesCompleted: (profile.exposureCyclesCompleted || 0) + 1,
        };
      }

      return { programKey: parsed.programKey, profileUpdates: { ...profileUpdates, programSwaps: {}, levelTransition: !!profileUpdates.effectiveLevel } };
    }

    return { programKey: selectProgram(profile) };
  } catch (err) {
    console.error("AI program generation failed, using static fallback:", err);
    return { programKey: selectProgram(profile) };
  }
};

const BuildingPlanScreen = ({ userName, profile, onComplete }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [programKey, setProgramKey] = useState<string | null>(null);
  const [generatedDays, setGeneratedDays] = useState<any[] | undefined>(undefined);
  const [profileUpdates, setProfileUpdates] = useState<any>({});
  const steps = [
    "Verifying your building access...",
    "Reviewing your goals and experience...",
    "Matching your gym's equipment...",
    "Assembling your 30-day program...",
    "Your program is ready.",
  ];

  useEffect(() => {
    // Start AI generation in parallel while steps animate
    generateAIProgram(profile).then(result => {
      setProgramKey(result.programKey);
      if (result.generatedDays) setGeneratedDays(result.generatedDays);
      if (result.profileUpdates) setProfileUpdates(result.profileUpdates);
    });
    }, []);
  
    useEffect(() => {
      if (currentStep < steps.length - 1) {
        const timer = setTimeout(() => setCurrentStep((s) => s + 1), 900);
        return () => clearTimeout(timer);
      } else {
        // Wait for AI to finish before completing — max 3 extra seconds
        const check = setInterval(() => {
          if (programKey !== null) {
            clearInterval(check);
            onComplete(programKey, profileUpdates, generatedDays);
          }
        }, 200);
        const timeout = setTimeout(() => {
          clearInterval(check);
          onComplete(programKey || selectProgram(profile), {}, undefined);
        }, 3000);
        return () => { clearInterval(check); clearTimeout(timeout); };
      }
    }, [currentStep, programKey]);

  const progress = ((currentStep + 1) / steps.length) * 100;
  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "0 32px" }}>
      <div style={{ marginBottom: 32, width: 72, height: 72, borderRadius: 16, overflow: "hidden" }}>
        <img src="https://res.cloudinary.com/dk5g9itw8/image/upload/Logo_rkq0cv" alt="AmenityFit" style={{ width: "120%", height: "120%", display: "block", objectFit: "cover", marginLeft: "-10%", marginTop: "-5%" }} />
      </div>
      <h2 style={{ color: COLORS.white, fontSize: 26, fontWeight: 800, textAlign: "center", margin: "0 0 8px", letterSpacing: -0.5 }}>Building Your Program</h2>
      <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: "0 0 40px", textAlign: "center" }}>Hang tight{userName ? `, ${userName}.` : "."} This only takes a moment.</p>
      <div style={{ position: "relative", width: 120, height: 120, marginBottom: 40 }}>
        <svg width="120" height="120" style={{ transform: "rotate(-90deg)" }}>
          <circle cx="60" cy="60" r="52" fill="none" stroke={COLORS.border} strokeWidth="6" />
          <circle cx="60" cy="60" r="52" fill="none" stroke={COLORS.accent} strokeWidth="6" strokeLinecap="round"
            strokeDasharray={`${2 * Math.PI * 52}`}
            strokeDashoffset={`${2 * Math.PI * 52 * (1 - progress / 100)}`}
            style={{ transition: "stroke-dashoffset 0.7s ease" }} />
        </svg>
        <span style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", color: COLORS.white, fontSize: 22, fontWeight: 800 }}>{Math.round(progress)}%</span>
      </div>
      <div style={{ width: "100%", maxWidth: 320 }}>
        {steps.map((s, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", marginBottom: 12, opacity: i <= currentStep ? 1 : 0.3, transition: "opacity 0.4s ease" }}>
            <div style={{ width: 20, height: 20, borderRadius: 99, marginRight: 12, flexShrink: 0, background: i < currentStep ? COLORS.success : i === currentStep ? COLORS.accent : COLORS.border, display: "flex", alignItems: "center", justifyContent: "center", transition: "background 0.3s ease" }}>
              {i < currentStep && <Check size={11} color={COLORS.white} strokeWidth={3} />}
            </div>
            <p style={{ color: i === currentStep ? COLORS.white : i < currentStep ? COLORS.success : COLORS.textSecondary, fontSize: 14, margin: 0, fontWeight: i === currentStep ? 600 : 400, transition: "color 0.3s ease" }}>{s}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

