const CycleCompleteScreen = ({ profile, onStartNewCycle }) => {
  const [phase, setPhase] = useState<"celebrate" | "ready">("celebrate");
  const sessionsCompleted = profile.sessionsCompleted || 0;
  const cycleNumber = profile.cycleNumber || 1;
  const streak = profile.streak || 0;

  useEffect(() => {
    const timer = setTimeout(() => setPhase("ready"), 2800);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div style={{
      minHeight: "100vh", background: COLORS.background,
      fontFamily: "'Inter', sans-serif", display: "flex",
      flexDirection: "column", alignItems: "center", justifyContent: "flex-start",
      padding: "48px 20px 40px", overflowY: "auto", overflowX: "hidden",
      boxSizing: "border-box", width: "100%",
    }}>
      {/* Glow ring */}
      <div style={{
        width: 120, height: 120, borderRadius: 99, marginBottom: 28,
        background: `radial-gradient(circle, ${COLORS.accent}30 0%, transparent 70%)`,
        border: `2px solid ${COLORS.accent}50`,
        display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: `0 0 60px ${COLORS.accent}30`,
        transition: "all 0.6s ease",
      }}>
        <span style={{ fontSize: 52 }}>🏆</span>
      </div>

      <div style={{ display: "inline-flex", alignItems: "center", background: `${COLORS.accent}20`, borderRadius: 99, padding: "4px 14px", marginBottom: 16 }}>
        <span style={{ color: COLORS.accent, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase" }}>Cycle {cycleNumber} Complete</span>
      </div>

      <h1 style={{ color: COLORS.white, fontSize: 32, fontWeight: 900, textAlign: "center", margin: "0 0 10px", letterSpacing: -0.8, lineHeight: 1.1 }}>
        30 Days Done.
      </h1>
      <p style={{ color: COLORS.textSecondary, fontSize: 15, textAlign: "center", margin: "0 0 36px", lineHeight: 1.6 }}>
        You showed up, put in the work, and finished the program. That's not nothing. That's everything.
      </p>

      {/* Stats row */}
      <div style={{ display: "flex", gap: 10, width: "100%", marginBottom: 32 }}>
        {[
          { label: "Sessions Done", value: String(sessionsCompleted), color: COLORS.accent },
          { label: "Day Streak", value: String(streak), color: COLORS.success },
          { label: "Cycles", value: String(cycleNumber), color: COLORS.primary },
        ].map((stat, i) => (
          <div key={i} style={{
            flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 10px",
            border: `1px solid ${COLORS.border}`, textAlign: "center",
          }}>
            <p style={{ color: stat.color, fontSize: 22, fontWeight: 900, margin: "0 0 4px", letterSpacing: -0.5 }}>{stat.value}</p>
            <p style={{ color: COLORS.textSecondary, fontSize: 9, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.6, margin: 0, lineHeight: 1.3 }}>{stat.label}</p>
          </div>
        ))}
      </div>

      {/* New cycle preview */}
      {phase === "ready" && (
        <div style={{
          width: "100%", background: `${COLORS.primary}15`,
          border: `1px solid ${COLORS.primary}40`, borderRadius: 18,
          padding: "18px 20px", marginBottom: 24,
          animation: "fadeIn 0.5s ease",
        }}>
          <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 6px" }}>What's Next</p>
          <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: "0 0 4px" }}>Your Cycle {cycleNumber + 1} Program</p>
          <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, lineHeight: 1.5 }}>
            A fresh 30 days built on everything you just accomplished. Same structure, new exercises, higher bar.
          </p>
        </div>
      )}

      <button
        onClick={onStartNewCycle}
        disabled={phase !== "ready"}
        style={{
          width: "100%", padding: "18px", borderRadius: 16, border: "none",
          background: phase === "ready"
            ? `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`
            : COLORS.border,
          color: COLORS.white, fontSize: 16, fontWeight: 800,
          cursor: phase === "ready" ? "pointer" : "default",
          letterSpacing: 0.3, transition: "all 0.4s ease",
          boxShadow: phase === "ready" ? `0 8px 24px ${COLORS.primary}50` : "none",
          opacity: phase === "ready" ? 1 : 0.5,
        }}
      >
        {phase === "ready" ? "Start Cycle " + (cycleNumber + 1) : "Preparing your next program..."}
      </button>
    </div>
  );
};

