// Stable seed: changes daily but stays constant for the entire session
const _dailySeed = new Date().getDate() * 31 + new Date().getMonth() * 127;

// Returns a stable image for a given body part type, varied by program day so the user
// sees different images as they progress through the 30-day program
const getWorkoutImage = (type: string, programDay: number = 1): string => {
  const pool = IMAGE_POOLS[type] || IMAGE_POOLS["full-body"];
  // Use a hash that guarantees each type and programDay combination
  // picks a different image — even across types with similar pool sizes.
  // Large prime offsets prevent collisions between upper/push/pull which
  // share similar exercises and used to show the same hero image.
  const typeHash = type === "upper-body" ? 3 : type === "lower-body" ? 37 : type === "core" ? 71 : type === "push" ? 11 : type === "pull" ? 53 : type === "cardio" ? 29 : type === "rest" ? 97 : 19;
  const seed = (_dailySeed * 7 + programDay * 13 + typeHash) & 0x7FFFFFFF;
  return pool[seed % pool.length];
};

const Dashboard = ({ profile, onStartWorkout, workoutDoneToday = false, isInProgress = false, onNavigate = (s) => {}, onViewWeekly = () => {}, reEntryMode = false, reEntrySessions = 0, reEntryTarget = 6, wearableModifier = null, onWearableOverride = () => {} }) => {
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [notifLoading, setNotifLoading] = useState(false);

  React.useEffect(() => {
    if (!profile?.uid) return;
    const fetchNotifs = async () => {
      setNotifLoading(true);
      try {
        const snap = await getDocs(collection(db, "users", profile.uid, "notifications"));
        const thirtyDaysAgo = Date.now() / 1000 - 30 * 24 * 60 * 60;
        const notifs = snap.docs
          .map(d => ({ id: d.id, ...d.data() }))
          .filter((n: any) => (n.createdAt?.seconds || 0) >= thirtyDaysAgo)
          .sort((a: any, b: any) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0))
          .slice(0, 20);
        setNotifications(notifs);
      } catch (e) {}
      setNotifLoading(false);
    };
    fetchNotifs();
  }, [profile?.uid]);

  const unreadCount = notifications.filter((n: any) => !n.read).length;

  const markAllRead = async () => {
    if (!profile?.uid) return;
    const unread = notifications.filter((n: any) => !n.read);
    await Promise.all(unread.map(n =>
      setDoc(doc(db, "users", profile.uid, "notifications", n.id), { read: true }, { merge: true })
    ));
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  const getNotifIcon = (type: string) => {
    if (type === "pr") return "🏆";
    if (type === "streak") return "🔥";
    if (type === "level-up") return "⚡";
    if (type === "cycle-complete") return "📈";
    if (type === "welcome-back") return "👋";
    if (type === "building") return "🏢";
    return "✓";
  };

  const rawFirst = (profile.name || "Athlete").split(" ")[0];
  const userName = rawFirst.charAt(0).toUpperCase() + rawFirst.slice(1).toLowerCase();
  const sessionLength = profile.sessionLength || 45;
  const frequency = profile.frequency || 4;
  const experience = EXPERIENCE_LABELS[profile.experience] || "Intermediate";
  const goal = GOAL_LABELS[profile.primaryGoal] || "General Fitness";
  const rawProgramDay = profile.programDay || 1;
  const programWeek = profile.programWeek || 1;
  // Pin the displayed day to the workout actually being done today.
  // After completion programDay increments — we keep the hero and card showing
  // the day that was just completed until a genuinely new calendar day starts.
  const programDay = workoutDoneToday ? Math.max(rawProgramDay - 1, 1) : rawProgramDay;
  // Determine workout type from Day 1 of the matched program
  // When workout engine is built this will pull from actual scheduled day
  const currentDay = getProgramDay(profile.programKey || selectProgram(profile), programDay, profile?.generatedDays);
  const isCardioDay = currentDay.type === "cardio" || currentDay.groups?.every((g: any) => g.type === "cardio");
  const isRestDay = currentDay.isRest || currentDay.groups?.length === 0;
  const dayFocuses = currentDay.groups
    .filter(g => g.type !== "cardio")
    .map((g: any) => g.focus || "full");
  const hasUpper = dayFocuses.some((f: string) => f.includes("upper"));
  const hasLower = dayFocuses.some((f: string) => f.includes("lower"));
  const workoutType = isRestDay ? "rest" : isCardioDay ? "cardio" : hasUpper && hasLower ? "full-body" : hasLower ? "lower-body" : "upper-body";
  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", overflowY: "auto" }}>

      {/* Header */}
      <div style={{ padding: "52px 24px 8px", background: `linear-gradient(180deg, ${COLORS.primary}18 0%, transparent 100%)` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 4 }}>
          <div>
          <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 4px", fontWeight: 500 }}>{getGreeting()}</p>
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
              <h1 style={{ color: COLORS.white, fontSize: 28, fontWeight: 900, margin: 0, letterSpacing: -0.8 }}>{userName || "Athlete"}</h1>
              {(() => { const b = getMasteryBadge(profile?.cycleNumber || 1); return b ? <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.1, textTransform: "uppercase", color: b.color, background: b.bg, border: `1px solid ${b.border}`, borderRadius: 99, padding: "3px 10px 3px 7px", display: "inline-flex", alignItems: "center", gap: 5, opacity: reEntryMode ? 0.4 : 1, transition: "opacity 0.4s ease" }}>{b.icon === "crown" ? <Crown size={11} color={b.color} strokeWidth={2} /> : b.icon === "trophy" ? <Trophy size={11} color={b.color} strokeWidth={2} /> : b.icon === "shield" ? <Shield size={11} color={b.color} strokeWidth={2} /> : <Flame size={11} color={b.color} strokeWidth={2} />}{b.label}</span> : null; })()}
            </div>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
          <div
              onClick={() => { setShowNotifications(s => !s); if (!showNotifications) markAllRead(); }}
              style={{ width: 40, height: 40, borderRadius: 12, background: COLORS.card, border: `1px solid ${COLORS.border}`, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", position: "relative" }}
            >
              <Bell size={20} color={COLORS.white} strokeWidth={1.8} />
              {unreadCount > 0 && (
                <div style={{ position: "absolute", top: 6, right: 6, width: 8, height: 8, borderRadius: 99, background: COLORS.accent, border: `1.5px solid ${COLORS.background}` }} />
              )}
            </div>
            {showNotifications && (
              <div style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 998 }} onClick={() => setShowNotifications(false)} />
            )}
            {showNotifications && (
              <div style={{ position: "fixed", top: 100, left: 16, right: 16, background: COLORS.card, borderRadius: 20, border: `1px solid ${COLORS.border}`, zIndex: 999, maxHeight: "60vh", overflow: "hidden", display: "flex", flexDirection: "column", boxShadow: `0 20px 60px rgba(0,0,0,0.5)` }}>
                <div style={{ padding: "16px 20px 12px", borderBottom: `1px solid ${COLORS.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
                  <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: 0 }}>Notifications</p>
                  {unreadCount > 0 && (
                    <span style={{ background: `${COLORS.accent}20`, color: COLORS.accent, fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 99 }}>{unreadCount} new</span>
                  )}
                </div>
                <div style={{ overflowY: "auto", flex: 1 }}>
                  {notifLoading ? (
                    <div style={{ padding: "24px 20px", textAlign: "center" }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>Loading...</p>
                    </div>
                  ) : notifications.length === 0 ? (
                    <div style={{ padding: "32px 20px", textAlign: "center" }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 4px" }}>No notifications yet.</p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0, opacity: 0.6 }}>Complete workouts to earn them.</p>
                    </div>
                  ) : notifications.map((n: any) => (
                    <div key={n.id} style={{ padding: "14px 20px", borderBottom: `1px solid ${COLORS.border}`, display: "flex", alignItems: "flex-start", gap: 12, background: n.read ? "transparent" : `${COLORS.primary}10` }}>
                      <span style={{ fontSize: 18, flexShrink: 0, marginTop: 1 }}>{getNotifIcon(n.type)}</span>
                      <div style={{ flex: 1 }}>
                        <p style={{ color: COLORS.white, fontSize: 13, fontWeight: n.read ? 400 : 600, margin: "0 0 2px", lineHeight: 1.4 }}>{n.message}</p>
                        {n.createdAt?.seconds && (
                          <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>
                            {new Date(n.createdAt.seconds * 1000).toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                          </p>
                        )}
                      </div>
                      {!n.read && <div style={{ width: 6, height: 6, borderRadius: 99, background: COLORS.accent, flexShrink: 0, marginTop: 4 }} />}
                    </div>
                  ))}
                </div>
              </div>
            )}
            <div
              onClick={() => onNavigate("profile")}
              style={{ width: 40, height: 40, borderRadius: 12, overflow: "hidden", cursor: "pointer", boxShadow: `0 4px 12px ${COLORS.primary}40`, flexShrink: 0 }}
            >
              {profile?.profilePhoto ? (
                <img src={profile.profilePhoto} alt="Profile" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              ) : (
                <div style={{ width: "100%", height: "100%", background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <span style={{ color: COLORS.white, fontSize: 16, fontWeight: 900 }}>
                    {(profile?.name || "A")[0].toUpperCase()}
                  </span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Re-entry banner */}
      {reEntryMode && (
        <div style={{ margin: "0 24px 0", background: `${COLORS.primary}15`, border: `1px solid ${COLORS.primary}30`, borderRadius: 16, padding: "14px 16px" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <Flame size={14} color={COLORS.primary} strokeWidth={2} />
              <span style={{ color: COLORS.white, fontSize: 13, fontWeight: 700 }}>Re-Entry Mode</span>
            </div>
            <span style={{ color: COLORS.textSecondary, fontSize: 12 }}>{reEntrySessions} of {reEntryTarget} sessions</span>
          </div>
          <div style={{ width: "100%", height: 4, background: COLORS.border, borderRadius: 99 }}>
          <div style={{ width: `${Math.min((reEntrySessions / reEntryTarget) * 100, 100)}%`, height: 4, background: COLORS.primary, borderRadius: 99, transition: "width 0.4s ease" }} />
          </div>
          <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "8px 0 0", lineHeight: 1.5 }}>Complete {reEntryTarget - reEntrySessions} more session{reEntryTarget - reEntrySessions !== 1 ? "s" : ""} to reclaim your full programming.</p>
        </div>
      )}

{wearableModifier && !profile?.wearableOverride && (
        <WearableBanner modifier={wearableModifier} onOverride={onWearableOverride} />
      )}

      {/* Scrollable content */}
      <div style={{ flex: 1, padding: "16px 24px 80px", overflowY: "auto" }}>

        {/* Today's Workout */}
        <TodayWorkoutCard type={workoutType} sessionLength={sessionLength} experience={experience} programDay={programDay} programWeek={programWeek} workoutDoneToday={workoutDoneToday} isInProgress={isInProgress} onStartWorkout={onStartWorkout} dayFocus={currentDay?.focus} exerciseCount={(() => { const _g = filterGroupsForSessionLength(currentDay?.groups || [], sessionLength); const _e = filterExercisesByEquipment(_g, profile?.equipmentPreference || "gym-and-bands", profile?.buildingEquipment || []); const _v = filterExercisesByVideo(_e); const _i = filterExercisesByInjury(_v, profile?.injuries || "none", profile?.equipmentPreference || "gym-and-bands", profile?.buildingEquipment || []); return _i.filter((g: any) => g.type !== "cardio").reduce((sum: number, g: any) => sum + (g.exercises?.length || 0), 0); })()} />

        {/* View Full Week link */}
        <button onClick={onViewWeekly} style={{ width: "100%", padding: "12px", borderRadius: 12, border: `1px solid ${COLORS.border}`, background: "transparent", color: COLORS.textSecondary, fontSize: 13, fontWeight: 600, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 20, marginTop: -8 }}>
          <Calendar size={14} color={COLORS.textSecondary} />
          View Full Week
          <ChevronRight size={14} color={COLORS.textSecondary} />
        </button>
        <div style={{ display: "flex", gap: 12, marginBottom: 20 }}>
          <StatCard label="Streak" value={String(profile.streak || 0)} sub="days 🔥" icon={Flame} color="#FF6B35" />
          <StatCard label="Completed" value={String(profile.cycleSessionsCompleted || 0)} sub="sessions" icon={Trophy} color={COLORS.success} />
          <StatCard label="This Week" value={`${profile.sessionsThisWeek || 0}/${frequency}`} sub="workouts" icon={Calendar} color={COLORS.accent} />
        </div>

        {/* Program Progress */}
        <ProgramProgress goal={goal} experience={experience} frequency={frequency} />

        {/* Nutrition */}
        <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Nutrition</p>
        <NutritionCard onPress={() => onNavigate("nutrition")} />

        {/* Trainer's Playlist */}
        <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Trainer's Pick</p>
        <PlaylistCard />

        {/* Fitness Assistant */}
        <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Need Help?</p>
        <AssistantCard onPress={() => onNavigate("assistant")} />
        <div style={{ height: 60 }} />
      </div>

      <BottomNav active="home" onNavigate={onNavigate} />
    </div>
  );
};

// ─── Onboarding Controller ────────────────────────────────────────────────────
const OnboardingFlow = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const [legalScreen, setLegalScreen] = useState<"privacy" | "terms" | null>(null);
  const [data, setData] = useState({
    inviteCode: "",
    name: "", email: "", password: "", age: "", gender: "",
    heightFt: "", heightIn: "", weightLbs: "",
    heightCm: "", weightKg: "",
    primaryGoal: "", secondaryGoal: "",
    experience: "", frequency: null, sessionLength: null,
    injuries: "", equipmentPreference: "",
  });
  const update = (fields) => setData((prev) => ({ ...prev, ...fields }));
  const next = () => setStep((s) => s + 1);
  const back = () => setStep((s) => Math.max(1, s - 1));
  const props = { data, onChange: update, onNext: next, onBack: back };

  // Legal screens shown inline during onboarding — back returns to disclaimer
  if (legalScreen === "privacy") return <PrivacyPolicyScreen onBack={() => setLegalScreen(null)} />;
  if (legalScreen === "terms") return <TermsOfServiceScreen onBack={() => setLegalScreen(null)} />;

  // Step 0: Health disclaimer — no progress bar, no back button, must agree to proceed
  if (step === 0) return <HealthDisclaimerStep onAgree={next} onViewPrivacy={() => setLegalScreen("privacy")} onViewTerms={() => setLegalScreen("terms")} />;

  // Steps 1–13: Standard onboarding flow
  if (step === 1) return <Step1InviteCode {...props} />;
  if (step === 2) return <Step2Name {...props} />;
  if (step === 3) return <Step2bCreateAccount {...props} />;
  if (step === 4) return <Step3Age {...props} />;
  if (step === 5) return <Step4Gender {...props} />;
  if (step === 6) return <Step5HeightWeight {...props} />;
  if (step === 7) return <Step6PrimaryGoal {...props} />;
  if (step === 8) return <Step7SecondaryGoal {...props} />;
  if (step === 9) return <Step8Experience {...props} />;
  if (step === 10) return <Step9Frequency {...props} />;
  if (step === 11) return <Step10SessionLength {...props} />;
  if (step === 12) return <Step11Injuries {...props} />;
  if (step === 13) return <Step12Equipment {...props} />;
  if (step === 14) return <BuildingPlanScreen userName={data.name ? data.name.split(" ")[0] : ""} profile={data} onComplete={(programKey, profileUpdates, generatedDays) => onComplete({ ...data, programKey, ...profileUpdates, ...(generatedDays ? { generatedDays } : {}) })} />;
  return null;
};


