const getVimeoId = (exerciseId: string, programDay: number = 1): string | null => {
  const entry = VIMEO_VIDEOS[exerciseId];
  if (!entry || !entry.vimeoIds || entry.vimeoIds.length === 0) return null;
  return entry.vimeoIds[programDay % entry.vimeoIds.length];
};


