// Selects the correct program key based on profile
// This is called at onboarding completion and stored on userProfile.programKey
//
// GENDER ROUTING (Phase 2 — backend intelligence layer):
// profile.gender is captured at onboarding and must be passed to the prescription engine.
// Male and female users get different exercise selections and program variants.
// When the full exercise library (400+) is loaded, gender-specific exercises are filtered
// using the gender field on each ExerciseData entry (to be added: gender?: "male" | "female" | "both").
// Programs labeled "M-" in the source docs are male-oriented; unlabeled/B- are general/female.
// The intelligence layer will use gender + goal + injuries + experience to select the right program key.
// ── ADVANCED PROGRAM PATH ──────────────────────────────────────────────────
// Returns the correct programKey for advanced users based on gender, goal,
// frequency, and cycle number. Cycles 1-8 are deterministic — no AI guessing.
// After cycle 8, generateAIProgram takes over with Month 6+ indefinitely.
const getAdvancedProgramPath = (
  gender: string,
  goal: string,
  frequency: number,
  cycleNumber: number,
  profile?: any
): string => {
  const freqKey = frequency <= 4 ? "4x" : frequency === 5 ? "5x" : "6x";

  // Band-only path — gender neutral, applies to both intermediate and advanced band users
  const equipmentReq = (profile?.equipmentRequired || []) as string[];
  const equipPref = (profile?.equipmentPreference || "").toLowerCase();
  const isBandOnly = (equipmentReq.length > 0 && equipmentReq.every((e: string) => e === "resistance_band")) ||
    equipPref === "bands" || equipPref === "bands-only" || equipPref === "resistance_band";
  if (isBandOnly) {
    const bandPath = [
      gender === "female" ? "womens-intermediate-bands-comin" : "mens-intermediate-3x-bands-comin",
      gender === "female" ? "womens-intermediate-bands-on-me" : "mens-intermediate-advanced-bands-on-me",
      "home-band-together",
      "home-homework",
      "shred-month-1",
      "shred-month-2",
      "shred-month-3",
    ];
    const idx = Math.min((cycleNumber || 1) - 1, bandPath.length - 1);
    return bandPath[idx];
  }

  const paths: Record<string, Record<string, string[]>> = {
    female: {
      fat_loss: [
        "womens-advanced-virtue-and-patience",
        "womens-advanced-winners-delight",
        "advanced-hypertrophy-month-1",
        "womens-advanced-always-on-my-grind",
        "advanced-hypertrophy-month-2",
        "womens-advanced-by-any-means",
        "advanced-hypertrophy-month-3",
        "womens-advanced-earn-your-victory",
      ],
      muscle_gain: [
        "womens-advanced-virtue-and-patience",
        "womens-advanced-winners-delight",
        "advanced-hypertrophy-month-1",
        "womens-advanced-always-on-my-grind",
        "advanced-hypertrophy-month-2",
        "womens-advanced-by-any-means",
        "advanced-hypertrophy-month-3",
        "womens-advanced-earn-your-victory",
      ],
      general_fitness: [
        "womens-advanced-virtue-and-patience",
        `advanced-${freqKey}`,
        "womens-advanced-winners-delight",
        "advanced-5x",
        "womens-advanced-always-on-my-grind",
        "advanced-6x",
        "womens-advanced-by-any-means",
        "womens-advanced-earn-your-victory",
      ],
      athletic_performance: [
        "womens-advanced-virtue-and-patience",
        "advanced-athletic-month-1",
        "womens-advanced-winners-delight",
        "advanced-athletic-month-2",
        "womens-advanced-by-any-means",
        "advanced-athletic-month-3",
        "womens-advanced-always-on-my-grind",
        "womens-advanced-earn-your-victory",
      ],
    },
    male: {
      fat_loss: [
        "mens-advanced-virtue-and-patience",
        "advanced-hypertrophy-month-1",
        "mens-advanced-winners-delight",
        "advanced-hypertrophy-month-2",
        `advanced-${freqKey}`,
        "advanced-hypertrophy-month-3",
        "mens-advanced-sporty",
        "advanced-6x",
      ],
      muscle_gain: [
        "mens-advanced-virtue-and-patience",
        "advanced-hypertrophy-month-1",
        "mens-advanced-winners-delight",
        "advanced-hypertrophy-month-2",
        `advanced-${freqKey}`,
        "advanced-hypertrophy-month-3",
        "mens-advanced-sporty",
        "advanced-6x",
      ],
      general_fitness: [
        "mens-advanced-virtue-and-patience",
        `advanced-${freqKey}`,
        "mens-advanced-winners-delight",
        "advanced-5x",
        "advanced-hypertrophy-month-1",
        "advanced-6x",
        "advanced-hypertrophy-month-2",
        "mens-advanced-sporty",
      ],
      athletic_performance: [
        "mens-advanced-virtue-and-patience",
        "advanced-athletic-month-1",
        "mens-advanced-winners-delight",
        "advanced-athletic-month-2",
        `advanced-${freqKey}`,
        "advanced-athletic-month-3",
        "advanced-5x",
        "mens-advanced-sporty",
      ],
    },
  };

  // Neutral path for non-binary and prefer not to say
  paths["neutral"] = {
    fat_loss: [
      `advanced-${freqKey}`,
      "advanced-hypertrophy-month-1",
      "advanced-hypertrophy-month-2",
      `advanced-${freqKey}`,
      "advanced-hypertrophy-month-3",
      "advanced-6x",
      "advanced-5x",
      "advanced-4x",
    ],
    muscle_gain: [
      `advanced-${freqKey}`,
      "advanced-hypertrophy-month-1",
      "advanced-hypertrophy-month-2",
      `advanced-${freqKey}`,
      "advanced-hypertrophy-month-3",
      "advanced-6x",
      "advanced-5x",
      "advanced-4x",
    ],
    general_fitness: [
      `advanced-${freqKey}`,
      "advanced-hypertrophy-month-1",
      "advanced-5x",
      "advanced-hypertrophy-month-2",
      "advanced-6x",
      "advanced-hypertrophy-month-3",
      "advanced-4x",
      "advanced-5x",
    ],
    athletic_performance: [
      `advanced-${freqKey}`,
      "advanced-athletic-month-1",
      "advanced-5x",
      "advanced-athletic-month-2",
      "advanced-6x",
      "advanced-athletic-month-3",
      "advanced-4x",
      "advanced-5x",
    ],
  };

  const genderKey = (gender === "female") ? "female" : (gender === "male") ? "male" : "neutral";
  const goalKey = (goal || "general_fitness") in (paths[genderKey] || {})
    ? goal
    : "general_fitness";
  const path = paths[genderKey][goalKey];
  // cycleNumber is 1-indexed; clamp to path length
  const idx = Math.min((cycleNumber || 1) - 1, path.length - 1);
  return path[idx];
};

const selectProgram = (profile: any): string => {
  const age = parseInt(String(profile.age)) || 30;
  const freq = profile.frequency || 3;
  const exp = profile.experience || "beginner";
  const isSenior = age >= 65;
  // Clamp frequency to valid range 3-6
  const correctedFreq = Math.min(Math.max(freq, 3), 6);

  // Accessibility track — silently route to low-impact beginner programs
  if (profile.accessibilityTrack) {
    return `senior-beginner-${correctedFreq}x`;
  }

  // Age 65+ → senior library regardless of experience
  if (isSenior) {
    if (exp === "advanced") return `senior-advanced-${correctedFreq}x`;
    if (exp === "intermediate") return `senior-intermediate-${correctedFreq}x`;
    return `senior-beginner-${correctedFreq}x`;
  }

  // Band-only intermediate and advanced users — use deterministic band path
  const equipmentReq = (profile.equipmentRequired || []) as string[];
  const equipPrefStr = (profile.equipmentPreference || "").toLowerCase();
  const isBandOnly = (equipmentReq.length > 0 && equipmentReq.every((e: string) => e === "resistance_band")) ||
    equipPrefStr === "bands" || equipPrefStr === "bands-only" || equipPrefStr === "resistance_band";
  if (isBandOnly) {
    if (exp === "advanced") {
      const gender = profile.gender || "male";
      const goal = profile.primaryGoal || "general_fitness";
      const cycleNum = profile.cycleNumber || 1;
      return getAdvancedProgramPath(gender, goal, correctedFreq, cycleNum, profile);
    }
    // Intermediate band-only — use frequency-matched intermediate program (works with bands)
    if (exp === "intermediate") {
      return `intermediate-${correctedFreq}x`;
    }
    // Beginner band-only — use band-friendly beginner program
    return correctedFreq <= 3 ? "beginner-3x-bands-comin" : "beginner-3x-earn-your-victory";
  }

  // Advanced users — use deterministic goal-based path with correct cycle
  if (exp === "advanced") {
    const gender = profile.gender || "male";
    const goal = profile.primaryGoal || "general_fitness";
    const cycleNum = profile.cycleNumber || 1;
    return getAdvancedProgramPath(gender, goal, correctedFreq, cycleNum, profile);
  }

  // Intermediate users — use frequency-matched generic program
  // Goal differentiation at intermediate level comes from the named program variants
  if (exp === "intermediate") {
    return `intermediate-${correctedFreq}x`;
  }

  // Beginner — frequency-matched generic program
  return `beginner-${correctedFreq}x`;
};

// Returns the correct ProgramDay for a given program key + day number
// Falls back to PROGRAM_DAY1 placeholder until programs are entered
// ─── BMI & Accessibility Track Logic ─────────────────────────────────────────
// Trigger: BMI ≥ 35 AND experience = 'beginner'
// The word 'obesity' NEVER appears in the UI — app silently serves appropriate exercises.
// Formula: weight(lbs) ÷ height(in)² × 703
const calculateBMI = (profile: any): number => {
  let weightLbs = Number(profile.weightLbs);
  let heightIn: number;
  if (profile.heightFt) {
    heightIn = (Number(profile.heightFt) * 12) + (Number(profile.heightIn) || 0);
  } else if (profile.heightCm) {
    heightIn = Number(profile.heightCm) / 2.54;
    weightLbs = Number(profile.weightKg) * 2.20462;
  } else {
    return 0;
  }
  if (!weightLbs || !heightIn || heightIn === 0) return 0;
  return (weightLbs / (heightIn * heightIn)) * 703;
};

const shouldUseAccessibilityTrack = (profile: any): boolean => {
  const bmi = calculateBMI(profile);
  const isBeginnerLevel = (profile.experience || "beginner") === "beginner";
  // AND condition is the safeguard: a large muscular athlete at BMI 35
  // would never also self-report as beginner
  return bmi >= 35 && isBeginnerLevel;
};

const getProgramDay = (programKey: string, programDay: number, generatedDays?: any[]) => {
  // Month 4+ — use generated days if provided
  if (generatedDays && generatedDays.length > 0) {
    const idx = (programDay - 1) % generatedDays.length;
    return generatedDays[idx];
  }
  const program = PROGRAMS[programKey];
  if (!program || !program.days || program.days.length === 0) {
    return PROGRAM_DAY1;
  }
  const idx = (programDay - 1) % program.days.length;
  return program.days[idx];
};

// ─── Program Database ─────────────────────────────────────────────────────────
// Open-ended — add as many programs as needed. No cap.
// Each program is an array of ProgramDay objects (any length, typically 30 days per cycle).
// Rest days use REST_DAY_TEMPLATE(dayNum). Workout days follow Senz's written programs.
// New programs can be added at any time by appending a new key to PROGRAMS.
//
// Current known programs (will grow):
//   Beginner:            3x, 4x, 5x
//   Intermediate:        3x, 4x, 5x, 6x
//   Advanced:            4x, 5x, 6x
//   Senior Beginner:     3x, 4x
//   Senior Intermediate: 3x, 4x
//   + any additional programs Senz adds (post-partum, athletic, sport-specific, etc.)


// ════════════════════════════════════════════════════════════════════════════
// AMENITYFIT INTELLIGENCE LAYER — PROGRAM PRESCRIPTION ENGINE
// ════════════════════════════════════════════════════════════════════════════
//
// WHAT THIS IS:
// The complete knowledge base and decision logic for selecting and generating
// workout programs. Built from 50+ real programs by Senz (fitmakesenz.com),
// covering beginner to advanced bodybuilding, across all genders and ages.
//
// CURRENT STATE (Phase 1 — Static):
// selectProgram() maps user profile to a stored program key.
// getProgramDay() returns the exact day object from PROGRAMS database.
//
// FUTURE STATE (Phase 2 — Backend Intelligence):
// selectProgram() will call a server-side Claude API with the full user profile
// and this entire knowledge base as context. The AI will either:
//   (a) Select the best matching stored program, OR
//   (b) Generate a new program from scratch using the principles below
//
// ────────────────────────────────────────────────────────────────────────────
// SENZ'S TRAINING PHILOSOPHY (extracted from 50+ programs):
// ────────────────────────────────────────────────────────────────────────────
//
// REST TIMES:
//   Strength sets (8-12 reps): 60-120 seconds between sets
//   Endurance sets (12-30 reps): 30 seconds between sets
//   Senior programs: "rest as long as you need"
//   Advanced athletic: 0-30 seconds between supersetted power movements
//
// REP TEMPO:
//   Standard: 1 second concentric, 2-3 second negative (slow eccentric)
//   Slow negative exceptions: chest fly machine, lying dumbbell fly, calf raises
//   Explosive exceptions: plyometric movements, med ball slams, box jumps
//
// SUPERSET PHILOSOPHY:
//   - Most exercises are supersetted or in trisets — never just random pairings
//   - Opposing muscle groups supersetted for efficiency (push/pull, quad/hamstring)
//   - Cardio bursts (mountain climbers, jump rope, jumping jacks) paired with
//     heavy compound lifts to elevate heart rate without compromising strength
//   - Single straight sets appear for: compound warm-ups, isolation finishers,
//     exercises requiring full concentration (heavy deadlifts, bench press)
//
// PROGRAM STRUCTURE PATTERNS:
//   Beginner 3x: Full body each session. Light weight, form focus.
//   Beginner 4x: Full body with dedicated abs/cardio day.
//   Intermediate 5x: Upper/lower split with abs integrated.
//   Advanced 5x: Push/pull/legs split. More isolation, higher volume.
//   Advanced 6x: Body part split (Back/Bi, Legs, Cardio, Shoulders, Chest/Tri).
//   Senior 4x: 3 workout days + 1 cardio. Resistance bands + dumbbells.
//   Athletic 7x: 4 strength + 2 cardio + 1 optional. Agility ladder on cardio days.
//
// FREQUENCY RULES (Senz's conventions):
//   3x/week → Mon/Wed/Fri rest pattern
//   4x/week → Mon/Tue/Thu/Fri rest pattern (Sat/Sun off)
//   5x/week → Mon-Fri (Sat/Sun off)
//   6x/week → Mon-Sat (Sun off)
//
// EXERCISE SELECTION PRINCIPLES:
//   - Begin sessions with largest compound movements when fresh
//   - Isolation exercises appear later in session, never at start
//   - Rotator cuff / external rotation work appears at END of upper body days
//     (lying dumbbell external rotation, face pulls, side-lying rotation)
//   - Abs programmed 3x/week minimum for advanced athletes
//   - Cardio finishes most intermediate/advanced sessions (not separate day)
//   - Senior programs: abs at end, low-impact cardio finish (15-20 mins)
//
// INJURY FLAG LOGIC:
//   - injuryFlags on exercises are used to filter intelligently
//   - "lower-back" flag → avoid deadlifts/heavy squats, substitute hip hinges
//   - "knee" flag → avoid plyometrics and deep squats, substitute leg press/step-ups
//   - "shoulder" flag → avoid overhead pressing, substitute lateral raises/rows
//   - "wrist" flag → avoid barbell pressing, substitute dumbbell variations
//
// PROGRESSION LOGIC (month-over-month):
//   Month 1: Establish movement patterns. Moderate weight, strict form.
//   Month 2: Increase volume (add sets). Introduce supersets where straight sets were.
//   Month 3: Increase intensity. Introduce circuits, plyometrics, compound movements.
//   Month 4+: Intelligence layer generates new programs by:
//     1. Reviewing what was done in months 1-3
//     2. Selecting exercises NOT yet used from the 400+ exercise library
//     3. Maintaining same structural principles (rest times, grouping logic)
//     4. Escalating complexity only if previous months show completion rate >80%
//     5. Never repeating the same program back-to-back
//
// GENDER ROUTING:
//   Women → Glute-dominant lower body (hip thrusts, Bulgarian splits, cable kickbacks)
//   Men → Quad-dominant lower body (squats, deadlifts, leg press)
//   Women upper → Higher rep ranges, more TRX/cable work
//   Men upper → Heavier compound lifts, more barbell work
//   Senior → Gender-neutral (safety > specificity)
//
// EQUIPMENT AVAILABILITY LOGIC:
//   "full-gym" → All exercises available
//   "dumbbells-only" → Filter to dumbbell/bodyweight exercises
//   "bands-only" → Route to home-band-together, travel-travel-bug, or shred programs
//   "limited" → Senior-style program regardless of age
//
// OVERAMBITION CORRECTION:
//   If user says 7x/week beginner → Cap at 5x, adjust to beginner-5x structure
//   If user says 6x/week intermediate → Build 5-day program + 1 active recovery
//   Never prescribe 6x+ for beginners regardless of stated preference
//
// MSC WORKOUTS + EXERCISE DEMO LIST:
//   MSC_Workouts.docx = Master reference pool of ~150 exercises organized by
//   Upper/Lower. This is the full available library to pull from when building
//   new programs. Each exercise in EXERCISES_DATA corresponds to an entry here.
//   Exercise_Demo_List.docx = 382 exercises with video demos for 3 client types
//   (Woman 1-K, Woman 2-A, Man 2). When video URLs are added to EXERCISES_DATA,
//   this list determines which videos exist for each exercise.
//
// ════════════════════════════════════════════════════════════════════════════

