// Filter exercises based on session length
// Exercise priority scoring for intelligent filtering
// Higher score = more important to keep
const getGroupPriority = (group: any): number => {
  if (group.type === "cardio") return 0; // Always last priority
  const exercises = group.exercises || [];
  let score = 0;
  exercises.forEach(ex => {
    const data = EXERCISES_DATA[ex.id];
    if (!data) return;
    const muscle = (data.muscle || "").toLowerCase();
    // Compound lower body = highest priority (most caloric burn)
    if (["quads", "hamstrings", "glutes"].includes(muscle)) score += 4;
    // Compound upper body = high priority
    else if (["back", "chest"].includes(muscle)) score += 3;
    // Shoulders = medium priority
    else if (muscle === "shoulders") score += 2;
    // Arms/isolation = lower priority
    else if (["triceps", "biceps"].includes(muscle)) score += 1;
    // Core = lowest (trained indirectly by compounds)
    else if (muscle === "core") score += 0.5;
  });
  return score;
};

// Detect the dominant focus of a day from its groups
// Generate intelligent focus summary from filtered groups
// ─── Derive workout title from actual exercise muscles ─────────────────────────
// Reads exercise IDs → EXERCISES_DATA muscles → computes accurate title
// This is what shows on the WorkoutListScreen hero and the weekly view card
const deriveWorkoutTitle = (groups: any[], dayType?: string, focus?: string): string => {
  if (!groups || groups.length === 0) return "Workout";

  // Honor explicit rest/cardio day types
  if (dayType === "rest") return "Rest Day";

  // Pure cardio day — no exercise groups
  const hasOnlyCardio = groups.every(g => g.type === "cardio");
  if (hasOnlyCardio) return "Cardio";

  const hasCardio = groups.some(g => g.type === "cardio");
  const workoutGroups = groups;

  // Pure cardio day — no strength groups at all
  if (workoutGroups.length === 0 && hasCardio) return "Cardio";

  // Collect all muscle groups from actual exercises
  const muscleCounts: Record<string, number> = {};
  workoutGroups.forEach(g => {
    (g.exercises || []).forEach((ex: any) => {
      const exData = EXERCISES_DATA[ex.id];
      if (!exData) return;
      const muscle = exData.muscle || "";
      // Map muscles to categories
      if (["Back", "Biceps"].includes(muscle)) {
        muscleCounts["Back & Biceps"] = (muscleCounts["Back & Biceps"] || 0) + 1;
      } else if (["Chest", "Triceps"].includes(muscle)) {
        muscleCounts["Chest & Triceps"] = (muscleCounts["Chest & Triceps"] || 0) + 1;
      } else if (["Quads", "Hamstrings", "Glutes", "Calves"].includes(muscle)) {
        muscleCounts["Legs"] = (muscleCounts["Legs"] || 0) + 1;
      } else if (muscle === "Shoulders") {
        muscleCounts["Shoulders"] = (muscleCounts["Shoulders"] || 0) + 1;
      } else if (muscle === "Core") {
        muscleCounts["Abs"] = (muscleCounts["Abs"] || 0) + 1;
      } else if (muscle === "Full Body") {
        muscleCounts["Full Body"] = (muscleCounts["Full Body"] || 0) + 1;
      }
    });
  });

  // Determine dominant category and combination
  const hasLegs = muscleCounts["Legs"] > 0;
  const hasUpper = (muscleCounts["Back & Biceps"] || 0) + (muscleCounts["Chest & Triceps"] || 0) + (muscleCounts["Shoulders"] || 0) > 0;
  const hasAbs = muscleCounts["Abs"] > 0;
  const hasBack = muscleCounts["Back & Biceps"] > 0;
  const hasChest = muscleCounts["Chest & Triceps"] > 0;
  const hasShoulders = muscleCounts["Shoulders"] > 0;
  const upperTypes = [hasBack, hasChest, hasShoulders].filter(Boolean).length;

  let title = "";

  if (hasLegs && hasUpper) {
    title = "Upper Body & Legs";
  } else if (hasLegs && hasAbs && !hasUpper) {
    title = "Legs & Abs";
  } else if (hasLegs && !hasUpper && !hasAbs) {
    title = "Legs";
  } else if (hasBack && hasChest && hasShoulders) {
    // All three upper groups = just "Upper Body"
    title = "Upper Body";
  } else if (hasBack && hasChest && !hasShoulders && !hasLegs) {
    title = "Upper Body";
  } else if (hasChest && hasShoulders && !hasBack && !hasLegs) {
    // Chest + Shoulders is still "Upper Body" — too verbose otherwise
    title = "Upper Body";
  } else if (hasBack && hasShoulders && !hasChest && !hasLegs) {
    title = "Back, Biceps & Shoulders";
  } else if (hasBack && !hasChest && !hasShoulders && !hasLegs) {
    title = "Back & Biceps";
  } else if (hasChest && !hasBack && !hasShoulders && !hasLegs) {
    title = "Chest & Triceps";
  } else if (hasShoulders && !hasBack && !hasChest && !hasLegs) {
    title = hasAbs ? "Shoulders & Abs" : "Shoulders";
  } else if (hasUpper && upperTypes >= 2) {
    title = "Upper Body";
  } else if (Object.keys(muscleCounts).length > 0) {
    const sorted = Object.entries(muscleCounts).sort((a, b) => b[1] - a[1]);
    title = sorted.slice(0, 2).map(e => e[0]).join(" & ");
  } else {
    title = "Full Body";
  }

  // Append Abs suffix only if abs are significant AND title doesn't already say Upper Body
  if (hasAbs && !title.includes("Abs") && !title.includes("Upper Body")) {
    const absCount = muscleCounts["Abs"] || 0;
    const total = Object.values(muscleCounts).reduce((a: number, b: number) => a + b, 0);
    if (absCount / total >= 0.25) title += " & Abs";
  }

  // Pure cardio day — no strength exercises at all
  if (hasCardio && Object.keys(muscleCounts).length === 0) return "Cardio";

  if (hasCardio) title += " & Cardio";

  return title || "Workout";
};

const getFocusSummary = (groups: any[], dayType?: string): string => {
  return deriveWorkoutTitle(groups, dayType);
};

const getDayFocus = (groups: any[]): string => {
  const exerciseGroups = groups.filter(g => g.type !== "cardio");
  const focuses = exerciseGroups.map(g => g.focus || "full");
  const hasUpper = focuses.some(f => f.includes("upper"));
  const hasLower = focuses.some(f => f.includes("lower"));
  const hasCore = focuses.some(f => f === "core");
  if (hasUpper && hasLower) return "full";
  if (hasLower) return "lower";
  if (hasUpper) return "upper";
  if (hasCore) return "core";
  return "full";
};

// Filters cardio option lines based on what equipment the building actually has.
// Non-bullet lines (headers/descriptions) always pass through.
const filterCardioNote = (note: string, buildingEquipment: string[]): string => {
  if (!buildingEquipment || buildingEquipment.length === 0) return note;
  const equipmentRules: Record<string, string[]> = {
    "Treadmill Walk or Run": ["treadmill"],
    "Stationary Bike": ["bike"],
    "Elliptical": ["elliptical"],
    "Stairmaster": ["stairmaster"],
    "Jump Rope": ["jump-rope"],
    "Rowing Machine": ["rowing-machine"],
  };
  const lines = note.split("\n");
  const hasRowingMachine = lines.some(l => l.trim() === "• Rowing Machine");
  const rowingAvailable = buildingEquipment.includes("rowing-machine");
  const filtered = lines.filter(line => {
    if (!line.startsWith("•")) return true;
    const label = line.replace("•", "").trim();
    const required = equipmentRules[label];
    if (!required) return true;
    return required.some(eq => buildingEquipment.includes(eq));
  });
  if (rowingAvailable && !hasRowingMachine) {
    const jumpRopeIdx = filtered.findIndex(l => l.trim() === "• Jump Rope");
    if (jumpRopeIdx !== -1) {
      filtered.splice(jumpRopeIdx, 0, "• Rowing Machine");
    } else {
      const lastBullet = filtered.map((l, i) => l.startsWith("•") ? i : -1).filter(i => i !== -1).pop();
      if (lastBullet !== undefined) filtered.splice(lastBullet, 0, "• Rowing Machine");
    }
  }
  return filtered.join("\n");
};

const parseInjuryFlags = (injuryText: string): string[] => {
  if (!injuryText || injuryText === "none") return [];
  const text = injuryText.toLowerCase();
  const flags: string[] = [];
  // Knee — catches: knee, knees, acl, mcl, meniscus, patella, kneecap, pcl
  if (text.includes("knee") || text.includes("knees") || text.includes("acl") || text.includes("mcl") || text.includes("meniscus") || text.includes("patella") || text.includes("kneecap") || text.includes("pcl")) {
    flags.push("knee-deep-flexion", "knee-impact", "knee-shear");
  }
  // Back — catches: back, spine, lumbar, disc, herniat, sciatica, lower back, scoliosis, sacral, si joint
  if (text.includes("back") || text.includes("spine") || text.includes("lumbar") || text.includes("disc") || text.includes("herniat") || text.includes("sciatica") || text.includes("scoliosis") || text.includes("sacral") || text.includes("si joint")) {
    flags.push("lumbar-flexion-loaded", "lumbar-hinge-heavy", "lumbar-rotation-loaded", "lumbar-extension");
  }
  // Shoulder — catches: shoulder, rotator, labrum, impingement, cuff, bursitis, ac joint, acromial
  if (text.includes("shoulder") || text.includes("rotator") || text.includes("labrum") || text.includes("impingement") || text.includes("cuff") || text.includes("bursitis") || text.includes("ac joint") || text.includes("acromial")) {
    flags.push("shoulder-impingement", "shoulder-overhead");
  }
  // Wrist — catches: wrist, carpal, tendon, tendinitis, tendinopathy
  if (text.includes("wrist") || text.includes("carpal") || (text.includes("tendon") && !text.includes("shoulder")) || text.includes("tendinit") || text.includes("tendinopat")) {
    flags.push("wrist-load");
  }
  // Elbow — catches: elbow, tennis elbow, golfer, epicondyl
  if (text.includes("elbow") || text.includes("tennis elbow") || text.includes("golfer") || text.includes("epicondyl")) {
    flags.push("elbow-load");
  }
  // Hip — catches: hip, groin, it band, iliotibial, psoas, flexor
  if (text.includes("hip") || text.includes("hips") || text.includes("groin") || text.includes("it band") || text.includes("iliotibial") || text.includes("psoas") || text.includes("hip flexor")) {
    flags.push("hip-flexion-loaded");
  }
  // Ankle — catches: ankle, achilles, plantar, foot, feet, shin splint
  if (text.includes("ankle") || text.includes("ankles") || text.includes("achilles") || text.includes("plantar") || text.includes("shin splint") || (text.includes("foot") && !text.includes("football")) || text.includes(" feet")) {
    flags.push("ankle-impact");
  }
  // Neck — catches: neck, cervical, trap, trapezius (upper)
  if (text.includes("neck") || text.includes("cervical")) {
    flags.push("lumbar-rotation-loaded");
  }
  return [...new Set(flags)];
};

const filterExercisesByEquipment = (groups: any[], equipmentPreference: string, buildingEquipment: string[] = []): any[] => {
  if (!equipmentPreference || equipmentPreference === "gym-and-bands") {
    if (buildingEquipment.length === 0) return groups;
  }

  // Check if an exercise passes equipment constraints
  const passesEquipmentCheck = (eq: string, equipmentPreference: string, buildingEquipment: string[]): boolean => {
    if (equipmentPreference === "bands" || equipmentPreference === "bands-only") {
      return eq.includes("band") || eq.includes("bodyweight") || eq === "";
    }
    if (equipmentPreference === "bodyweight-only") {
      return eq.includes("bodyweight") || eq === "";
    }
    if (equipmentPreference === "gym" || equipmentPreference === "gym-only") {
      if (eq.includes("band") && !eq.includes("cable")) return false;
    }
    if (buildingEquipment.length > 0) {
      const hasDumbbells = buildingEquipment.includes("dumbbells");
      const hasBarbell = buildingEquipment.includes("barbell") || buildingEquipment.includes("squat-rack");
      const hasCable = buildingEquipment.includes("cables") || buildingEquipment.includes("cable-machine");
      const hasSmith = buildingEquipment.includes("smith-machine");
      const hasLegPress = buildingEquipment.includes("leg-press");
      const hasLegCurl = buildingEquipment.includes("leg-curl");
      const hasLegExtension = buildingEquipment.includes("leg-extension");
      const hasChestPressMachine = buildingEquipment.includes("chest-press-machine");
      const hasSeatedRow = buildingEquipment.includes("seated-row-machine");
      if (eq.includes("cable") && !hasCable && !hasSmith) return false;
      if (eq.includes("smith machine") && !hasSmith && !hasBarbell) return false;
      if (eq === "leg press machine" && !hasLegPress) return false;
      if (eq === "leg curl machine" && !hasLegCurl) return false;
      if (eq === "leg extension machine" && !hasLegExtension) return false;
      if (eq === "chest press machine" && !hasChestPressMachine && !hasDumbbells) return false;
      if (eq === "seated row machine" && !hasSeatedRow && !hasCable) return false;
      if ((eq === "barbell") && !hasBarbell && !hasSmith) return false;
    }
    return true;
  };

  // Find a swap for a removed exercise — same muscle group, passes equipment check, not already in workout
  const findEquipmentSwap = (removedEx: any, usedIds: Set<string>, equipmentPreference: string, buildingEquipment: string[]): any | null => {
    const removedData = (EXERCISES_DATA as any)[removedEx.id];
    if (!removedData) return null;
    const targetMuscle = removedData.muscle;
    const allIds = Object.keys(EXERCISES_DATA);
    for (const candidateId of allIds) {
      if (usedIds.has(candidateId)) continue;
      const candidateData = (EXERCISES_DATA as any)[candidateId];
      if (!candidateData) continue;
      if (candidateData.muscle !== targetMuscle) continue;
      const candidateEq = (candidateData.equipment || "").toLowerCase();
      if (!passesEquipmentCheck(candidateEq, equipmentPreference, buildingEquipment)) continue;
      // Has a video
      if (!(VIMEO_VIDEOS as any)[candidateId]) continue;
      return { ...removedEx, id: candidateId };
    }
    return null;
  };

  return groups.map(group => {
    if (group.type === "cardio") return group;

    // Build set of all IDs currently in the entire workout for dedup
    const allUsedIds = new Set<string>(
      groups.flatMap((g: any) => (g.exercises || []).map((e: any) => e.id))
    );

    const resultExercises: any[] = [];
    for (const ex of (group.exercises || [])) {
      const exData = (EXERCISES_DATA as any)[ex.id];
      if (!exData) { resultExercises.push(ex); continue; }
      const eq = (exData.equipment || "").toLowerCase();
      if (passesEquipmentCheck(eq, equipmentPreference, buildingEquipment)) {
        resultExercises.push(ex);
        allUsedIds.add(ex.id);
      } else {
        // Try to find a gym-appropriate swap
        const swap = findEquipmentSwap(ex, allUsedIds, equipmentPreference, buildingEquipment);
        if (swap) {
          resultExercises.push(swap);
          allUsedIds.add(swap.id);
        }
        // If no swap found, exercise is dropped — group may shrink but won't disappear entirely
      }
    }
    return { ...group, exercises: resultExercises };
  }).filter(group => group.type === "cardio" || (group.exercises && group.exercises.length > 0));
};

const filterExercisesByVideo = (groups: any[]): any[] => {
  return groups.map(group => {
    if (group.type === "cardio") return group;
    const filteredExercises = (group.exercises || []).filter((ex: any) => {
      return !!(VIMEO_VIDEOS as any)[ex.id];
    });
    return { ...group, exercises: filteredExercises };
  }).filter(group => group.type === "cardio" || (group.exercises && group.exercises.length > 0));
};

