const getInjuryCategory = (flags: string[]): string[] => {
  const categories: string[] = [];
  if (flags.some(f => f.startsWith("knee"))) categories.push("knee");
  if (flags.some(f => f.startsWith("lumbar"))) categories.push("back");
  if (flags.some(f => f.startsWith("shoulder"))) categories.push("shoulder");
  if (flags.some(f => f.startsWith("hip"))) categories.push("hip");
  if (flags.some(f => f === "elbow-load")) categories.push("elbow");
  if (flags.some(f => f === "wrist-load")) categories.push("wrist");
  if (flags.some(f => f === "hip-flexion-loaded")) categories.push("hip");
  return categories;
};

const filterExercisesByInjury = (groups: any[], injuryText: string, equipmentPreference: string = "gym-and-bands", buildingEquipment: string[] = []): any[] => {
  const activeFlags = parseInjuryFlags(injuryText);
  if (activeFlags.length === 0) return groups;
  const injuryCategories = getInjuryCategory(activeFlags);

  // Collect all exercise IDs already in the workout (before swaps) to prevent duplicates
  const allExerciseIds = new Set(
    groups.flatMap(g => (g.exercises || []).map((ex: any) => ex.id))
  );
  const usedInSwaps = new Set<string>();

  return groups.map(group => {
    if (group.type === "cardio") return group;
    const safeExercises = (group.exercises || []).map((ex: any) => {
      const exData = (EXERCISES_DATA as any)[ex.id];
      if (!exData || !exData.injuryFlags) return ex;
      const isFlagged = exData.injuryFlags.some((flag: string) => activeFlags.includes(flag));
      if (!isFlagged) return ex;
      // Flagged — walk the regression ladder before excluding
      const ladder = INJURY_REGRESSION_LADDER[ex.id];
      if (ladder) {
        for (const category of injuryCategories) {
          const steps = ladder[category] || [];
          for (const stepId of steps) {
            const stepData = (EXERCISES_DATA as any)[stepId];
            if (!stepData) continue;
            // Skip if already in the workout or already used as a swap
            if (allExerciseIds.has(stepId) || usedInSwaps.has(stepId)) continue;
            // Step is safe if it has no flags that conflict with active injury
            const stepSafe = !stepData.injuryFlags || !stepData.injuryFlags.some((f: string) => activeFlags.includes(f));
            if (stepSafe) {
              // Also verify the swap exercise is compatible with user equipment
              const stepEquipment = (stepData.equipment || "").toLowerCase();
              const isBandOnly = equipmentPreference === "bands" || equipmentPreference === "bands-only";
              const isGymOnly = equipmentPreference === "gym" || equipmentPreference === "gym-only";
              const isBodyweightOnly = equipmentPreference === "bodyweight-only";
              const stepHasBand = stepEquipment.includes("band") || stepEquipment.includes("resistance");
              const stepHasGym = !stepHasBand && stepEquipment !== "bodyweight" && stepEquipment !== "";
              const stepIsBodyweight = stepEquipment === "bodyweight" || stepEquipment === "";
              // Check building equipment if gym user
              const buildingHasEquipment = buildingEquipment.length === 0 || 
                buildingEquipment.some(e => stepEquipment.includes(e.toLowerCase().replace(/_/g, ' ')));
              if (isBandOnly && !stepHasBand && !stepIsBodyweight) continue;
              if (isGymOnly && stepHasBand && !stepIsBodyweight) continue;
              if (isBodyweightOnly && !stepIsBodyweight) continue;
              usedInSwaps.add(stepId);
              return { ...ex, id: stepId };
            }
          }
        }
      }
      // No safe regression found — exclude entirely
      return null;
    }).filter(Boolean);
    return { ...group, exercises: safeExercises };
  }).filter(group => group.type === "cardio" || (group.exercises && group.exercises.length > 0));
};

const filterGroupsForReEntry = (groups: any[], effectiveLevel: string, progressionPhase: string): any[] => {
  const cardioGroups = groups.filter(g => g.type === "cardio");
  const nonCardioGroups = groups.filter(g => g.type !== "cardio");

  const isEvolved = progressionPhase === "month6+";
  const isAdvanced = effectiveLevel === "advanced" || isEvolved;
  const isIntermediate = effectiveLevel === "intermediate" || effectiveLevel === "senior-intermediate";
  const isBeginner = effectiveLevel === "beginner" || effectiveLevel === "senior-beginner";

  // Month 6+ re-entry: same program, same pool, same progression state — just dial back intensity
  // Uses base-level exercise variants where available, keeps evolved programming intact
  if (isEvolved) {
    const evolvedReEntryMap: Record<string, string> = {
      "dumbbell-bulgarian-split-squat": "leg-press",
      "single-leg-rdl": "dumbbell-romanian-deadlift",
      "single-leg-deadlift": "dumbbell-romanian-deadlift",
      "single-leg-press": "leg-press",
      "single-leg-leg-curl": "machine-hamstring-curl",
      "barbell-squat": "goblet-squat",
      "barbell-deadlift": "dumbbell-romanian-deadlift",
      "barbell-overhead-press": "standing-shoulder-press",
      "barbell-bench-press": "low-incline-dumbbell-bench-press",
      "incline-barbell-press": "dumbbell-incline-press",
      "pistol-squat": "goblet-squat",
      "shrimp-squat": "goblet-squat",
      "single-leg-hip-thrust": "band-glute-bridge",
      "single-leg-lateral-leap": "band-lateral-walk",
      "crossover-step-up": "dumbbell-step-ups",
      "goblet-squat-jump": "goblet-squat",
      "medicine-ball-squat-jumps": "goblet-squat",
      "tuck-jump": "squat-jumps",
      "drop-jumps": "squat-jumps",
      "plyo-lunge-switches": "stationary-lunge",
      "dumbbell-lunge-switches": "walking-dumbbell-lunge",
      "bosu-ball-dumbbell-deadlift-to-row": "one-arm-dumbbell-row",
      "pendlay-row": "bent-over-row-overhand",
      "trap-bar-deadlift": "dumbbell-romanian-deadlift",
      "trap-bar-squat": "leg-press",
    };
    let selectedGroups = nonCardioGroups.slice(0, 4);
    selectedGroups = selectedGroups.map(g => {
      const isTriset = g.type === "superset" && (g.exercises || []).length >= 3;
      const exercises = isTriset ? (g.exercises || []).slice(0, 2) : (g.exercises || []);
      const safeExercises = exercises.map((ex: any) => ({
        ...ex,
        id: evolvedReEntryMap[ex.id] || ex.id,
        sets: Math.min(ex.sets || 3, 3),
      }));
      return {
        ...g,
        exercises: safeExercises,
        type: isTriset ? "superset" : g.type,
      };
    });
    return [...selectedGroups, ...cardioGroups];
  }

  if (isBeginner) {
    // Beginner re-entry: cap at 3 non-cardio groups, reduce sets to 2
    const beginnerGroups = nonCardioGroups.slice(0, 3).map(g => ({
      ...g,
      exercises: (g.exercises || []).map((ex: any) => ({
        ...ex,
        sets: Math.min(ex.sets || 2, 2),
      })),
    }));
    return [...beginnerGroups, ...cardioGroups];
  }

  // Advanced unilateral / high-skill exercise IDs to swap out for advanced re-entry
  const advancedUnilateralIds = [
    "dumbbell-bulgarian-split-squat", "single-leg-rdl", "single-leg-deadlift",
    "pistol-squat", "shrimp-squat", "single-leg-hip-thrust", "single-leg-lateral-leap",
    "crossover-step-up", "single-leg-press", "single-leg-leg-curl",
  ];

  let selectedGroups = [...nonCardioGroups];

  if (isIntermediate) {
    // Intermediate: cap at 4 non-cardio groups (min 3), reduce sets to 3
    selectedGroups = selectedGroups.slice(0, Math.max(4, Math.min(selectedGroups.length, 4)));
    selectedGroups = selectedGroups.length < 3 ? nonCardioGroups.slice(0, 3) : selectedGroups;
    selectedGroups = selectedGroups.map(g => ({
      ...g,
      exercises: (g.exercises || []).map((ex: any) => ({
        ...ex,
        sets: Math.min(ex.sets || 3, 3),
      })),
    }));
  }

  if (isAdvanced) {
    // Advanced/Evolved: cap at 4 groups (min 3), reduce sets to 3,
    // simplify trisets to supersets, swap advanced unilateral moves
    selectedGroups = selectedGroups.slice(0, 4);
    selectedGroups = selectedGroups.length < 3 ? nonCardioGroups.slice(0, 3) : selectedGroups;
    selectedGroups = selectedGroups.map(g => {
      // Simplify trisets — keep only first two exercises
      const isTriset = g.type === "superset" && (g.exercises || []).length >= 3;
      const exercises = isTriset
        ? (g.exercises || []).slice(0, 2)
        : (g.exercises || []);

      // Swap advanced unilateral exercises to bilateral equivalents
      const safeExercises = exercises.map((ex: any) => {
        if (advancedUnilateralIds.includes(ex.id)) {
          const bilateralMap: Record<string, string> = {
            "dumbbell-bulgarian-split-squat": "dumbbell-goblet-squat",
            "single-leg-rdl": "dumbbell-romanian-deadlift",
            "single-leg-deadlift": "dumbbell-romanian-deadlift",
            "pistol-squat": "bodyweight-squat",
            "shrimp-squat": "bodyweight-squat",
            "single-leg-hip-thrust": "glute-bridge",
            "single-leg-lateral-leap": "lateral-squat",
            "crossover-step-up": "dumbbell-step-up",
            "single-leg-press": "leg-press",
            "single-leg-leg-curl": "machine-hamstring-curl",
          };
          return { ...ex, id: bilateralMap[ex.id] || ex.id };
        }
        return ex;
      });

      return {
        ...g,
        exercises: safeExercises.map((ex: any) => ({
          ...ex,
          sets: Math.min(ex.sets || 3, 3),
        })),
        type: isTriset ? "superset" : g.type,
      };
    });
  }

  return [...selectedGroups, ...cardioGroups];
};

const filterGroupsForSessionLength = (groups: any[], sessionLength: number) => {
  const exerciseGroups = groups.filter(g => g.type !== "cardio");
  const cardioGroups = groups.filter(g => g.type === "cardio");
  const dayFocus = getDayFocus(groups);

  if (sessionLength >= 60) {
    // Full program — but always ensure cardio groups are at the end
    const nonCardio = groups.filter(g => g.type !== "cardio");
    const cardio = groups.filter(g => g.type === "cardio");
    return [...nonCardio, ...cardio];
  }

  // Separate abs/core groups from main working groups
  const absGroups = exerciseGroups.filter(g =>
    g.focus === "core" || (g.label || "").toLowerCase().includes("abs")
  );
  const mainGroups = exerciseGroups.filter(g =>
    g.focus !== "core" && !(g.label || "").toLowerCase().includes("abs")
  );

  // Score all main groups by priority
  const scored = mainGroups.map(g => ({ group: g, score: getGroupPriority(g) }));
  scored.sort((a, b) => b.score - a.score);

  // Helper: select groups up to a max total exercise count
  const selectUpToExCount = (candidates: typeof scored, maxEx: number, ensureBothBodyParts = false): any[] => {
    let selected: any[] = [];
    let exCount = 0;

    if (ensureBothBodyParts && dayFocus === "full") {
      // For full body: pick at least one lower + one upper first
      const lower = candidates.find(s => (s.group.focus || "").includes("lower"));
      const upper = candidates.find(s => (s.group.focus || "").includes("upper") && !(s.group.focus || "").includes("lower"));
      if (lower) { selected.push(lower.group); exCount += lower.group.exercises?.length || 0; }
      if (upper && exCount + (upper.group.exercises?.length || 0) <= maxEx) { selected.push(upper.group); exCount += upper.group.exercises?.length || 0; }
      candidates = candidates.filter(s => !selected.includes(s.group));
    }

    for (const { group } of candidates) {
      const count = group.exercises?.length || 0;
      if (exCount + count <= maxEx) {
        selected.push(group);
        exCount += count;
      }
    }
    return selected;
  };

  if (sessionLength >= 45) {
    // 45 min: max 6 exercises + 1 abs group (or cardio instead of abs on cardio days)
    // If cardio is in the program, cap main exercises at 4-5 to leave room for cardio
    const hasCardio = cardioGroups.length > 0;
    const mainExCap = hasCardio ? 4 : 6;
    let selected = selectUpToExCount(scored, mainExCap, true);
    if (absGroups[0] && !hasCardio) selected.push(absGroups[0]);
    if (hasCardio) selected.push(...cardioGroups);
    return selected;
  }

  // 30 min: max 4 exercises total, no abs, no cardio
  const selected = selectUpToExCount(scored, 4, true);
  return selected;
};

const calculateCardioMinutes = (groups: any[], sessionLength: number): number => {
  const nonCardioGroups = groups.filter(g => g.type !== "cardio");
  // Estimate time for strength work: ~3.5 mins per exercise including rest
  const totalExercises = groups.filter(g => g.type !== "cardio").reduce((sum, g) => sum + (g.exercises?.length || 0), 0);
  const minutesPerExercise = sessionLength <= 30 ? 3 : sessionLength <= 45 ? 3.5 : 4.5;
  const estimatedStrengthMinutes = Math.round(totalExercises * minutesPerExercise);
  // Warmup buffer — always assume 5 mins
  const warmupBuffer = 5;
  const remainingMinutes = sessionLength - estimatedStrengthMinutes - warmupBuffer;
  // Clamp between 10 and 45 minutes
  const isCardioOnly = groups.filter(g => g.type !== "cardio").length === 0;
  const maxCardio = isCardioOnly ? 55 : 45;
  return Math.round(Math.min(maxCardio, Math.max(10, remainingMinutes)) / 5) * 5;
};

