// ─── Expand abbreviated day titles ─────────────────────────────────────────
// "Day 4 — Upper" → "Day 4 — Upper Body", "Day 2 — Lower/Cardio" → "Day 2 — Lower Body/Cardio"
const expandDayTitle = (title: string): string => {
  if (!title) return title;
  return title
    .replace(/— Upper$/i, "— Upper Body")
    .replace(/— Lower$/i, "— Lower Body")
    .replace(/— Upper\//gi, "— Upper Body/")
    .replace(/\/Upper\//gi, "/Upper Body/")
    .replace(/\/Upper$/gi, "/Upper Body")
    .replace(/— Lower\//gi, "— Lower Body/")
    .replace(/\/Lower\//gi, "/Lower Body/")
    .replace(/\/Lower$/gi, "/Lower Body");
};

