// ─── Rest Timer ────────────────────────────────────────────────────────────────
const RestTimer = ({ restLabel, onDone, showWater = false }) => {
  const getSeconds = (label: string) => {
    if (label.includes("30-45")) return 37;
    if (label.includes("45-60")) return 45;  // lean to lower end
    if (label.includes("60-90")) return 60;  // default to 60 — user decides if they need more
    if (label.includes("90-120")) return 105; // midpoint
    if (label === "30 seconds") return 30;
    if (label === "60 seconds") return 60;
    if (label.includes("2 min") || label.includes("120")) return 110; // lean to 2 mins
    return 60;
  };
  const [seconds, setSeconds] = useState(getSeconds(restLabel));

  useEffect(() => {
    if (seconds <= 0) { onDone(); return; }
    const t = setTimeout(() => setSeconds(s => s - 1), 1000);
    return () => clearTimeout(t);
  }, [seconds]);

  const pct = seconds / getSeconds(restLabel);

  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "60px 32px 0" }}>
      <p style={{ color: COLORS.textSecondary, fontSize: 14, fontWeight: 600, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 32px" }}>{showWater ? "Rest Between Groups" : "Rest Time"}</p>
      {showWater && (
        <div style={{ background: `${COLORS.primary}15`, border: `1px solid ${COLORS.primary}30`, borderRadius: 16, padding: "12px 20px", marginBottom: 24, display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontSize: 20 }}>💧</span>
          <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: 0 }}>Good time to grab some water</p>
        </div>
      )}
      <div style={{ position: "relative", width: 160, height: 160, marginBottom: 32 }}>
        <svg width="160" height="160" style={{ transform: "rotate(-90deg)" }}>
          <circle cx="80" cy="80" r="70" fill="none" stroke={COLORS.border} strokeWidth="8" />
          <circle cx="80" cy="80" r="70" fill="none" stroke={COLORS.accent} strokeWidth="8" strokeLinecap="round"
            strokeDasharray={`${2 * Math.PI * 70}`}
            strokeDashoffset={`${2 * Math.PI * 70 * (1 - pct)}`}
            style={{ transition: "stroke-dashoffset 1s linear" }} />
        </svg>
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", textAlign: "center" }}>
          <p style={{ color: COLORS.white, fontSize: 48, fontWeight: 900, margin: 0, letterSpacing: -2 }}>{seconds}</p>
          <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>seconds</p>
        </div>
      </div>
      <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: "0 0 32px", textAlign: "center", lineHeight: 1.5 }}>
        {restLabel}
      </p>
      <button onClick={onDone} style={{ padding: "14px 40px", borderRadius: 14, border: `1px solid ${COLORS.border}`, background: "transparent", color: COLORS.textSecondary, fontSize: 15, fontWeight: 600, cursor: "pointer" }}>
        Skip Rest
      </button>
    </div>
  );
};

// ─── Active Exercise Screen ────────────────────────────────────────────────────

// ─── Swap Exercise Algorithm ──────────────────────────────────────────────────
// Swap is NEUTRAL — user taps because they want a change, not because of injury.
// The algorithm finds the best replacement following a strict cascade:
//   1. Same muscle group + same equipment + same difficulty → ideal match
//   2. Same muscle group + same equipment + any difficulty → equipment match
//   3. Same muscle group + compatible equipment + same difficulty → equipment flex
//   4. Same muscle group + any available equipment → muscle group match
// Equipment compatibility: gym-and-bands can use both; gym-only avoids bands; bands-only avoids machines
// Injury flags from onboarding profile are respected — excluded from swap candidates
// Exercise already in current group is excluded to avoid duplicates
// Swap persists for that session only — next session returns to original program

const getSwapCandidates = (
  exerciseId: string,
  originalExerciseId: string,
  currentGroupExerciseIds: string[],
  fullProgramExerciseIds: string[],  // all exercises used anywhere in the current program
  equipmentPreference: string,
  injuries: string,
  userDifficulty: string
): Array<{ id: string; name: string; score: number }> => {
  const target = EXERCISES_DATA[exerciseId];
  if (!target) return [];

  const targetMuscle = target.muscle;
  const targetEquipment = target.equipment;
  const targetDifficulty = target.difficulty || userDifficulty || "beginner";
  const injuryList = injuries ? injuries.split(",").map(i => i.trim().toLowerCase()) : [];

  // Equipment compatibility based on user preference
  const isEquipmentCompatible = (exEquipment: string): boolean => {
    if (!exEquipment) return false;
    const eq = exEquipment.toLowerCase();
    if (equipmentPreference === "bands") {
      // Bands only — allow band, bodyweight, resistance band
      return eq.includes("band") || eq.includes("bodyweight") || eq.includes("resistance");
    }
    if (equipmentPreference === "gym") {
      // Gym only — allow machines, dumbbells, barbell, cable, bodyweight — no bands
      return !eq.includes("band") && !eq.includes("resistance");
    }
    // gym-and-bands — allow everything
    return true;
  };

  const candidates: Array<{ id: string; name: string; score: number }> = [];

  Object.entries(EXERCISES_DATA).forEach(([id, ex]: [string, any]) => {
    // Skip: same exercise, already in group, no muscle match
    if (id === exerciseId && id !== originalExerciseId) return;
    if (id !== originalExerciseId && currentGroupExerciseIds.includes(id)) return;
    if (ex.muscle !== targetMuscle) return;
    if (!isEquipmentCompatible(ex.equipment)) return;

    // Skip if any of the user's parsed injury flags match this exercise's injury flags
    const activeInjuryFlags = parseInjuryFlags(injuries);
    if (ex.injuryFlags && activeInjuryFlags.length > 0) {
      const hasConflict = ex.injuryFlags.some((flag: string) => activeInjuryFlags.includes(flag));
      if (hasConflict) return;
    }

    // Must have a video mapping
    if (!VIMEO_VIDEOS[id]) return;

    // Score: higher = better match
    let score = 0;
    if (fullProgramExerciseIds.includes(id)) score -= 15;      // deprioritize if already in program elsewhere
    if (ex.equipment === targetEquipment) score += 30;         // same equipment = highest priority
    else if (isEquipmentCompatible(ex.equipment)) score += 10; // compatible equipment
    if (ex.difficulty === targetDifficulty) score += 20;        // same difficulty
    else if (ex.difficulty === "beginner") score += 5;          // easier is safer than harder

    candidates.push({ id, name: ex.name, score });
  });

  // Sort by score descending, then alphabetically for consistency
  return candidates.sort((a, b) => b.score - a.score || a.name.localeCompare(b.name));
};

