const MUSCLE_COLORS = {
  weight: COLORS.accent,
  waist: "#FF6B35",
  hips: "#A78BFA",
  arms: "#2ECC71",
  chest: "#F59E0B",
  neck: "#06B6D4",
  thighs: "#EC4899",
};

const MiniGraph = ({ data, color, unit = "lbs", activeMetric = "weight" }) => {
  if (!data || data.length === 0) return (
    <div style={{ height: 60, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0, textAlign: "center" }}>Tap + Log Stats to set your baseline and start tracking</p>
    </div>
  );
  if (data.length < 2) return (
    <div style={{ height: 60, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0, textAlign: "center" }}>Your starting weight is logged. Add measurements and log weekly to track your progress.</p>
    </div>
  );

  const values = data.map(d => d.value);
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = max - min || 1;
  const w = 280;
  const h = 60;
  const pad = 8;

  const points = data.map((d, i) => {
    const x = pad + (i / (data.length - 1)) * (w - pad * 2);
    const y = h - pad - ((d.value - min) / range) * (h - pad * 2);
    return `${x},${y}`;
  });

  const validData = data.filter(d => d.value != null);
  if (validData.length < 2) return null;
  const first = validData[0].value;
  const last = validData[validData.length - 1].value;
  const diff = last - first;
  const sign = diff > 0 ? "+" : "";

  return (
    <div style={{ overflow: "hidden", width: "100%" }}>
      <svg width="100%" height={h} viewBox={`0 0 ${w} ${h}`} preserveAspectRatio="none" style={{ display: "block" }}>
        <defs>
          <linearGradient id="graphGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={color} stopOpacity="0.3" />
            <stop offset="100%" stopColor={color} stopOpacity="0" />
          </linearGradient>
        </defs>
        <polyline
          points={points.join(" ")}
          fill="none"
          stroke={color}
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
        {data.map((d, i) => {
          const x = pad + (i / (data.length - 1)) * (w - pad * 2);
          const y = h - pad - ((d.value - min) / range) * (h - pad * 2);
          return <circle key={i} cx={x} cy={y} r="4" fill={color} />;
        })}
      </svg>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
        <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>{data[0].label}</span>
        <span style={{ color: (unit === "in" || unit === "cm") && activeMetric === "arms" ? (diff >= 0 ? COLORS.success : "#FF6B35") : diff <= 0 ? COLORS.success : "#FF6B35", fontSize: 13, fontWeight: 700 }}>
          {sign}{diff.toFixed(1)} {unit} since start
        </span>
        <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>{data[data.length - 1].label}</span>
      </div>
    </div>
  );
};

const ThirtyDayCalendar = ({ completedDays, restDays = [] as number[], totalDays = 30, currentDay = 1 }) => {
  const days = Array.from({ length: totalDays }, (_, i) => i + 1);
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
      {days.map(d => {
        const isCompleted = completedDays.includes(d);
        const isRest = restDays.includes(d);
        const isToday = d === currentDay;
        return (
          <div key={d} style={{
            width: 32, height: 32, borderRadius: 8,
            display: "flex", alignItems: "center", justifyContent: "center",
            background: isCompleted
              ? `${COLORS.success}25`
              : isToday
              ? `${COLORS.primary}40`
              : isRest
              ? `${COLORS.textSecondary}12`
              : "transparent",
            border: `1.5px solid ${
              (isToday && isCompleted) ? COLORS.success
              : isToday ? COLORS.accent
              : isCompleted ? COLORS.success
              : isRest ? `${COLORS.textSecondary}30`
              : COLORS.border
            }`,
            position: "relative",
            transition: "all 0.2s ease",
          }}>
            {isCompleted ? (
              <Check size={14} color={COLORS.success} strokeWidth={2.5} />
            ) : isRest ? (
              <span style={{ fontSize: 13 }}>🌙</span>
            ) : (
              <span style={{
                fontSize: 11,
                fontWeight: isToday ? 700 : 400,
                color: isToday ? COLORS.white : COLORS.textSecondary,
              }}>{d}</span>
            )}
            {/* Blue dot always shows on today — even after completion */}
            {isToday && (
              <div style={{
                position: "absolute", bottom: -3, left: "50%",
                transform: "translateX(-50%)",
                width: 4, height: 4, borderRadius: 99,
                background: COLORS.accent,
              }} />
            )}
          </div>
        );
      })}
    </div>
  );
};

const LogStatsModal = ({ onSave, onClose, unit, isBaseline = false, wellnessMode = false, canLogMetric = null as any, getMetricDaysSinceLastLog = null as any }) => {
  const [weight, setWeight] = useState("");
  const [waist, setWaist] = useState("");
  const [hips, setHips] = useState("");
  const [arms, setArms] = useState("");
  const [chest, setChest] = useState("");
  const [neck, setNeck] = useState("");
  const [thighs, setThighs] = useState("");

  const isLocked = (key: string) => !isBaseline && canLogMetric && !canLogMetric(key);
  const daysLeft = (key: string) => {
    if (!getMetricDaysSinceLastLog) return 0;
    const days = getMetricDaysSinceLastLog(key);
    return days === null ? 0 : Math.max(0, 7 - days);
  };

  const inputStyle = (hasVal, locked = false) => ({
    flex: 1, padding: "12px 10px", borderRadius: 12,
    border: `1.5px solid ${locked ? COLORS.border : hasVal ? COLORS.accent : COLORS.border}`,
    background: locked ? `${COLORS.border}30` : COLORS.background,
    color: locked ? COLORS.textSecondary : COLORS.white, fontSize: 16,
    fontWeight: 700, textAlign: "center" as const, outline: "none",
    fontFamily: "'Inter', sans-serif", boxSizing: "border-box" as const,
    width: "100%", cursor: locked ? "not-allowed" : "text",
  });

  const handleSave = () => {
    const hasAnyValue = weight || waist || hips || arms || chest || neck || thighs;
    if (!hasAnyValue && !isBaseline) return;
    const now = new Date();
    const label = `${now.toLocaleString("default", { month: "short" })} ${now.getDate()}`;
    onSave({
      weight: Number(weight) || null,
      waist: Number(waist) || null,
      hips: Number(hips) || null,
      arms: Number(arms) || null,
      chest: Number(chest) || null,
      neck: Number(neck) || null,
      thighs: Number(thighs) || null,
      label,
      date: now.toISOString(),
    });
    // Clear entered values and stay open so user can log more metrics
    setWeight("");
    setWaist("");
    setHips("");
    setArms("");
    setChest("");
    setNeck("");
    setThighs("");
  };

  const measureLabel = unit === "metric" ? "cm" : "in";

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.85)",
      display: "flex", alignItems: "flex-end", justifyContent: "center",
      zIndex: 100, fontFamily: "'Inter', sans-serif",
    }}>
      <style>{`.lst-scroll::-webkit-scrollbar{display:none}`}</style>
      <div className="lst-scroll" style={{
        background: COLORS.card, borderRadius: "24px 24px 0 0",
        padding: "24px 24px 48px", width: "100%", maxWidth: 480,
        border: `1px solid ${COLORS.border}`, maxHeight: "90vh", overflowY: "auto",
        scrollbarWidth: "none" as any,
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <h2 style={{ color: COLORS.white, fontSize: 20, fontWeight: 800, margin: 0 }}>Log Your Stats</h2>
          <button onClick={onClose} style={{ background: "none", border: "none", color: COLORS.textSecondary, fontSize: 24, cursor: "pointer" }}>×</button>
        </div>
        <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 20px", lineHeight: 1.5 }}>
          {isBaseline ? "Set your baseline measurements so we can track your progress from day one." : "Log when you feel ready. Weekly check-ins give the most accurate picture of your progress."}
        </p>
        <div style={{ marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <p style={{ color: COLORS.textSecondary, fontSize: 12, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", margin: 0 }}>
              Weight ({unit === "metric" ? "kg" : "lbs"}) <span style={{ color: COLORS.accent }}>*</span>
            </p>
            {isLocked("weight") && (
              <span style={{ color: "#F59E0B", fontSize: 11, fontWeight: 700 }}>🔒 Available in {daysLeft("weight")}d</span>
            )}
          </div>
          <input type="number" placeholder={isLocked("weight") ? "Locked" : "0"} value={weight}
            onChange={e => !isLocked("weight") && setWeight(e.target.value)}
            disabled={isLocked("weight")}
            style={inputStyle(!!weight, isLocked("weight"))} />
        </div>
        {!wellnessMode && (
          <>
            <p style={{ color: COLORS.textSecondary, fontSize: 12, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 10px" }}>
              Measurements ({measureLabel}) — Optional
            </p>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 10 }}>
              {[
                { label: "Waist", val: waist, set: setWaist, key: "waist" },
                { label: "Chest", val: chest, set: setChest, key: "chest" },
                { label: "Arms", val: arms, set: setArms, key: "arms" },
              ].map(f => {
                const locked = isLocked(f.key);
                return (
                  <div key={f.label} style={{ textAlign: "center" }}>
                    <input type="number" placeholder={locked ? "🔒" : "0"} value={f.val}
                      onChange={e => !locked && f.set(e.target.value)}
                      disabled={locked} style={inputStyle(!!f.val, locked)} />
                    <p style={{ color: locked ? "#F59E0B" : COLORS.textSecondary, fontSize: 11, margin: "5px 0 0", fontWeight: 600 }}>
                      {f.label}{locked ? ` (${daysLeft(f.key)}d)` : ""}
                    </p>
                  </div>
                );
              })}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 24 }}>
              {[
                { label: "Hips", val: hips, set: setHips, key: "hips" },
                { label: "Neck", val: neck, set: setNeck, key: "neck" },
                { label: "Thighs", val: thighs, set: setThighs, key: "thighs" },
              ].map(f => {
                const locked = isLocked(f.key);
                return (
                  <div key={f.label} style={{ textAlign: "center" }}>
                    <input type="number" placeholder={locked ? "🔒" : "0"} value={f.val}
                      onChange={e => !locked && f.set(e.target.value)}
                      disabled={locked} style={inputStyle(!!f.val, locked)} />
                    <p style={{ color: locked ? "#F59E0B" : COLORS.textSecondary, fontSize: 11, margin: "5px 0 0", fontWeight: 600 }}>
                      {f.label}{locked ? ` (${daysLeft(f.key)}d)` : ""}
                    </p>
                  </div>
                );
              })}
            </div>
          </>
        )}
        {(() => {
          const hasAnyValue = [
            { key: "weight", val: weight }, { key: "waist", val: waist },
            { key: "hips", val: hips }, { key: "arms", val: arms },
            { key: "chest", val: chest }, { key: "neck", val: neck }, { key: "thighs", val: thighs }
          ].some(f => f.val && !isLocked(f.key));
          return (
            <button onClick={handleSave} disabled={!hasAnyValue} style={{
              width: "100%", padding: "18px", borderRadius: 16, border: "none",
              background: !hasAnyValue ? COLORS.border : `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`,
              color: !hasAnyValue ? COLORS.textSecondary : COLORS.white,
              fontSize: 16, fontWeight: 700, cursor: !hasAnyValue ? "not-allowed" : "pointer",
              boxShadow: !hasAnyValue ? "none" : `0 8px 30px ${COLORS.primary}40`,
            }}>Save Stats</button>
          );
        })()}
      </div>
    </div>
  );
};

const ProgressScreen = ({ profile, onBack, onNavigate = (s) => {}, onUpdate = (p) => {} }) => {
  const [activeMetric, setActiveMetric] = useState("weight");
  const [showLogModal, setShowLogModal] = useState(false);
  // Workout history state — must live at component top level (React hooks rules)
  const [historyLoaded, setHistoryLoaded] = useState(false);
  const [historyLoading, setHistoryLoading] = useState(false);
  const [sessionHistory, setSessionHistory] = useState<any[]>([]);
  const [historyExpanded, setHistoryExpanded] = useState(false);
  const [selectedSession, setSelectedSession] = useState<any>(null);

  // Auto-load history when Progress tab opens — shows sessions immediately after completion
  // Also reloads when sessionsCompleted changes (user just finished a workout)
  const sessionsCompleted = profile?.sessionsCompleted || 0;
  useEffect(() => {
    if (profile?.uid) {
      setHistoryLoading(true);
      setHistoryLoaded(false);
      // Small delay to ensure Firestore write from workout completion has propagated
      fetchWorkoutHistory(profile.uid).then(sessions => {
        setSessionHistory(sessions);
        setHistoryLoaded(true);
        setHistoryLoading(false);
      });
    }
  }, [profile?.uid, sessionsCompleted]);

  useEffect(() => {
    const uid = profile?.uid || auth.currentUser?.uid;
    if (uid) {
      fetchWorkoutHistory(uid).then(sessions => {
        setSessionHistory(sessions);
        setHistoryLoaded(true);
        setHistoryLoading(false);
      });
    }
  }, [profile?.uid, profile?.sessionsCompleted]);
  const wellnessMode = profile?.wellnessMode || false;
  const unit = profile?.heightFt ? "imperial" : "metric";
  const startWeight = unit === "imperial"
    ? (Number(profile?.weightLbs) || null)
    : (Number(profile?.weightKg) || null);
  const weightUnit = unit === "imperial" ? "lbs" : "kg";
  const measureUnit = unit === "imperial" ? "in" : "cm";
  const seedBaseline = (): any[] => {
    if (!startWeight) return [];
    return [{ weight: startWeight, waist: null, hips: null, arms: null, chest: null, neck: null, thighs: null, label: "Baseline", date: profile?.createdAt || new Date().toISOString() }];
  };
  const rawLogs: any[] = (profile?.statsLogs && profile.statsLogs.length > 0) ? profile.statsLogs : seedBaseline();
  const hasBaselineEntry = rawLogs.some(l => l.label === "Baseline");
  const logs: any[] = hasBaselineEntry ? rawLogs : [
    { weight: startWeight, waist: null, hips: null, arms: null, chest: null, neck: null, thighs: null, label: "Baseline", date: profile?.createdAt || rawLogs[0]?.date || new Date().toISOString() },
    ...rawLogs,
  ];
  const hasBaseline = logs.length > 0;

  const completedDays: number[] = profile?.completedProgramDays || [];
  const restDayNumbers: number[] = (() => {
    const progKey = profile?.programKey;
    if (!progKey) return [];
    const isMonth6 = progKey.startsWith("month6-");
    if (!isMonth6 && profile?.restProgramDays?.length > 0) return profile.restProgramDays;
    if (isMonth6) {
      const freq = profile?.frequency || 6;
      const restDaysByFrequency: Record<number, number[]> = {
        6: [7], 5: [4, 7], 4: [3, 5, 7], 3: [2, 4, 6, 7], 2: [2, 4, 5, 6, 7],
      };
      const weekRestDays = restDaysByFrequency[freq] || [7];
      const allRestDays: number[] = [];
      for (let day = 1; day <= 30; day++) {
        const cycleDay = ((day - 1) % 7) + 1;
        if (weekRestDays.includes(cycleDay)) allRestDays.push(day);
      }
      return allRestDays;
    }
    // For regular programs use PROGRAMS data
    const baseProgramKey = isMonth6 ? progKey.replace("month6-", "") : progKey;
    const program = PROGRAMS[baseProgramKey];
    if (!program?.days) return [];
    const programLength = program.days.length;
    const restIndices = program.days
      .filter((d: any) => d.isRest)
      .map((d: any) => d.dayNum)
      .filter(Boolean);
    const allRestDays: number[] = [];
    for (let day = 1; day <= 30; day++) {
      const cycleDay = ((day - 1) % programLength) + 1;
      if (restIndices.includes(cycleDay)) allRestDays.push(day);
    }
    return allRestDays;
  })();
  const workoutDoneToday = profile?.lastSessionDate === new Date().toDateString();
  const rawProgramDay = profile?.programDay || 1;
  const currentDay = workoutDoneToday ? Math.max(rawProgramDay - 1, 1) : rawProgramDay;
  const totalSessions = profile?.cycleSessionsCompleted || 0;
  const frequency = profile?.frequency || 3;
  const weeklyTarget = frequency;
  const sessionsThisWeek = profile?.sessionsThisWeek || 0;
  const completionPct = Math.round((totalSessions / 30) * 100);
  const streak = profile?.streak || 0;

  const weightData = logs.filter(l => l.weight != null).map(l => ({ value: l.weight, label: l.label }));
  const waistData = logs.filter(l => l.waist).map(l => ({ value: l.waist, label: l.label }));
  const hipsData = logs.filter(l => l.hips).map(l => ({ value: l.hips, label: l.label }));
  const armsData = logs.filter(l => l.arms).map(l => ({ value: l.arms, label: l.label }));
  const chestData = logs.filter(l => l.chest).map(l => ({ value: l.chest, label: l.label }));
  const neckData = logs.filter(l => l.neck).map(l => ({ value: l.neck, label: l.label }));
  const thighsData = logs.filter(l => l.thighs).map(l => ({ value: l.thighs, label: l.label }));

  const getActiveData = () => {
    if (activeMetric === "weight") return weightData;
    if (activeMetric === "waist") return waistData;
    if (activeMetric === "hips") return hipsData;
    if (activeMetric === "arms") return armsData;
    if (activeMetric === "chest") return chestData;
    if (activeMetric === "neck") return neckData;
    if (activeMetric === "thighs") return thighsData;
    return weightData;
  };

  
  // Per-metric: can this metric be logged today?
  const metricKeys: Record<string, string> = {
    weight: "weight", waist: "waist", hips: "hips",
    arms: "arms", chest: "chest", neck: "neck", thighs: "thighs",
  };
  const getMetricDaysSinceLastLog = (metricKey: string) => {
    // Each metric locks independently — find the last log that has a value for THIS metric
    const logsWithValue = logs.filter(l => l[metricKey] != null && l.label !== "Baseline");
    if (logsWithValue.length === 0) return null;
    const lastMetricLog = logsWithValue[logsWithValue.length - 1];
    return Math.floor((Date.now() - new Date(lastMetricLog.date).getTime()) / (1000 * 60 * 60 * 24));
  };
  const canLogMetric = (metricKey: string) => {
    const days = getMetricDaysSinceLastLog(metricKey);
    return days === null || days >= 7;
  };const handleSaveLog = (entry: any) => {
    const label = logs.length === 0 ? "Baseline" : entry.label;
    const filteredEntry: any = { label, date: entry.date };
    const metricKeyList = ["weight", "waist", "hips", "arms", "chest", "neck", "thighs"];
    metricKeyList.forEach(key => {
      if (entry[key] != null && canLogMetric(key)) {
        filteredEntry[key] = entry[key];
      }
    });
  
    const updatedLogs = [...logs, filteredEntry];
    onUpdate({ ...profile, statsLogs: updatedLogs });
  };
  const metrics = wellnessMode
    ? [{ id: "weight", label: "Weight" }]
    : [
        { id: "weight", label: "Weight" },
        { id: "waist", label: "Waist" },
        { id: "hips", label: "Hips" },
        { id: "arms", label: "Arms" },
        { id: "chest", label: "Chest" },
        { id: "neck", label: "Neck" },
        { id: "thighs", label: "Thighs" },
      ];

  // Overall can-log: at least one metric can be logged
  const canLogToday = metrics.some(m => canLogMetric(m.id));
  const activeMetricDays = getMetricDaysSinceLastLog(activeMetric);
  const activeMetricCanLog = canLogMetric(activeMetric);
  const daysUntilNextLog = activeMetricDays === null ? 0 : Math.max(0, 7 - activeMetricDays);

  // Numbers detail view — show all logged values for a metric
  const [showMetricDetail, setShowMetricDetail] = useState(false);

  // Get all logs for the active metric with dates and values
  const getActiveMetricHistory = () => {
    return logs
      .filter(l => l[activeMetric] != null)
      .map(l => ({
        value: l[activeMetric],
        label: l.label,
        date: l.date ? new Date(l.date).toLocaleDateString("en-US", { month: "short", day: "numeric" }) : "—",
      }))
      .reverse(); // newest first
  };

  return (
    <div style={{
      height: "100vh", background: COLORS.background,
      fontFamily: "'Inter', sans-serif", display: "flex",
      flexDirection: "column", overflow: "hidden", overflowY: "auto",
    }}>
      {/* Header */}
      <div style={{ padding: "52px 24px 20px", background: `linear-gradient(180deg, ${COLORS.primary}18 0%, transparent 100%)` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
          <h1 style={{ color: COLORS.white, fontSize: 28, fontWeight: 900, margin: 0, letterSpacing: -0.8 }}>Progress</h1>
          <button
            onClick={() => setShowLogModal(true)}
            title={!canLogToday ? `All metrics locked for now` : ""}
            style={{
              padding: "10px 18px", borderRadius: 12, border: "none",
              background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`,
              color: COLORS.white,
              fontSize: 13, fontWeight: 700,
              cursor: "pointer",
              boxShadow: `0 4px 16px ${COLORS.primary}40`,
              transition: "all 0.2s ease",
            }}
          >
            {wellnessMode ? (canLogToday ? "Log Weight" : `Log in ${daysUntilNextLog}d`) : (canLogToday ? "+ Log Stats" : `Log in ${daysUntilNextLog}d`)}
          </button>
        </div>
        <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: 0 }}>
          {(() => {
            const isMonth6 = profile?.programKey?.startsWith("month6-");
            const baseKey = isMonth6 ? profile.programKey.replace("month6-", "") : profile?.programKey;
            const rawLabel = PROGRAMS[baseKey]?.label || "";
            const { name, levelTag } = getProgramParts(rawLabel);
            const effectiveLevel = profile?.effectiveLevel || profile?.experience || "";
            const levelLabel = effectiveLevel === "advanced" ? "Advanced" : effectiveLevel === "intermediate" ? "Intermediate" : effectiveLevel === "beginner" ? "Beginner" : effectiveLevel === "senior-beginner" ? "Senior Beginner" : effectiveLevel === "senior-intermediate" ? "Senior Intermediate" : levelTag;
            const cycleLabel = isMonth6 ? " (Evolved)" : "";
            const motivationalName = getProgramMotivationalName(profile?.programKey || "");
            const cleanName = isMonth6 ? getEvolvedProgramName(profile?.programKey || "") : (motivationalName || name || rawLabel.replace(/^(men's|women's|senior\s*)?(beginner|intermediate|advanced)\s*\d*x?\/?week?\s*[-—]?\s*/i, "").trim() || rawLabel);
            const nameHasLevel = levelLabel && cleanName.toLowerCase().includes(levelLabel.toLowerCase());
            if (!cleanName) return "Your current program";
            return (
              <span>
                <span style={{ color: COLORS.white, fontWeight: 600 }}>{cleanName}{cycleLabel}</span>
                {levelLabel && !nameHasLevel ? <span style={{ color: COLORS.accent, fontSize: 12, marginLeft: 6, fontWeight: 600 }}>· {levelLabel}</span> : null}
              </span>
            );
          })()}
        </p>
      </div>

      <div style={{ padding: "0 24px 80px" }}>

        {/* Wellness mode banner */}
        {wellnessMode && (
          <div style={{
            background: `${COLORS.primary}15`, border: `1px solid ${COLORS.primary}30`,
            borderRadius: 14, padding: "12px 16px", marginBottom: 16,
            display: "flex", alignItems: "center", gap: 10,
          }}>
            <span style={{ fontSize: 18 }}>🌿</span>
            <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, lineHeight: 1.5 }}>
              Wellness mode is on. Focus on consistency. Body measurements are paused.
            </p>
          </div>
        )}

        {/* ── Results Section ── */}
        <div style={{ background: COLORS.card, borderRadius: 20, padding: "20px", marginBottom: 16, border: `1px solid ${COLORS.border}` }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Results</p>
            {getActiveMetricHistory().length > 0 && (
              <button
                onClick={() => setShowMetricDetail(v => !v)}
                style={{ background: "transparent", border: `1px solid ${COLORS.border}`, borderRadius: 8, padding: "4px 10px", color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, cursor: "pointer" }}
              >
                {showMetricDetail ? "Hide Numbers" : "See Numbers"}
              </button>
            )}
          </div>

          {/* Metric toggle — shows lock state per metric */}
          <div style={{ display: "flex", gap: 8, marginBottom: 20, overflowX: "auto" }}>
            {metrics.map(m => {
              const isActive = activeMetric === m.id;
              const locked = !canLogMetric(m.id);
              return (
                <button
                  key={m.id}
                  onClick={() => { setActiveMetric(m.id); }}
                  style={{
                    padding: "8px 16px", borderRadius: 99, border: "none",
                    background: isActive ? MUSCLE_COLORS[m.id] : locked ? `${COLORS.border}80` : COLORS.border,
                    color: isActive ? COLORS.white : locked ? COLORS.textSecondary + "80" : COLORS.textSecondary,
                    fontSize: 13, fontWeight: 700, cursor: "pointer",
                    flexShrink: 0, transition: "all 0.2s ease",
                    boxShadow: isActive ? `0 4px 12px ${MUSCLE_COLORS[m.id]}40` : "none",
                    opacity: locked && !isActive ? 0.6 : 1,
                  }}
                >
                  {m.label}
                </button>
              );
            })}
          </div>

          {/* Numbers detail view — all logged entries for this metric */}
          {showMetricDetail ? (
            <div>
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 12px" }}>
                {metrics.find(m => m.id === activeMetric)?.label} History
              </p>
              {getActiveMetricHistory().map((entry, i, arr) => {
                const prevEntry = arr[i + 1]; // arr is newest-first, so next index = older entry
                const delta = prevEntry ? entry.value - prevEntry.value : null;
                const deltaColor = delta === null ? COLORS.textSecondary : delta < 0 ? COLORS.success : delta > 0 ? "#FF4D4D" : COLORS.textSecondary;
                const deltaLabel = delta === null ? "" : `${delta > 0 ? "+" : ""}${delta.toFixed(1)} ${activeMetric === "weight" ? weightUnit : measureUnit}`;
                return (
                  <div key={i} style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: "10px 0",
                    borderBottom: i < arr.length - 1 ? `1px solid ${COLORS.border}` : "none",
                  }}>
                    <div>
                      <p style={{ color: COLORS.white, fontSize: 16, fontWeight: 700, margin: "0 0 2px" }}>
                        {entry.value} {activeMetric === "weight" ? weightUnit : measureUnit}
                      </p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{entry.label}</p>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      {delta !== null && (
                        <p style={{ color: deltaColor, fontSize: 13, fontWeight: 700, margin: "0 0 2px" }}>{deltaLabel}</p>
                      )}
                      <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>{entry.date}</p>
                    </div>
                  </div>
                );
              })}
              {!activeMetricCanLog && (
                <p style={{ color: COLORS.textSecondary, fontSize: 12, textAlign: "center", margin: "12px 0 0" }}>
                  Next {metrics.find(m => m.id === activeMetric)?.label} log available in {daysUntilNextLog} day{daysUntilNextLog !== 1 ? "s" : ""}
                </p>
              )}
            </div>
          ) : (
            <MiniGraph data={getActiveData()} color={MUSCLE_COLORS[activeMetric]} unit={activeMetric === "weight" ? weightUnit : measureUnit} activeMetric={activeMetric} />
          )}
        </div>

        {/* ── Consistency Section ── */}
        <div style={{ background: COLORS.card, borderRadius: 20, padding: "20px", marginBottom: 16, border: `1px solid ${COLORS.border}` }}>
          <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 16px" }}>Consistency</p>

          <div style={{ display: "flex", gap: 12, marginBottom: 16 }}>
            {/* Streak */}
            <div style={{ flex: 1, background: COLORS.background, borderRadius: 14, padding: "16px 12px", textAlign: "center", border: `1px solid ${COLORS.border}` }}>
              <p style={{ fontSize: 28, fontWeight: 900, color: streak > 0 ? "#FF6B35" : COLORS.textSecondary, margin: "0 0 2px" }}>
                {streak}{streak > 0 ? " 🔥" : ""}
              </p>
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Streak</p>
            </div>
            {/* Completed */}
            <div style={{ flex: 1, background: COLORS.background, borderRadius: 14, padding: "16px 12px", textAlign: "center", border: `1px solid ${COLORS.border}` }}>
              <p style={{ fontSize: 28, fontWeight: 900, color: COLORS.success, margin: "0 0 2px" }}>{totalSessions}</p>
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Sessions</p>
            </div>
            {/* This week */}
            <div style={{ flex: 1, background: COLORS.background, borderRadius: 14, padding: "16px 12px", textAlign: "center", border: `1px solid ${COLORS.border}` }}>
              <p style={{ fontSize: 28, fontWeight: 900, color: COLORS.accent, margin: "0 0 2px" }}>{sessionsThisWeek}/{weeklyTarget}</p>
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>This Week</p>
            </div>
          </div>

          {/* Completion bar */}
          <div style={{ background: COLORS.background, borderRadius: 14, padding: "14px 16px", border: `1px solid ${COLORS.border}` }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
              <span style={{ color: COLORS.white, fontSize: 14, fontWeight: 600 }}>Program completion</span>
              <span style={{ color: COLORS.accent, fontSize: 14, fontWeight: 700 }}>{completionPct}%</span>
            </div>
            <div style={{ height: 6, background: COLORS.border, borderRadius: 99, overflow: "hidden" }}>
              <div style={{
                height: "100%", borderRadius: 99,
                background: `linear-gradient(90deg, ${COLORS.primary}, ${COLORS.accent})`,
                width: `${completionPct}%`, transition: "width 0.4s ease",
              }} />
            </div>
            <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "8px 0 0" }}>
              {totalSessions} of 30 sessions complete · Day {currentDay} of 30
            </p>
          </div>
        </div>

        {/* ── 30-Day Calendar ── */}
        <div style={{ background: COLORS.card, borderRadius: 20, padding: "20px", marginBottom: 16, border: `1px solid ${COLORS.border}` }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Program Calendar</p>
            <span style={{ color: COLORS.accent, fontSize: 12, fontWeight: 700 }}>Day {currentDay} of 30</span>
          </div>
          <ThirtyDayCalendar completedDays={completedDays} restDays={restDayNumbers} totalDays={30} currentDay={currentDay} />
          <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: `${COLORS.success}25`, border: `1px solid ${COLORS.success}` }} />
              <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>Completed</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <span style={{ fontSize: 12 }}>🌙</span>
              <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>Rest Day</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: `${COLORS.primary}40`, border: `1px solid ${COLORS.accent}` }} />
              <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>Today</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, border: `1px solid ${COLORS.border}` }} />
              <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>Upcoming</span>
            </div>
          </div>
        </div>

        {/* ── Body Measurements ── */}
        {!wellnessMode && logs.length > 1 && (logs[logs.length - 1].waist || logs[logs.length - 1].hips || logs[logs.length - 1].arms || logs[logs.length - 1].chest || logs[logs.length - 1].neck || logs[logs.length - 1].thighs) && (
          <div style={{ background: COLORS.card, borderRadius: 20, padding: "20px", marginBottom: 16, border: `1px solid ${COLORS.border}` }}>
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 16px" }}>Measurements</p>
            {[
              [
                { key: "waist", label: "Waist", color: "#FF6B35", goalDown: true },
                { key: "hips", label: "Hips", color: "#A78BFA", goalDown: false },
                { key: "arms", label: "Arms", color: "#2ECC71", goalDown: false },
              ],
              [
                { key: "chest", label: "Chest", color: "#F59E0B", goalDown: false },
                { key: "neck", label: "Neck", color: "#06B6D4", goalDown: true },
                { key: "thighs", label: "Thighs", color: "#EC4899", goalDown: false },
              ],
            ].map((row, ri) => (
              <div key={ri} style={{ display: "flex", gap: 10, marginBottom: ri === 0 ? 10 : 0 }}>
                {row.map(m => {
                  const latest = [...logs].reverse().find(l => l[m.key]);
                  const first = logs.find(l => l[m.key]);
                  if (!latest) return <div key={m.key} style={{ flex: 1 }} />;
                  const diff = latest[m.key] - (first?.[m.key] || latest[m.key]);
                  const sign = diff > 0 ? "+" : "";
                  const isGain = diff > 0;
                  const changeColor = m.goalDown
                    ? (isGain ? "#FF4D4D" : COLORS.success)
                    : (isGain ? COLORS.success : "#FF4D4D");
                  return (
                    <div key={m.key} style={{ flex: 1, background: COLORS.background, borderRadius: 14, padding: "12px 8px", border: `1px solid ${COLORS.border}`, textAlign: "center" }}>
                      <p style={{ color: m.color, fontSize: 18, fontWeight: 800, margin: "0 0 2px" }}>{latest[m.key]}{measureUnit}</p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 10, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.5, margin: "0 0 3px" }}>{m.label}</p>
                      {diff !== 0 && (
                        <p style={{ color: changeColor, fontSize: 10, fontWeight: 700, margin: 0 }}>
                          {sign}{diff.toFixed(1)}{measureUnit}
                        </p>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        )}

        {/* ── Workout History Section ── */}
        {(() => {
          const sessionsCompleted = profile?.sessionsCompleted || 0;

          if (sessionsCompleted === 0) return null;

          // ── Session Detail View — uses WorkoutListScreen in review mode ──
          if (selectedSession) {
            const groups = selectedSession.groups || [];
            // Determine hero image from workout type (same logic as active workout)
            const focusLower = (selectedSession.dayFocus || "").toLowerCase();
            const wType = focusLower.includes("leg") || focusLower.includes("lower") || focusLower.includes("glute") || focusLower.includes("hamstring")
              ? "lower-body"
              : focusLower.includes("chest") || focusLower.includes("push") || focusLower.includes("tricep")
              ? "push"
              : focusLower.includes("back") || focusLower.includes("pull") || focusLower.includes("bicep")
              ? "upper-body"
              : "full-body";
              const heroImage = selectedSession.heroImage || getWorkoutImage(wType, selectedSession.programDay || 1);
            const bgPos = wType === "lower-body" ? "center 60%" : "center top";

            // Build a fake day object for WorkoutListScreen
            const fakeDay = {
              dayNum: selectedSession.programDay || 1,
              title: expandDayTitle(selectedSession.dayTitle || selectedSession.dayFocus || "Workout"),
              focus: selectedSession.dayFocus || "Workout",
              isRest: false,
              groups,
              notes: [],
            };

            return (
              <WorkoutListScreen
                day={fakeDay}
                filteredGroups={groups}
                onStart={() => {}}
                onBack={() => setSelectedSession(null)}
                workoutImage={heroImage}
                programDay={selectedSession.programDay || 1}
                programWeek={Math.ceil((selectedSession.programDay || 1) / 7)}
                isReview={true}
                bgPosition={bgPos}
                equipmentPreference={selectedSession.equipmentPreference || profile?.equipmentPreference || "gym-and-bands"}
                historyMeta={{
                  completedDateStr: selectedSession.completedDateStr,
                  programLabel: selectedSession.programLabel,
                  cycleNumber: selectedSession.cycleNumber,
                  weightsLogged: selectedSession.weightsLogged || null,
                }}
              />
            );
          }

         // ── History List View ──
          const PREVIEW_COUNT = 3;
          const MAX_COUNT = 20;
          const showingAll = historyExpanded;
          const displaySessions = showingAll ? sessionHistory.slice(0, MAX_COUNT) : sessionHistory.slice(0, PREVIEW_COUNT);
          const groupedHistory = (() => {
            const byCycle: Record<number, Record<number, any[]>> = {};
            displaySessions.forEach(session => {
              const cycle = session.cycleNumber || 1;
              const dayNum = session.programDay || 1;
              const week = Math.ceil(dayNum / 7);
              if (!byCycle[cycle]) byCycle[cycle] = {};
              if (!byCycle[cycle][week]) byCycle[cycle][week] = [];
              byCycle[cycle][week].push(session);
            });
            return byCycle;
          })();
          const cycleKeys = Object.keys(groupedHistory).map(Number).sort((a, b) => b - a);        

          return (
            <div style={{ background: COLORS.card, borderRadius: 20, padding: "20px", marginBottom: 16, border: `1px solid ${COLORS.border}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Workout History</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{sessionsCompleted} sessions</p>
              </div>

              {!historyLoaded && historyLoading && (
                <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "12px 0", margin: 0 }}>Loading your workout history...</p>
              )}
              {historyLoaded && sessionHistory.length === 0 && (
                <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "12px 0", margin: 0 }}>No saved workouts yet. Complete a session and it will appear here.</p>
              )}

              {historyLoaded && cycleKeys.map(cycle => {
                const weeks = groupedHistory[cycle];
                const weekKeys = Object.keys(weeks).map(Number).sort((a, b) => b - a);
                return (
                  <div key={cycle} style={{ marginBottom: 20 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
                      <div style={{ background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, borderRadius: 8, padding: "4px 12px" }}>
                        <span style={{ color: COLORS.white, fontSize: 11, fontWeight: 800, letterSpacing: 1 }}>MONTH {cycle}</span>
                      </div>
                      <div style={{ flex: 1, height: 1, background: COLORS.border }} />
                      <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>{Object.values(weeks).flat().length} sessions</span>
                    </div>
                    {weekKeys.map(week => (
                      <div key={week} style={{ marginBottom: 12 }}>
                        <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase" as const, margin: "0 0 8px", paddingLeft: 4 }}>Week {week}</p>
                        <div style={{ background: COLORS.background, borderRadius: 14, border: `1px solid ${COLORS.border}`, overflow: "hidden" }}>
                          {weeks[week].map((session: any, si: number) => (
                            <div key={session.id || si} onClick={() => setSelectedSession(session)} style={{ display: "flex", alignItems: "center", gap: 12, padding: "13px 14px", cursor: "pointer", borderBottom: si < weeks[week].length - 1 ? `1px solid ${COLORS.border}` : "none" }}>
                              <div style={{ width: 32, height: 32, borderRadius: 99, flexShrink: 0, background: `${COLORS.success}20`, border: `1px solid ${COLORS.success}40`, display: "flex", alignItems: "center", justifyContent: "center" }}>
                                <Check size={14} color={COLORS.success} strokeWidth={3} />
                              </div>
                              <div style={{ flex: 1 }}>
                                <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 600, margin: "0 0 1px", lineHeight: 1.3 }}>{session.programName || session.dayFocus || session.dayTitle || "Workout"}</p>
                                <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: "0 0 4px" }}>{session.completedAt?.toDate ? session.completedAt.toDate().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }) : `Day ${session.programDay || "—"}`}</p>

                              </div>
                              <ChevronRight size={15} color={COLORS.border} />
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                );
              })}

{historyLoaded && sessionHistory.length > PREVIEW_COUNT && (
                <button onClick={() => onNavigate('history')} style={{ width: "100%", padding: "12px", background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, color: COLORS.primary, fontSize: 13, fontWeight: 700, cursor: "pointer", marginTop: 4 }}>
                  See all {sessionHistory.length} workouts →
                </button>
              )}
              {historyLoaded && sessionHistory.length > 0 && (
                <p style={{ color: COLORS.textSecondary, fontSize: 12, textAlign: "center", margin: "4px 0 0" }}>{sessionHistory.length} session{sessionHistory.length !== 1 ? "s" : ""} saved · Tap any to review</p>
              )}
            </div>
          );
        })()}
        <div style={{ height: 60 }} />

      </div>

      {/* Log Stats Modal */}
      {showLogModal && (
        <LogStatsModal
          onSave={handleSaveLog}
          onClose={() => setShowLogModal(false)}
          unit={unit}
          isBaseline={logs.length === 0}
          wellnessMode={wellnessMode}
          canLogMetric={canLogMetric}
          getMetricDaysSinceLastLog={getMetricDaysSinceLastLog}
        />
      )}

      <BottomNav active="progress" onNavigate={onNavigate} />
    </div>
  );
};

// ─── History Screen ───────────────────────────────────────────────────────────
const HistoryScreen = ({ profile, onBack, onNavigate = (s: string) => {} }) => {
  const [sessions, setSessions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedSession, setSelectedSession] = useState<any>(null);
  const [expandedYears, setExpandedYears] = useState<Record<number, boolean>>({});
  const [expandedMonths, setExpandedMonths] = useState<Record<string, boolean>>({});

  useEffect(() => {
    if (profile?.uid) {
      fetchWorkoutHistory(profile?.uid || auth.currentUser?.uid || "").then(s => {
        setSessions(s);
        setLoading(false);
        // Auto-expand current year and most recent month
        const currentYear = new Date().getFullYear();
        setExpandedYears({ [currentYear]: true });
        if (s.length > 0) {
          const first = s[0];
          const date = first.completedAt?.toDate ? first.completedAt.toDate() : new Date(first.completedAt);
          const cycle = first.cycleNumber || 1;
          setExpandedMonths({ [`${date.getFullYear()}-${cycle}`]: true });
        }
      });
    }
  }, [profile?.uid]);

  if (selectedSession) {
    const groups = selectedSession.groups || [];
    const wType = selectedSession.workoutType ||
      (selectedSession.dayFocus?.toLowerCase().includes("lower") || selectedSession.dayFocus?.toLowerCase().includes("leg") || selectedSession.dayFocus?.toLowerCase().includes("glute") ? "lower-body"
      : selectedSession.dayFocus?.toLowerCase().includes("push") || selectedSession.dayFocus?.toLowerCase().includes("chest") || selectedSession.dayFocus?.toLowerCase().includes("tricep") ? "push"
      : selectedSession.dayFocus?.toLowerCase().includes("pull") || selectedSession.dayFocus?.toLowerCase().includes("back") || selectedSession.dayFocus?.toLowerCase().includes("bicep") ? "upper-body"
      : selectedSession.dayFocus?.toLowerCase().includes("upper") ? "upper-body"
      : selectedSession.dayFocus?.toLowerCase().includes("abs") || selectedSession.dayFocus?.toLowerCase().includes("core") ? "core"
      : "full-body");
      const heroImage = selectedSession.heroImage || getWorkoutImage(wType, selectedSession.programDay || 1);
    const bgPos = wType === "lower-body" ? "center 60%" : "center top";
    const fakeDay = {
      dayNum: selectedSession.programDay || 1,
      title: expandDayTitle(selectedSession.dayTitle || selectedSession.dayFocus || "Workout"),
      focus: selectedSession.dayFocus || "Workout",
      isRest: false,
      groups,
      notes: [],
    };
    return (
      <WorkoutListScreen
        day={fakeDay}
        filteredGroups={groups}
        onStart={() => {}}
        onBack={() => setSelectedSession(null)}
        workoutImage={heroImage}
        programDay={selectedSession.programDay || 1}
        programWeek={Math.ceil((selectedSession.programDay || 1) / 7)}
        isReview={true}
        bgPosition={bgPos}
        equipmentPreference={selectedSession.equipmentPreference || profile?.equipmentPreference || "gym-and-bands"}
        historyMeta={{
          completedDateStr: selectedSession.completedDateStr,
          programLabel: selectedSession.programLabel,
          cycleNumber: selectedSession.cycleNumber,
        }}
      />
    );
  }

  // Group sessions by year → cycle(month) → week
  const grouped: Record<number, Record<number, Record<number, any[]>>> = {};
  sessions.forEach(session => {
    const date = session.completedAt?.toDate ? session.completedAt.toDate() : new Date(session.completedAt || Date.now());
    const year = date.getFullYear();
    const cycle = session.cycleNumber || 1;
    const week = Math.ceil((session.programDay || 1) / 7);
    if (!grouped[year]) grouped[year] = {};
    if (!grouped[year][cycle]) grouped[year][cycle] = {};
    if (!grouped[year][cycle][week]) grouped[year][cycle][week] = [];
    grouped[year][cycle][week].push(session);
  });

  const years = Object.keys(grouped).map(Number).sort((a, b) => b - a);

  const toggleYear = (year: number) => setExpandedYears(p => ({ ...p, [year]: !p[year] }));
  const toggleMonth = (key: string) => setExpandedMonths(p => ({ ...p, [key]: !p[key] }));

  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ padding: "52px 20px 16px", display: "flex", alignItems: "center", gap: 12, borderBottom: `1px solid ${COLORS.border}` }}>
        <button onClick={onBack} style={{ background: "none", border: "none", cursor: "pointer", color: COLORS.white, padding: 4 }}>
          <ArrowLeft size={22} color={COLORS.white} />
        </button>
        <div>
          <h2 style={{ color: COLORS.white, fontSize: 20, fontWeight: 800, margin: 0 }}>Workout History</h2>
          <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{sessions.length} sessions total</p>
        </div>
      </div>

      {/* Content */}
      <div style={{ flex: 1, overflowY: "auto", padding: "16px 16px 100px" }}>
        {loading && <p style={{ color: COLORS.textSecondary, textAlign: "center", marginTop: 40 }}>Loading history...</p>}
        {!loading && sessions.length === 0 && <p style={{ color: COLORS.textSecondary, textAlign: "center", marginTop: 40 }}>No workouts saved yet.</p>}

        {years.map(year => (
          <div key={year} style={{ marginBottom: 16 }}>
            {/* Year header */}
            <button onClick={() => toggleYear(year)} style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", background: "none", border: "none", cursor: "pointer", padding: "10px 0", marginBottom: 8 }}>
              <span style={{ color: COLORS.white, fontSize: 18, fontWeight: 800 }}>{year}</span>
              <ChevronRight size={18} color={COLORS.textSecondary} style={{ transform: expandedYears[year] ? "rotate(90deg)" : "none", transition: "transform 0.2s" }} />
            </button>

            {expandedYears[year] && Object.keys(grouped[year]).map(Number).sort((a, b) => b - a).map(cycle => {
              const monthKey = `${year}-${cycle}`;
              const allSessionsInMonth = Object.values(grouped[year][cycle]).flat();
              return (
                <div key={cycle} style={{ marginBottom: 10, marginLeft: 8 }}>
                  {/* Month header */}
                  <button onClick={() => toggleMonth(monthKey)} style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, cursor: "pointer", padding: "10px 14px", marginBottom: 6 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                      <div style={{ background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, borderRadius: 6, padding: "3px 10px" }}>
                        <span style={{ color: COLORS.white, fontSize: 11, fontWeight: 800, letterSpacing: 1 }}>MONTH {cycle}</span>
                      </div>
                      <span style={{ color: COLORS.textSecondary, fontSize: 12 }}>{allSessionsInMonth.length} sessions</span>
                    </div>
                    <ChevronRight size={15} color={COLORS.textSecondary} style={{ transform: expandedMonths[monthKey] ? "rotate(90deg)" : "none", transition: "transform 0.2s" }} />
                  </button>

                  {expandedMonths[monthKey] && Object.keys(grouped[year][cycle]).map(Number).sort((a, b) => b - a).map(week => (
                    <div key={week} style={{ marginLeft: 8, marginBottom: 8 }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", margin: "0 0 6px", paddingLeft: 4 }}>Week {week}</p>
                      <div style={{ background: COLORS.background, borderRadius: 12, border: `1px solid ${COLORS.border}`, overflow: "hidden" }}>
                        {grouped[year][cycle][week].map((session: any, si: number) => (
                          <div key={session.id || si} onClick={() => setSelectedSession(session)} style={{ display: "flex", alignItems: "center", gap: 12, padding: "13px 14px", cursor: "pointer", borderBottom: si < grouped[year][cycle][week].length - 1 ? `1px solid ${COLORS.border}` : "none" }}>
                            <div style={{ width: 32, height: 32, borderRadius: 99, flexShrink: 0, background: `${COLORS.success}20`, border: `1px solid ${COLORS.success}40`, display: "flex", alignItems: "center", justifyContent: "center" }}>
                              <Check size={14} color={COLORS.success} strokeWidth={3} />
                            </div>
                            <div style={{ flex: 1 }}>
                              <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 600, margin: "0 0 1px", lineHeight: 1.3 }}>{session.programName || session.dayFocus || session.dayTitle || "Workout"}</p>
                              <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>{session.completedAt?.toDate ? session.completedAt.toDate().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }) : `Day ${session.programDay || "—"}`}</p>
                            </div>
                            <ChevronRight size={15} color={COLORS.border} />
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <BottomNav active="progress" onNavigate={onNavigate} />
    </div>
  );
};
