            <button onClick={() => { setEditingField("injuries"); setTempValue(profile?.injuries ?? ""); }} style={{ background: `${COLORS.primary}20`, border: `1px solid ${COLORS.primary}40`, borderRadius: 10, padding: "6px 14px", color: COLORS.accent, fontSize: 13, fontWeight: 600, cursor: "pointer", flexShrink: 0 }}>Edit</button>
