const SuperAdminLogin = ({ onLogin, onBack }) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleLogin = () => {
    if (email === SUPER_ADMIN_CREDENTIALS.email && password === SUPER_ADMIN_CREDENTIALS.password) {
      onLogin();
    } else {
      setError("Invalid credentials.");
    }
  };

  const inputStyle = (filled: boolean) => ({
    width: "100%", padding: "16px 18px", borderRadius: 14,
    border: `1.5px solid ${filled ? COLORS.accent : COLORS.border}`,
    background: COLORS.card, color: COLORS.white, fontSize: 15,
    fontFamily: "'Inter', sans-serif", outline: "none",
    boxSizing: "border-box" as const, marginBottom: 14,
  });

  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", justifyContent: "center", padding: "0 24px" }}>
      <div style={{ marginBottom: 40 }}>
        <div style={{ width: 44, height: 44, borderRadius: 12, background: `linear-gradient(135deg, #1a1a2e, ${COLORS.primary})`, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 24, border: `1px solid ${COLORS.border}` }}>
          <Shield size={20} color={COLORS.accent} />
        </div>
        <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 8px" }}>Restricted Access</p>
        <h1 style={{ color: COLORS.white, fontSize: 26, fontWeight: 900, margin: "0 0 6px", letterSpacing: -0.5 }}>Operator Login</h1>
        <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: 0 }}>AmenityFit platform command center.</p>
      </div>

      <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} style={inputStyle(!!email)} />
      <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} style={inputStyle(!!password)} onKeyDown={e => e.key === "Enter" && handleLogin()} />

      {error && (
        <div style={{ background: "#FF4D4D15", border: "1px solid #FF4D4D40", borderRadius: 12, padding: "12px 16px", marginBottom: 16 }}>
          <p style={{ color: "#FF6B6B", fontSize: 13, margin: 0 }}>{error}</p>
        </div>
      )}

      <button onClick={handleLogin} style={{ width: "100%", padding: "18px", borderRadius: 16, border: "none", background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, color: COLORS.white, fontSize: 16, fontWeight: 700, cursor: "pointer", marginBottom: 16 }}>
        Access Command Center
      </button>
      <button onClick={onBack} style={{ background: "none", border: "none", color: COLORS.textSecondary, fontSize: 13, cursor: "pointer", padding: 8 }}>
        Back
      </button>
    </div>
  );
};

const SuperAdminDashboard = ({ onSignOut }) => {
  const [activeTab, setActiveTab] = useState<"overview" | "buildings" | "queue" | "revenue">("overview");
  const [selectedBuilding, setSelectedBuilding] = useState<any>(null);
  const [buildingSearch, setBuildingSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "active" | "at_risk" | "churned">("all");
  const [groupByCompany, setGroupByCompany] = useState(false);
  const [queueSubmissions, setQueueSubmissions] = useState<any[]>([]);
  const [queueLoading, setQueueLoading] = useState(false);
  const [queueLoaded, setQueueLoaded] = useState(false);
  const [allBuildings, setAllBuildings] = useState<any[]>([]);
  const [buildingsLoading, setBuildingsLoading] = useState(true);

  useEffect(() => {
    fetchAllBuildings().then(data => {
      setAllBuildings(data);
      setBuildingsLoading(false);
    });
  }, []);

  // Live presence — users who opened the app in the last 5 minutes
  const [liveUsers, setLiveUsers] = useState<any[]>([]);

  // Fetch presence on mount and refresh every 30 seconds
  useEffect(() => {
    const load = () => fetchLivePresence().then(setLiveUsers);
    load();
    const interval = setInterval(load, 30000);
    return () => clearInterval(interval);
  }, []);

  // Helper: live count for a specific buildingId and optional role filter
  const getLiveCount = (buildingId: string, role?: string) => {
    return liveUsers.filter(u =>
      u.buildingId === buildingId && (role ? u.role === role : true)
    ).length;
  };
  const totalLiveNow = liveUsers.length;
  // Queue filter must live at component top level — React hooks rules
  const [queueFilter, setQueueFilter] = useState<"all" | "pending" | "reviewed">("pending");
  const [activatingId, setActivatingId] = useState<string | null>(null);
  const [selectedBuildingCodes, setSelectedBuildingCodes] = React.useState<any[]>([]);
  const [showBuildingCodes, setShowBuildingCodes] = React.useState(false);
  const [batchInput, setBatchInput] = React.useState("");
  const [batchPmEmail, setBatchPmEmail] = React.useState("");
  const [batchCompanyName, setBatchCompanyName] = React.useState("");
  const [batchParsed, setBatchParsed] = React.useState<any[]>([]);
  const [batchReviewMode, setBatchReviewMode] = React.useState(false);
  const [batchActivating, setBatchActivating] = React.useState(false);
  const [batchProgress, setBatchProgress] = React.useState<{done: number; total: number; current: string; errors: string[]}>({ done: 0, total: 0, current: "", errors: [] });
  const [batchComplete, setBatchComplete] = React.useState(false);
  const [activationResult, setActivationResult] = useState<any>(null);

  const totalBuildings = allBuildings.length;
  const activeBuildings = allBuildings.filter(b => b.subscription === "active").length;
  const atRiskBuildings = allBuildings.filter(b => b.subscription === "at_risk").length;
  const churnedBuildings = allBuildings.filter(b => b.subscription === "churned").length;
  const totalResidents = allBuildings.reduce((a, b) => a + (b.inviteCodesRedeemed || 0), 0);
  const totalActive = allBuildings.reduce((a, b) => a + (b.activeUsersThisMonth || 0), 0);
  const totalWorkouts = allBuildings.reduce((a, b) => a + (b.totalWorkoutsThisMonth || 0), 0);
  const totalAssistant = allBuildings.reduce((a, b) => a + (b.fitnessAssistantQuestionsThisMonth || 0), 0);
  const month = new Date().toLocaleString("default", { month: "long", year: "numeric" });

  const statusColor = (status: string) => status === "active" ? COLORS.success : status === "at_risk" ? "#F59E0B" : "#FF4D4D";
  const statusLabel = (status: string) => status === "active" ? "Active" : status === "at_risk" ? "At Risk" : "Churned";

  const engagementScore = (b: any) => {
    const redeemed = b.inviteCodesRedeemed || b.signedUp || 0;
    const active = b.activeUsersThisMonth || b.active || 0;
    const units = b.units || 1;
    const adoption = redeemed / units;
    const activeness = redeemed > 0 ? active / redeemed : 0;
    return Math.round((adoption * 0.4 + activeness * 0.6) * 100);
  };

  const filteredBuildings = allBuildings
    .filter(b => {
      const matchesSearch = b.name.toLowerCase().includes(buildingSearch.toLowerCase()) ||
        b.location.toLowerCase().includes(buildingSearch.toLowerCase());
      const matchesStatus = statusFilter === "all" || b.subscription === statusFilter;
      return matchesSearch && matchesStatus;
    })
    .sort((a, b) => engagementScore(b) - engagementScore(a));

  const tabs = [
    { id: "overview", label: "Platform Overview" },
    { id: "buildings", label: "Buildings" },
    { id: "queue", label: "Activation Queue" },
    { id: "batch", label: "Batch Activate" },
    { id: "revenue", label: "Revenue" },
  ];

  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", overflowY: "auto" }}>
      {/* Header */}
      <div style={{ padding: "52px 24px 20px", background: `linear-gradient(180deg, rgba(30,95,190,0.15) 0%, transparent 100%)`, borderBottom: `1px solid ${COLORS.border}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
              <Shield size={12} color={COLORS.accent} />
              <span style={{ color: COLORS.accent, fontSize: 10, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase" }}>Super Admin · Operator View</span>
            </div>
            <h1 style={{ color: COLORS.white, fontSize: 22, fontWeight: 900, margin: "0 0 2px", letterSpacing: -0.5 }}>Command Center</h1>
            <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>{month}</p>
          </div>
          <button onClick={onSignOut} style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: "8px 14px", color: COLORS.textSecondary, fontSize: 13, fontWeight: 600, cursor: "pointer" }}>Sign Out</button>
        </div>
      </div>

      {/* Tab bar */}
      <div style={{ display: "flex", padding: "0 12px", borderBottom: `1px solid ${COLORS.border}`, overflowX: "auto", WebkitOverflowScrolling: "touch" as any, scrollbarWidth: "none" as any }}>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} style={{
            padding: "12px 16px", background: "none", border: "none", cursor: "pointer",
            color: activeTab === t.id ? COLORS.white : COLORS.textSecondary,
            fontSize: 13, fontWeight: activeTab === t.id ? 700 : 500,
            borderBottom: `2px solid ${activeTab === t.id ? COLORS.accent : "transparent"}`,
            whiteSpace: "nowrap" as const,
          }}>{t.label}</button>
        ))}
      </div>

      <div style={{ flex: 1, padding: "20px 24px 80px", overflowY: "auto" }}>

        {/* ── PLATFORM OVERVIEW ── */}
        {activeTab === "overview" && (
          <>
            {/* Alert banner for at-risk buildings */}
            {atRiskBuildings > 0 && (
              <div style={{ background: "#F59E0B15", border: "1px solid #F59E0B40", borderRadius: 14, padding: "12px 16px", marginBottom: 20, display: "flex", alignItems: "center", gap: 10 }}>
                <AlertTriangle size={16} color="#F59E0B" />
                <p style={{ color: "#F59E0B", fontSize: 13, margin: 0, fontWeight: 600 }}>
                  {atRiskBuildings} building{atRiskBuildings > 1 ? "s" : ""} at churn risk. Low engagement detected.
                </p>
              </div>
            )}

            {/* Platform health */}
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Platform Health</p>
            <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}`, textAlign: "center" }}>
                <p style={{ color: COLORS.success, fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{activeBuildings}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Active</p>
              </div>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}`, textAlign: "center" }}>
                <p style={{ color: "#F59E0B", fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{atRiskBuildings}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>At Risk</p>
              </div>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}`, textAlign: "center" }}>
                <p style={{ color: "#FF4D4D", fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{churnedBuildings}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Churned</p>
              </div>
            </div>

            {/* Platform totals */}
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Platform Totals — {month}</p>
            <div style={{ display: "flex", gap: 10, marginBottom: 10 }}>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                <p style={{ color: COLORS.accent, fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{totalResidents}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Total Residents</p>
              </div>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                <p style={{ color: COLORS.success, fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{totalActive}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Active Users</p>
              </div>
            </div>
            <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                <p style={{ color: "#FF6B35", fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{totalWorkouts.toLocaleString()}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Workouts Done</p>
              </div>
              <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                <p style={{ color: "#A78BFA", fontSize: 24, fontWeight: 900, margin: "0 0 4px" }}>{totalAssistant.toLocaleString()}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Assistant Sessions</p>
              </div>
            </div>

            {/* Quick building status */}
            <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Building Status</p>
            <input
              type="text"
              placeholder="Search buildings..."
              value={buildingSearch}
              onChange={e => setBuildingSearch(e.target.value)}
              style={{ width: "100%", padding: "12px 16px", borderRadius: 12, border: `1.5px solid ${COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 14, fontFamily: "'Inter', sans-serif", outline: "none", boxSizing: "border-box" as const, marginBottom: 12 }}
            />
            <div style={{ background: COLORS.card, borderRadius: 18, padding: "4px 20px", border: `1px solid ${COLORS.border}` }}>
              {filteredBuildings.map((b, i) => {
                const live = getLiveCount(String(b.id));
                return (
                <div key={b.id} onClick={() => { setSelectedBuilding(b); setShowBuildingCodes(false); setSelectedBuildingCodes([]); setActiveTab("buildings"); }} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 0", borderBottom: i < filteredBuildings.length - 1 ? `1px solid ${COLORS.border}` : "none", cursor: "pointer" }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 2 }}>
                      <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: 0 }}>{b.name}</p>
                      {live > 0 && (
                        <div style={{ display: "flex", alignItems: "center", gap: 4, background: `${COLORS.success}20`, borderRadius: 99, padding: "2px 8px" }}>
                          <div style={{ width: 6, height: 6, borderRadius: 99, background: COLORS.success, boxShadow: `0 0 5px ${COLORS.success}` }} />
                          <span style={{ color: COLORS.success, fontSize: 11, fontWeight: 700 }}>{live}</span>
                        </div>
                      )}
                    </div>
                    <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{b.location}</p>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ textAlign: "right" }}>
                      <p style={{ color: COLORS.white, fontSize: 13, fontWeight: 700, margin: "0 0 2px" }}>{engagementScore(b)}%</p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>engagement</p>
                    </div>
                    <div style={{ background: `${statusColor(b.subscription)}20`, borderRadius: 99, padding: "4px 10px", minWidth: 60, textAlign: "center" }}>
                      <span style={{ color: statusColor(b.subscription), fontSize: 11, fontWeight: 700 }}>{statusLabel(b.subscription)}</span>
                    </div>
                  </div>
                </div>
                );
              })}
              {filteredBuildings.length === 0 && (
                <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "20px 0", margin: 0 }}>No buildings match your search.</p>
              )}
            </div>
          </>
        )}

        {/* ── BUILDINGS TAB ── */}
        {activeTab === "buildings" && (
          <>
            {selectedBuilding ? (
              <>
                <button onClick={() => setSelectedBuilding(null)} style={{ display: "flex", alignItems: "center", gap: 8, background: "none", border: "none", color: COLORS.accent, fontSize: 14, fontWeight: 600, cursor: "pointer", padding: "0 0 20px", marginLeft: -4 }}>
                  <ArrowLeft size={16} color={COLORS.accent} /> All Buildings
                </button>

                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20 }}>
                  <div>
                    <h2 style={{ color: COLORS.white, fontSize: 20, fontWeight: 900, margin: "0 0 4px", letterSpacing: -0.3 }}>{selectedBuilding.name}</h2>
                    <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>{selectedBuilding.location}</p>
                  </div>
                  <div style={{ background: `${statusColor(selectedBuilding.subscription)}20`, borderRadius: 99, padding: "6px 14px" }}>
                    <span style={{ color: statusColor(selectedBuilding.subscription), fontSize: 12, fontWeight: 700 }}>{statusLabel(selectedBuilding.subscription)}</span>
                  </div>
                </div>

                <div style={{ display: "flex", gap: 10, marginBottom: 10 }}>
                  <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "14px", border: `1px solid ${COLORS.border}` }}>
                    <p style={{ color: COLORS.accent, fontSize: 22, fontWeight: 900, margin: "0 0 4px" }}>{selectedBuilding.inviteCodesRedeemed}/{selectedBuilding.units}</p>
                    <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Adoption</p>
                  </div>
                  <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "14px", border: `1px solid ${COLORS.border}` }}>
                    <p style={{ color: COLORS.success, fontSize: 22, fontWeight: 900, margin: "0 0 4px" }}>{selectedBuilding.activeUsersThisMonth}</p>
                    <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Active</p>
                  </div>
                </div>

                {/* Live presence breakdown */}
                {(() => {
                  const buildingIdStr = String(selectedBuilding.id);
                  const liveResidents = getLiveCount(buildingIdStr, 'resident');
                  const liveManager = getLiveCount(buildingIdStr, 'manager');
                  const totalLive = liveResidents + liveManager;
                  return (
                    <div style={{ background: totalLive > 0 ? `${COLORS.success}12` : COLORS.card, borderRadius: 16, padding: "14px 16px", border: `1px solid ${totalLive > 0 ? COLORS.success + "40" : COLORS.border}`, marginBottom: 10 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: totalLive > 0 ? 10 : 0 }}>
                        <div style={{ width: 8, height: 8, borderRadius: 99, background: totalLive > 0 ? COLORS.success : COLORS.border, boxShadow: totalLive > 0 ? `0 0 8px ${COLORS.success}` : "none" }} />
                        <p style={{ color: totalLive > 0 ? COLORS.success : COLORS.textSecondary, fontSize: 13, fontWeight: 700, margin: 0 }}>
                          {totalLive > 0 ? `${totalLive} in app right now` : "Nobody in app right now"}
                        </p>
                      </div>
                      {totalLive > 0 && (
                        <div style={{ display: "flex", gap: 16, paddingLeft: 16 }}>
                          <div>
                            <p style={{ color: COLORS.white, fontSize: 18, fontWeight: 800, margin: "0 0 2px" }}>{liveResidents}</p>
                            <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>Residents</p>
                          </div>
                          <div>
                            <p style={{ color: COLORS.white, fontSize: 18, fontWeight: 800, margin: "0 0 2px" }}>{liveManager}</p>
                            <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>Manager {liveManager > 1 ? "⚠️" : ""}</p>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })()}
                <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
                  <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "14px", border: `1px solid ${COLORS.border}` }}>
                    <p style={{ color: "#FF6B35", fontSize: 22, fontWeight: 900, margin: "0 0 4px" }}>{(selectedBuilding.totalWorkoutsThisMonth || 0).toLocaleString()}</p>
                    <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Workouts</p>
                  </div>
                  <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "14px", border: `1px solid ${COLORS.border}` }}>
                    <p style={{ color: "#A78BFA", fontSize: 22, fontWeight: 900, margin: "0 0 4px" }}>{engagementScore(selectedBuilding)}%</p>
                    <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>Engagement</p>
                  </div>
                </div>

                <div style={{ background: COLORS.card, borderRadius: 18, padding: "18px 20px", border: `1px solid ${COLORS.border}`, marginBottom: 16 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.2, textTransform: "uppercase", margin: "0 0 14px" }}>Subscription</p>
                  {[
                    { label: "Tier", value: selectedBuilding.tier },
                    { label: "Renewal", value: selectedBuilding.renewalDate },
                    { label: "Units", value: `${selectedBuilding.units} residents` },
                    { label: "Gym Equipment", value: selectedBuilding.equipmentProfile || "Not configured" },
                    { label: "Last Activity", value: selectedBuilding.weeksSinceLastActivity === 0 ? "This week" : `${selectedBuilding.weeksSinceLastActivity} weeks ago` },
                  ].map((row, i, arr) => (
                    <div key={i} style={{ display: "flex", justifyContent: "space-between", paddingBottom: i < arr.length - 1 ? 10 : 0, marginBottom: i < arr.length - 1 ? 10 : 0, borderBottom: i < arr.length - 1 ? `1px solid ${COLORS.border}` : "none" }}>
                      <span style={{ color: COLORS.textSecondary, fontSize: 13 }}>{row.label}</span>
                      <span style={{ color: COLORS.white, fontSize: 13, fontWeight: 600 }}>{row.value}</span>
                    </div>
                  ))}
                </div>

                {selectedBuilding.subscription === "at_risk" && (
                  <div style={{ background: "#F59E0B15", border: "1px solid #F59E0B40", borderRadius: 14, padding: "14px 16px" }}>
                    <p style={{ color: "#F59E0B", fontSize: 13, fontWeight: 600, margin: "0 0 4px" }}>Churn Risk Detected</p>
                    <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, lineHeight: 1.5 }}>Engagement has dropped significantly. Consider reaching out to the building manager to offer support or a check-in.</p>
                  </div>
                )}

                {/* Contract Management */}
                <div style={{ background: COLORS.card, borderRadius: 16, padding: "16px", border: `1px solid ${COLORS.border}`, marginTop: 10 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.2, textTransform: "uppercase", margin: "0 0 12px" }}>Contract</p>

                  {/* Renewal date setter */}
                  <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 6px" }}>Renewal Date</p>
                  <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
                    <input
                      type="date"
                      defaultValue={selectedBuilding.renewalDate || ""}
                      id={`renewal-${selectedBuilding.id}`}
                      style={{ flex: 1, padding: "10px 12px", borderRadius: 10, border: `1px solid ${COLORS.border}`, background: COLORS.background, color: COLORS.white, fontSize: 13, fontFamily: "'Inter', sans-serif", outline: "none" }}
                    />
                    <button
                      onClick={async () => {
                        const input = document.getElementById(`renewal-${selectedBuilding.id}`) as HTMLInputElement;
                        const val = input?.value;
                        if (!val) return;
                        await setDoc(doc(db, "buildings", String(selectedBuilding.id)), { renewalDate: val }, { merge: true });
                        setSelectedBuilding((prev: any) => ({ ...prev, renewalDate: val }));
                        setAllBuildings(prev => prev.map(b => b.id === selectedBuilding.id ? { ...b, renewalDate: val } : b));
                        alert("Renewal date saved.");
                      }}
                      style={{ padding: "10px 16px", borderRadius: 10, border: "none", background: COLORS.primary, color: COLORS.white, fontSize: 13, fontWeight: 700, cursor: "pointer" }}
                    >
                      Save
                    </button>
                  </div>

                  {/* Stripe Invoice */}
                  <div style={{ marginBottom: 16 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Billing</p>
                      {selectedBuilding.stripeCustomerId ? (
                        <span style={{ color: COLORS.success, fontSize: 12, fontWeight: 600 }}>✓ Stripe customer linked</span>
                      ) : (
                        <button
                          onClick={async () => {
                            if (!selectedBuilding.managerEmail) { alert("No manager email on this building."); return; }
                            try {
                              const res = await fetch("https://us-central1-amenityfit-31276.cloudfunctions.net/createStripeCustomer", {
                                method: "POST",
                                headers: { "Content-Type": "application/json" },
                                body: JSON.stringify({
                                  buildingId: String(selectedBuilding.id),
                                  buildingName: selectedBuilding.name,
                                  managerEmail: selectedBuilding.managerEmail,
                                  units: selectedBuilding.units || 0,
                                  secret: "amenityfit-activation-2026",
                                }),
                              });
                              const data = await res.json();
                              if (data.success) {
                                setSelectedBuilding((prev: any) => ({ ...prev, stripeCustomerId: data.customerId }));
                                alert(`✅ Stripe customer created. Invoice sent to ${selectedBuilding.managerEmail}`);
                              } else {
                                alert("Stripe error: " + (data.error || "Unknown error"));
                              }
                            } catch (e) {
                              alert("Failed to create Stripe customer. Check console.");
                            }
                          }}
                          style={{ background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, border: "none", borderRadius: 8, padding: "6px 12px", color: COLORS.white, fontSize: 12, fontWeight: 600, cursor: "pointer" }}
                        >
                          Create Stripe Invoice
                        </button>
                      )}
                    </div>
                  </div>

                  {/* Invite Codes */}
                  <div style={{ marginBottom: 16 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Invite Codes</p>
                      <button
                        onClick={async () => {
                          if (showBuildingCodes) { setShowBuildingCodes(false); return; }
                          const snap = await getDocs(query(collection(db, "inviteCodes"), where("buildingId", "==", String(selectedBuilding.id))));
                          const codes = snap.docs.map(d => ({ id: d.id, ...d.data() })).sort((a: any, b: any) => parseInt(a.unitNumber) - parseInt(b.unitNumber));
                          setSelectedBuildingCodes(codes);
                          setShowBuildingCodes(true);
                        }}
                        style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 8, padding: "6px 12px", color: COLORS.accent, fontSize: 12, fontWeight: 600, cursor: "pointer" }}
                      >
                        {showBuildingCodes ? "Hide Codes" : `View Codes (${selectedBuilding.inviteCodesGenerated || 0})`}
                      </button>
                    </div>
                    {showBuildingCodes && selectedBuildingCodes.length > 0 && (
                      <div style={{ background: COLORS.background, borderRadius: 12, border: `1px solid ${COLORS.border}`, overflow: "hidden", maxHeight: 300, overflowY: "auto" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", padding: "8px 14px", borderBottom: `1px solid ${COLORS.border}` }}>
                          <span style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1 }}>UNIT</span>
                          <span style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1 }}>CODE</span>
                          <span style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1 }}>STATUS</span>
                        </div>
                        {selectedBuildingCodes.map((c: any) => (
                          <div key={c.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 14px", borderBottom: `1px solid ${COLORS.border}` }}>
                            <span style={{ color: COLORS.textSecondary, fontSize: 13, width: 40 }}>#{c.unitNumber}</span>
                            <span style={{ color: COLORS.white, fontSize: 13, fontWeight: 700, fontFamily: "monospace", letterSpacing: 1.5 }}>{c.code}</span>
                            <span style={{ fontSize: 11, fontWeight: 700, color: (c.usedBy?.length > 0) ? COLORS.success : COLORS.textSecondary }}>{(c.usedBy?.length > 0) ? "Used" : c.status === "active" ? "Active" : "Inactive"}</span>
                          </div>
                        ))}
                      </div>
                    )}
                    {showBuildingCodes && selectedBuildingCodes.length === 0 && (
                      <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>No codes found for this building.</p>
                    )}
                  </div>

                  {/* Cancel contract */}
                  {selectedBuilding.subscription !== "churned" && (
                    <button
                      onClick={() => {
                        if (!window.confirm(`Cancel contract for ${selectedBuilding.name}? This marks them as churned and cannot be undone without manual Firestore edit.`)) return;
                        const secondCheck = window.confirm("Are you absolutely sure? This will remove them from active billing.");
                        if (!secondCheck) return;
                        const cancellationDate = new Date(); cancellationDate.setDate(cancellationDate.getDate() + 30); const cancellationDateStr = cancellationDate.toISOString().split("T")[0];
                        setDoc(doc(db, "buildings", String(selectedBuilding.id)), { subscription: "churned", renewalDate: "", cancellationDate: cancellationDateStr }, { merge: true });
                        setSelectedBuilding((prev: any) => ({ ...prev, subscription: "churned", renewalDate: "", cancellationDate: cancellationDateStr }));
                        setAllBuildings(prev => prev.map(b => b.id === selectedBuilding.id ? { ...b, subscription: "churned", renewalDate: "", cancellationDate: cancellationDateStr } : b));
                      }}
                      style={{ width: "100%", padding: "12px", borderRadius: 10, border: "1px solid #FF4D4D40", background: "transparent", color: "#FF6B6B", fontSize: 13, fontWeight: 600, cursor: "pointer" }}
                    >
                      Cancel Contract
                    </button>
                  )}
                  {selectedBuilding.subscription === "churned" && (
                    <button
                      onClick={async () => {
                        if (!window.confirm(`Reactivate ${selectedBuilding.name}?`)) return;
                        await setDoc(doc(db, "buildings", String(selectedBuilding.id)), { subscription: "active" }, { merge: true });
                        setSelectedBuilding((prev: any) => ({ ...prev, subscription: "active" }));
                        setAllBuildings(prev => prev.map(b => b.id === selectedBuilding.id ? { ...b, subscription: "active" } : b));
                      }}
                      style={{ width: "100%", padding: "12px", borderRadius: 10, border: `1px solid ${COLORS.success}40`, background: "transparent", color: COLORS.success, fontSize: 13, fontWeight: 600, cursor: "pointer" }}
                    >
                      Reactivate Building
                    </button>
                  )}
                </div>
              </>
            ) : (
              <>
                <input
                  type="text"
                  placeholder="Search by name or city..."
                  value={buildingSearch}
                  onChange={e => setBuildingSearch(e.target.value)}
                  style={{ width: "100%", padding: "12px 16px", borderRadius: 12, border: `1.5px solid ${COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 14, fontFamily: "'Inter', sans-serif", outline: "none", boxSizing: "border-box" as const, marginBottom: 12 }}
                />
                <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" as const }}>
                  {(["all", "active", "at_risk", "churned"] as const).map(f => (
                    <button key={f} onClick={() => setStatusFilter(f)} style={{
                      padding: "6px 14px", borderRadius: 99, border: `1px solid ${statusFilter === f ? COLORS.accent : COLORS.border}`,
                      background: statusFilter === f ? `${COLORS.accent}20` : "transparent",
                      color: statusFilter === f ? COLORS.accent : COLORS.textSecondary,
                      fontSize: 12, fontWeight: 600, cursor: "pointer",
                    }}>
                      {f === "all" ? "All" : f === "at_risk" ? "At Risk" : f.charAt(0).toUpperCase() + f.slice(1)}
                    </button>
                  ))}
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>
                    {filteredBuildings.length} of {totalBuildings} Buildings
                  </p>
                  <button
                    onClick={() => setGroupByCompany(g => !g)}
                    style={{ background: groupByCompany ? `${COLORS.accent}20` : COLORS.card, border: `1px solid ${groupByCompany ? COLORS.accent : COLORS.border}`, borderRadius: 99, padding: "5px 14px", color: groupByCompany ? COLORS.accent : COLORS.textSecondary, fontSize: 12, fontWeight: 700, cursor: "pointer", letterSpacing: 0.5 }}
                  >
                    {groupByCompany ? "✓ By Company" : "Group by Company"}
                  </button>
                </div>

                {(() => {
                  const BuildingCard = ({ b }: { b: any }) => (
                    <div key={b.id} onClick={() => setSelectedBuilding(b)} style={{ background: COLORS.card, borderRadius: 18, padding: "16px 20px", border: `1px solid ${b.subscription === "at_risk" ? "#F59E0B40" : b.subscription === "churned" ? "#FF4D4D30" : COLORS.border}`, marginBottom: 12, cursor: "pointer" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                        <div>
                          <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: "0 0 2px" }}>{b.name}</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{b.location} · {b.tier}</p>
                        </div>
                        <div style={{ background: `${statusColor(b.subscription)}20`, borderRadius: 99, padding: "4px 12px" }}>
                          <span style={{ color: statusColor(b.subscription), fontSize: 11, fontWeight: 700 }}>{statusLabel(b.subscription)}</span>
                        </div>
                      </div>
                      <div style={{ display: "flex", gap: 16 }}>
                        <div>
                          <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{b.signedUp}/{b.units}</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>adoption</p>
                        </div>
                        <div>
                          <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{b.active}</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>active</p>
                        </div>
                        <div>
                          <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{(b.totalWorkoutsThisMonth || 0).toLocaleString()}</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>workouts</p>
                        </div>
                        {getLiveCount(String(b.id)) > 0 && (
                          <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                            <div style={{ width: 6, height: 6, borderRadius: 99, background: COLORS.success, boxShadow: `0 0 6px ${COLORS.success}` }} />
                            <div>
                              <p style={{ color: COLORS.success, fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{getLiveCount(String(b.id))}</p>
                              <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>live now</p>
                            </div>
                          </div>
                        )}
                        <div>
                          <p style={{ color: engagementScore(b) >= 50 ? COLORS.success : engagementScore(b) >= 30 ? "#F59E0B" : "#FF4D4D", fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{engagementScore(b)}%</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 11, margin: 0 }}>score</p>
                        </div>
                      </div>
                    </div>
                  );

                  if (!groupByCompany) {
                    return (
                      <>
                        {filteredBuildings.map((b: any) => <BuildingCard key={b.id} b={b} />)}
                        {filteredBuildings.length === 0 && (
                          <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "40px 0", margin: 0 }}>No buildings match your search or filter.</p>
                        )}
                      </>
                    );
                  }

                  // Group by companyId — buildings without one go to "Independent"
                  const groups: Record<string, any[]> = {};
                  filteredBuildings.forEach((b: any) => {
                    const key = b.companyName || b.companyId || "Independent";
                    if (!groups[key]) groups[key] = [];
                    groups[key].push(b);
                  });

                  // Sort: named companies first (alphabetical), Independent last
                  const sortedKeys = Object.keys(groups).sort((a, b) => {
                    if (a === "Independent") return 1;
                    if (b === "Independent") return -1;
                    return a.localeCompare(b);
                  });

                  return (
                    <>
                      {sortedKeys.map(company => {
                        const buildings = groups[company];
                        const allActive = buildings.every((b: any) => b.subscription === "active");
                        const anyChurned = buildings.some((b: any) => b.subscription === "churned");
                        const anyAtRisk = buildings.some((b: any) => b.subscription === "at_risk");
                        const dotColor = anyChurned ? "#FF4D4D" : anyAtRisk ? "#F59E0B" : COLORS.success;
                        const totalActiveResidents = buildings.reduce((a: number, b: any) => a + (b.activeUsersThisMonth || b.active || 0), 0);
                        return (
                          <div key={company} style={{ marginBottom: 20 }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, padding: "8px 12px", background: `${COLORS.primary}15`, borderRadius: 10, border: `1px solid ${COLORS.primary}25` }}>
                              <div style={{ width: 8, height: 8, borderRadius: "50%", background: dotColor, boxShadow: `0 0 6px ${dotColor}`, flexShrink: 0 }} />
                              <p style={{ color: COLORS.white, fontSize: 13, fontWeight: 800, margin: 0, flex: 1 }}>{company}</p>
                              <span style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600 }}>{buildings.length} {buildings.length === 1 ? "building" : "buildings"}</span>
                              <span style={{ color: COLORS.textSecondary, fontSize: 11 }}>·</span>
                              <span style={{ color: COLORS.accent, fontSize: 11, fontWeight: 600 }}>{totalActiveResidents} active</span>
                            </div>
                            {buildings.map((b: any) => <BuildingCard key={b.id} b={b} />)}
                          </div>
                        );
                      })}
                      {filteredBuildings.length === 0 && (
                        <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "40px 0", margin: 0 }}>No buildings match your search or filter.</p>
                      )}
                    </>
                  );
                })()}
              </>
            )}
          </>
        )}

        {/* ── CONTENT & PROGRAMS ── */}
        {activeTab === "content" && (
          <>
            <div style={{ background: `${COLORS.primary}15`, border: `1px solid ${COLORS.primary}30`, borderRadius: 14, padding: "14px 16px", marginBottom: 24 }}>
              <p style={{ color: COLORS.accent, fontSize: 13, fontWeight: 600, margin: "0 0 4px" }}>Global Content Management</p>
              <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, lineHeight: 1.5 }}>Push program updates, new exercises, or content changes to all buildings simultaneously. Changes go live across all resident experiences when deployed.</p>
            </div>

            {[
              { title: "Workout Programs", desc: "30-day structured programs across Beginner, Intermediate, Advanced, and Senior levels with Month 4+ evolved variants", status: "Current", action: "Update Programs" },
              { title: "Exercise Library", desc: "748 exercises with video, coaching cues, equipment tags, injury flags, and progression logic", status: "Current", action: "Edit Library" },
              { title: "Power 24 Nutrition", desc: "24 smoothie recipes with images, macros, and trainer tips", status: "Current", action: "Edit Recipes" },
              { title: "Motivational Content", desc: "53 Senz quotes + 40 generated variants cycling through session completions", status: "Current", action: "Edit Quotes" },
              { title: "Fitness Assistant Context", desc: "System prompt and coaching context powering the assistant", status: "Current", action: "Edit Prompt" },
            ].map((item, i) => (
              <div key={i} style={{ background: COLORS.card, borderRadius: 18, padding: "18px 20px", border: `1px solid ${COLORS.border}`, marginBottom: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 6 }}>
                  <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: 0 }}>{item.title}</p>
                  <div style={{ background: `${COLORS.success}20`, borderRadius: 99, padding: "3px 10px" }}>
                    <span style={{ color: COLORS.success, fontSize: 11, fontWeight: 700 }}>{item.status}</span>
                  </div>
                </div>
                <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 14px", lineHeight: 1.5 }}>{item.desc}</p>
                <button style={{ background: `${COLORS.primary}20`, border: `1px solid ${COLORS.primary}40`, borderRadius: 10, padding: "8px 16px", color: COLORS.accent, fontSize: 13, fontWeight: 600, cursor: "pointer" }}>
                  {item.action}
                </button>
              </div>
            ))}
          </>
        )}

        {/* ── ACTIVATION QUEUE ── */}
        {activeTab === "queue" && (() => {
          const pendingCount = queueSubmissions.filter(s => s.status === "pending").length;
          const filteredQueue = queueSubmissions.filter(s => {
            if (queueFilter === "pending") return s.status === "pending";
            if (queueFilter === "reviewed") return s.status === "activated" || s.status === "rejected";
            return true;
          });

          const updateStatus = async (id: string, status: "activated" | "rejected" | "pending") => {
            const ok = await updateSubmissionStatus(id, status as any);
            if (ok) setQueueSubmissions(prev => prev.map(s => s.id === id ? { ...s, status } : s));
          };

          return (
            <>
              {/* Header */}
              <div style={{ background: `${COLORS.primary}15`, border: `1px solid ${COLORS.primary}30`, borderRadius: 14, padding: "14px 16px", marginBottom: 20 }}>
                <p style={{ color: COLORS.accent, fontSize: 13, fontWeight: 600, margin: "0 0 4px" }}>Building Activation Queue</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, lineHeight: 1.5 }}>
                  Intake forms from amenityfit.app land here. Review, then manually set up their Firebase account and send invite codes.
                </p>
              </div>

              {/* Load button — first visit */}
              {!queueLoaded && (
                <button
                  onClick={async () => {
                    setQueueLoading(true);
                    const results = await fetchBuildingSubmissions();
                    setQueueSubmissions(results);
                    setQueueLoaded(true);
                    setQueueLoading(false);
                  }}
                  style={{ width: "100%", padding: "16px", borderRadius: 16, border: "none", background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, color: COLORS.white, fontSize: 15, fontWeight: 700, cursor: "pointer", marginBottom: 20 }}
                >
                  {queueLoading ? "Loading..." : "Load Queue"}
                </button>
              )}

              {/* Filter tabs — shown after load */}
              {queueLoaded && (
                <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
                  {([
                    { id: "pending", label: `Pending${pendingCount > 0 ? ` (${pendingCount})` : ""}` },
                    { id: "reviewed", label: "Reviewed" },
                    { id: "all", label: "All" },
                  ] as const).map(f => (
                    <button
                      key={f.id}
                      onClick={() => setQueueFilter(f.id)}
                      style={{
                        padding: "8px 16px", borderRadius: 99, fontSize: 13, fontWeight: 600, cursor: "pointer",
                        border: `1.5px solid ${queueFilter === f.id ? COLORS.accent : COLORS.border}`,
                        background: queueFilter === f.id ? `${COLORS.accent}18` : "transparent",
                        color: queueFilter === f.id ? COLORS.accent : COLORS.textSecondary,
                      }}
                    >
                      {f.label}
                    </button>
                  ))}
                  {/* Refresh */}
                  <button
                    onClick={async () => {
                      setQueueLoading(true);
                      const results = await fetchBuildingSubmissions();
                      setQueueSubmissions(results);
                      setQueueLoading(false);
                    }}
                    style={{ marginLeft: "auto", padding: "8px 14px", borderRadius: 99, fontSize: 13, fontWeight: 600, cursor: "pointer", border: `1px solid ${COLORS.border}`, background: "transparent", color: COLORS.textSecondary }}
                  >
                    {queueLoading ? "..." : "↻"}
                  </button>
                  
                </div>
              )}

              {/* Empty state */}
              {queueLoaded && filteredQueue.length === 0 && (
                <div style={{ background: COLORS.card, borderRadius: 16, padding: "32px 24px", border: `1px solid ${COLORS.border}`, textAlign: "center" }}>
                  <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: "0 0 6px" }}>
                    {queueFilter === "pending" ? "No pending submissions" : queueFilter === "reviewed" ? "Nothing reviewed yet" : "Queue is empty"}
                  </p>
                  <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0 }}>
                    {queueFilter === "pending" ? "New building requests from amenityfit.app will appear here." : "Activated and rejected buildings will show here."}
                  </p>
                </div>
              )}

              {/* Submission cards */}
              {queueLoaded && filteredQueue.map((sub: any, i: number) => {
                const submittedDate = sub.submittedAt?.toDate ? sub.submittedAt.toDate().toLocaleDateString() : "—";
                const reviewedDate = sub.reviewedAt?.toDate ? sub.reviewedAt.toDate().toLocaleDateString() : null;
                const isPending = sub.status === "pending";
                const isRejected = sub.status === "rejected";
                const isActivated = sub.status === "activated";
                const statusColor = isActivated ? COLORS.success : isRejected ? "#FF4D4D" : "#F59E0B";
                const cardOpacity = isRejected ? 0.65 : 1;

                return (
                  <div key={sub.id || i} style={{ background: COLORS.card, borderRadius: 16, padding: "18px", border: `1px solid ${isRejected ? "#FF4D4D30" : COLORS.border}`, marginBottom: 12, opacity: cardOpacity }}>

                    {/* Building header */}
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                      <div style={{ flex: 1, marginRight: 12 }}>
                        <p style={{ color: COLORS.white, fontSize: 15, fontWeight: 700, margin: "0 0 2px" }}>{sub.buildingName || "Unnamed Building"}</p>
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{sub.location || "No address"} · {sub.units || "?"} units</p>
                      </div>
                      <div style={{ background: `${statusColor}20`, borderRadius: 99, padding: "3px 10px", flexShrink: 0 }}>
                        <span style={{ color: statusColor, fontSize: 11, fontWeight: 700, textTransform: "uppercase" as const }}>{sub.status}</span>
                      </div>
                    </div>

                    {/* Details */}
                    <div style={{ marginBottom: 14 }}>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 3px" }}>
                        Contact: <span style={{ color: COLORS.white }}>{sub.contactName || "—"}</span>
                      </p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 3px" }}>
                        Email: <span style={{ color: COLORS.white }}>{sub.managerEmail || "—"}</span>
                      </p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 3px" }}>
                        Phone: <span style={{ color: COLORS.white }}>{sub.phone || "—"}</span>
                      </p>
                      <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 3px" }}>
                        Submitted: <span style={{ color: COLORS.white }}>{submittedDate}</span>
                        {reviewedDate && <span style={{ color: COLORS.textSecondary }}> · Reviewed: {reviewedDate}</span>}
                      </p>
                      {sub.equipment && sub.equipment.length > 0 && (
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "6px 0 0", lineHeight: 1.6 }}>
                          Equipment ({sub.equipment.length}): <span style={{ color: COLORS.white }}>{sub.equipment.join(", ")}</span>
                        </p>
                      )}
                    </div>

                    {/* Pending actions */}
                    {isPending && (
                      <div style={{ display: "flex", gap: 10 }}>
                        <button
                          onClick={async () => {
                            if (!sub.managerEmail) { alert("No manager email on this submission."); return; }
                            const activating = activatingId === sub.id;
                            if (activating) return;
                            setActivatingId(sub.id);

                            try {
                              // 1. Generate buildingId slug from building name
                              const slug = (sub.buildingName || "building")
                                .toLowerCase()
                                .replace(/[^a-z0-9]+/g, "-")
                                .replace(/^-|-$/g, "")
                                + "-" + Math.random().toString(36).slice(2, 6);

                              // 2. Generate temp password
                              const tempPassword = "AmenityFit" + Math.floor(1000 + Math.random() * 9000) + "!";

                              // 3. Create Firebase Auth account via REST API
                              const userCredential = await createUserWithEmailAndPassword(auth, sub.managerEmail, tempPassword);
                              const uid = userCredential.user.uid;

                              // 4. Create /users/{uid} doc
                              await setDoc(doc(db, "users", uid), {
                                role: "manager",
                                buildingId: slug,
                                email: sub.managerEmail,
                                name: sub.contactName || "",
                                passwordChangeRequired: true,
                                createdAt: serverTimestamp(),
                              });

                              // 5. Create /buildings/{slug} doc
                              await setDoc(doc(db, "buildings", slug), {
                                name: sub.buildingName || "",
                                programName: sub.buildingName || "",
                                location: sub.location || "",
                                units: sub.units || 0,
                                managerEmail: sub.managerEmail,
                                equipment: sub.equipment || [],
                                equipmentProfile: sub.equipmentProfile || "",
                                subscription: "active",
                                subscriptionTier: "Standard",
                                tier: "Standard",
                                renewalDate: "",
                                subscriptionRenewal: "",
                                inviteCodesGenerated: sub.units || 0,
                                inviteCodesRedeemed: 0,
                                activeUsersThisMonth: 0,
                                totalWorkoutsThisMonth: 0,
                                avgSessionsPerUserPerWeek: 0,
                                fitnessAssistantQuestionsThisMonth: 0,
                                weeksSinceLastActivity: 0,
                                popularTimes: [],
                                programWeekBreakdown: [],
                                retentionCurve: [],
                                milestones: [],
                                createdAt: serverTimestamp(),
                              });

                              // 6. Generate invite codes — sequential with collision check
                              const units = sub.units || 0;
                              const CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
                              const genCode = () => {
                                let c = "AF-";
                                for (let i = 0; i < 6; i++) c += CHARS[Math.floor(Math.random() * CHARS.length)];
                                return c;
                              };
                              const generatedCodes: {code: string, unit: string}[] = [];
                              const usedCodes = new Set<string>(
                                (await getDocs(collection(db, "inviteCodes"))).docs.map(d => d.id)
                              );
                              for (let i = 1; i <= units; i++) {
                                let code = genCode();
                                let attempts = 0;
                                while (usedCodes.has(code) && attempts < 20) {
                                  code = genCode();
                                  attempts++;
                                }
                                usedCodes.add(code);
                                await setDoc(doc(db, "inviteCodes", code), {
                                  code,
                                  buildingId: slug,
                                  buildingName: sub.buildingName || "",
                                  unitNumber: String(i),
                                  status: "active",
                                  createdAt: serverTimestamp(),
                                  usedBy: [],
                                });
                                generatedCodes.push({ code, unit: String(i) });
                              }

                              // 7. Update submission status
                              await updateStatus(sub.id, "activated");

                              // 8. Store activation record — no plain-text password in Firestore
                              await setDoc(doc(db, "buildingSubmissions", sub.id), {
                                activatedBuildingId: slug,
                                activatedUid: uid,
                                activatedAt: serverTimestamp(),
                              }, { merge: true });

                              // 8b. Add managerUid to building doc for report lookups
                              await setDoc(doc(db, "buildings", slug), { managerUid: uid }, { merge: true });

                              // 8c. Send activation email via Resend Cloud Function
                              const codeListHtml = generatedCodes.map(c =>
                                `<tr><td style="padding:8px 16px;font-size:13px;color:#555;border-bottom:1px solid #f0f0f0;">Unit ${c.unit}</td><td style="padding:8px 16px;font-size:14px;font-weight:700;color:#111;letter-spacing:2px;border-bottom:1px solid #f0f0f0;">${c.code}</td></tr>`
                              ).join("");

                              const activationEmailHtml = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="margin:0;padding:0;background:#f5f5f7;font-family:-apple-system,'Helvetica Neue',Arial,sans-serif;">
<div style="max-width:620px;margin:32px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,0.10);">
  <div style="background:linear-gradient(135deg,#1E5FBE,#6C63FF);padding:36px 40px 32px;">
    <p style="color:rgba(255,255,255,0.7);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;margin:0 0 10px;">AmenityFit Setup</p>
    <h1 style="color:#fff;font-size:26px;font-weight:900;margin:0 0 6px;letter-spacing:-0.5px;">${sub.buildingName} is Live</h1>
    <p style="color:rgba(255,255,255,0.75);font-size:14px;margin:0;">${sub.location || ""}</p>
  </div>
  <div style="padding:32px 40px;">
    <p style="font-size:15px;color:#333;line-height:1.6;margin:0 0 28px;">Hi ${sub.contactName || "there"},<br><br>Your building is activated and ready. Everything you need to get your residents started is below.</p>

    <p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Manager Login</p>
    <div style="border:1px solid #eee;border-radius:12px;overflow:hidden;margin-bottom:28px;">
      <table style="width:100%;border-collapse:collapse;">
        <tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Login URL</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#1E5FBE;border-bottom:1px solid #eee;"><a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> then tap "Building Manager"</td></tr>
        <tr><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Email</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#111;border-bottom:1px solid #eee;">${sub.managerEmail}</td></tr>
        <tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;">Temporary Password</td><td style="padding:13px 16px;font-size:15px;font-weight:900;color:#111;letter-spacing:2px;">${tempPassword}</td></tr>
      </table>
    </div>
    <p style="font-size:12px;color:#aaa;margin:-20px 0 28px;padding:0 4px;">Change your password after your first login.</p>

    <p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Resident Invite Codes (${generatedCodes.length} codes)</p>
    <p style="font-size:13px;color:#555;margin:0 0 12px;line-height:1.6;">One code per unit. Share the code with the resident in that unit. Multiple residents in the same unit can each create their own profile using the same code.</p>
    <div style="border:1px solid #eee;border-radius:12px;overflow:hidden;margin-bottom:28px;">
      <table style="width:100%;border-collapse:collapse;">${codeListHtml}</table>
    </div>

    <p style="font-size:13px;color:#555;line-height:1.6;margin:0 0 28px;">Your residents can download the AmenityFit app at <a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> and sign up using their invite code.</p>

    <p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Your Manager Dashboard</p>
    <div style="background:#f5f5f7;border-radius:12px;padding:16px 20px;margin-bottom:28px;">
      <p style="font-size:13px;color:#333;margin:0 0 10px;line-height:1.6;">You have access to a building manager portal where you can track resident activity, workout completions, adoption rates, and monthly reports.</p>
      <p style="font-size:13px;color:#333;margin:0;line-height:1.6;">Log in at <a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> using your credentials above, then tap <strong>Building Manager</strong> on the welcome screen.</p>
    </div>

    <div style="background:#f5f5f7;border-radius:12px;padding:16px 20px;">
      <p style="font-size:13px;color:#333;margin:0;">Questions? Contact <a href="mailto:support@fitmakesenz.com" style="color:#1E5FBE;">support@fitmakesenz.com</a></p>
    </div>
  </div>
  <div style="background:#fafafa;border-top:1px solid #eee;padding:20px 40px;">
    <p style="font-size:11px;color:#aaa;margin:0;">Senz · AmenityFit · <a href="https://amenityfit.app" style="color:#aaa;">amenityfit.app</a></p>
  </div>
</div>
</body></html>`;

                              try {
                                await fetch("https://us-central1-amenityfit-31276.cloudfunctions.net/sendActivationEmail", {
                                  method: "POST",
                                  headers: { "Content-Type": "application/json" },
                                  body: JSON.stringify({
                                    to: sub.managerEmail,
                                    subject: `Your AmenityFit Dashboard is Ready - ${sub.buildingName}`,
                                    html: activationEmailHtml,
                                    secret: "amenityfit-activation-2026",
                                  }),
                                });
                              } catch (emailErr) {
                                console.error("Activation email failed:", emailErr);
                              }

                              setActivationResult({ slug, uid, tempPassword, email: sub.managerEmail, units });

                              // Reload queue to get updated submission with credentials
                              const updated = await fetchBuildingSubmissions();
                              setQueueSubmissions(updated);

                            } catch (e) {
                              console.error("Activation error:", e);
                              alert("Activation failed. Check console for details.");
                            }
                            setActivatingId(null);
                          }}
                          style={{ flex: 1, padding: "13px", borderRadius: 12, border: "none", background: activatingId === sub.id ? COLORS.border : `linear-gradient(135deg, ${COLORS.success}, #1a9e4a)`, color: activatingId === sub.id ? COLORS.textSecondary : COLORS.white, fontSize: 13, fontWeight: 700, cursor: activatingId === sub.id ? "not-allowed" : "pointer" }}
                        >
                          {activatingId === sub.id ? "Activating..." : "✓ Activate"}
                        </button>
                        <button
                          onClick={() => updateStatus(sub.id, "rejected")}
                          style={{ flex: 1, padding: "13px", borderRadius: 12, border: `1px solid #FF4D4D40`, background: "transparent", color: "#FF6B6B", fontSize: 13, fontWeight: 600, cursor: "pointer" }}
                        >
                          Reject
                        </button>
                      </div>
                    )}

                    {/* Rejected — show undo */}
                    {isRejected && (
                      <button
                        onClick={() => updateStatus(sub.id, "pending")}
                        style={{ width: "100%", padding: "12px", borderRadius: 12, border: `1px solid ${COLORS.border}`, background: "transparent", color: COLORS.textSecondary, fontSize: 13, fontWeight: 600, cursor: "pointer" }}
                      >
                        ↩ Undo Rejection — Move Back to Pending
                      </button>
                    )}

                    {/* Activated — show credentials */}
                    {isActivated && (
                      <div style={{ background: `${COLORS.success}10`, borderRadius: 10, padding: "12px 14px", border: `1px solid ${COLORS.success}30`, marginTop: 4 }}>
                        <p style={{ color: COLORS.success, fontSize: 12, fontWeight: 700, margin: "0 0 8px" }}>
                          ✓ Building activated — send these credentials to the manager:
                        </p>
                        {sub.activatedBuildingId && (
                          <>
                            <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 4px" }}>
                              Email: <span style={{ color: COLORS.white, fontWeight: 600 }}>{sub.managerEmail}</span>
                            </p>
                            <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 4px" }}>
                              Temp Password: <span style={{ color: COLORS.white, fontWeight: 600 }}>{activationResult?.email === sub.managerEmail ? activationResult.tempPassword : "••••••••• (check email)"}</span>
                            </p>
                            <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 4px" }}>
                              Building ID: <span style={{ color: COLORS.white, fontWeight: 600 }}>{sub.activatedBuildingId}</span>
                            </p>
                            <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 8px" }}>
                              Invite Codes: <span style={{ color: COLORS.white, fontWeight: 600 }}>{activationResult?.email === sub.managerEmail ? activationResult.units : sub.inviteCodesGenerated || sub.units} codes generated</span>
                            </p>
                            <button
                              onClick={() => {
                                const text = `Welcome to AmenityFit!\n\nYour building dashboard is ready.\n\nLogin: ${sub.managerEmail}\nTemp Password: ${sub.tempPassword}\n\nSign in at: https://f6lmn8.csb.app\nTap "Building Manager" on the welcome screen.\n\nYour resident invite codes are attached to this email. Each unit has its own unique code in AF-XXXXXX format — just share the code with the resident moving into that unit. Multiple residents in the same unit can each create their own profile using the same code.\n\nWelcome aboard,\nAsenso — AmenityFit`;
                                navigator.clipboard.writeText(text).catch(() => {});
                                alert("Welcome message copied to clipboard!");
                              }}
                              style={{ width: "100%", padding: "10px", borderRadius: 8, border: `1px solid ${COLORS.success}40`, background: "transparent", color: COLORS.success, fontSize: 12, fontWeight: 700, cursor: "pointer" }}
                            >
                              Copy Welcome Message
                            </button>
                            <button
                              onClick={async () => {
                                const codes = await fetchBuildingCodes(sub.activatedBuildingId);
                                if (!codes.length) { alert("No codes found."); return; }
                                const list = codes.map(c => `Unit ${c.unitNumber}: ${c.id}`).join("\n");
                                const full = `AMENITYFIT INVITE CODES\n${sub.buildingName}\n${sub.location}\n\n${list}\n\nEach code is used once at signup. Share one code per unit.\n\nQuestions? Contact support@fitmakesenz.com`;
                                navigator.clipboard.writeText(full).catch(() => {});
                                alert(`${codes.length} codes copied to clipboard!`);
                              }}
                              style={{ width: "100%", padding: "10px", borderRadius: 8, border: `1px solid ${COLORS.accent}40`, background: "transparent", color: COLORS.accent, fontSize: 12, fontWeight: 700, cursor: "pointer", marginTop: 8 }}
                            >
                              Copy Invite Codes List
                            </button>
                          </>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </>
          );
        })()}

        {/* ── REVENUE TAB ── */}
        {activeTab === "batch" && (
          <div>
            {!batchReviewMode && !batchComplete && (
              <>
                <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 16px" }}>Batch Building Activation</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 16px", lineHeight: 1.6 }}>Paste a CSV list of buildings. One building per line:<br /><span style={{ color: COLORS.accent, fontFamily: "monospace", fontSize: 12 }}>Building Name, Address, Units, Manager Email</span></p>

                <div style={{ marginBottom: 14 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.2, textTransform: "uppercase", margin: "0 0 8px" }}>Company Name</p>
                  <input
                    type="text"
                    placeholder="e.g. AKAM Associates"
                    value={batchCompanyName}
                    onChange={e => setBatchCompanyName(e.target.value)}
                    style={{ width: "100%", padding: "14px 16px", borderRadius: 14, border: `1.5px solid ${batchCompanyName ? COLORS.accent : COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 14, fontFamily: "'Inter', sans-serif", outline: "none", boxSizing: "border-box" as const }}
                  />
                </div>

                <div style={{ marginBottom: 14 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.2, textTransform: "uppercase", margin: "0 0 8px" }}>PM Executive Email <span style={{ color: COLORS.textSecondary, fontWeight: 400, textTransform: "none", letterSpacing: 0 }}>(receives monthly portfolio report)</span></p>
                  <input
                    type="email"
                    placeholder="e.g. jsmith@akamassociates.com"
                    value={batchPmEmail}
                    onChange={e => setBatchPmEmail(e.target.value)}
                    style={{ width: "100%", padding: "14px 16px", borderRadius: 14, border: `1.5px solid ${batchPmEmail ? COLORS.accent : COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 14, fontFamily: "'Inter', sans-serif", outline: "none", boxSizing: "border-box" as const }}
                  />
                </div>

                <div style={{ marginBottom: 16 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.2, textTransform: "uppercase", margin: "0 0 8px" }}>Building List</p>
                  <textarea
                    placeholder={"The Maverick, 123 Main St New York NY, 60, manager@themaverick.com\nThe Hudson, 456 Park Ave New York NY, 80, manager@thehudson.com"}
                    value={batchInput}
                    onChange={e => setBatchInput(e.target.value)}
                    rows={10}
                    style={{ width: "100%", padding: "14px 16px", borderRadius: 14, border: `1.5px solid ${batchInput ? COLORS.accent : COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 13, fontFamily: "monospace", outline: "none", boxSizing: "border-box" as const, resize: "vertical" as const, lineHeight: 1.6 }}
                  />
                </div>

                <button
                  onClick={() => {
                    const lines = batchInput.trim().split("\n").filter(l => l.trim());
                    const parsed = lines.map((line, i) => {
                      const parts = line.split(",").map(p => p.trim());
                      return {
                        buildingName: parts[0] || `Building ${i + 1}`,
                        location: parts[1] || "",
                        units: parseInt(parts[2]) || 0,
                        managerEmail: parts[3] || "",
                        valid: !!(parts[0] && parts[3] && parseInt(parts[2]) > 0),
                      };
                    });
                    setBatchParsed(parsed);
                    setBatchReviewMode(true);
                  }}
                  disabled={!batchInput.trim() || !batchCompanyName.trim()}
                  style={{ width: "100%", padding: "16px", borderRadius: 16, border: "none", background: batchInput.trim() && batchCompanyName.trim() ? `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})` : COLORS.border, color: batchInput.trim() && batchCompanyName.trim() ? COLORS.white : COLORS.textSecondary, fontSize: 15, fontWeight: 700, cursor: batchInput.trim() && batchCompanyName.trim() ? "pointer" : "not-allowed" }}
                >
                  Review Buildings →
                </button>
              </>
            )}

            {batchReviewMode && !batchActivating && !batchComplete && (
              <>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: 0 }}>Review — {batchParsed.length} Buildings · {batchCompanyName}</p>
                  <button onClick={() => setBatchReviewMode(false)} style={{ background: "none", border: "none", color: COLORS.textSecondary, fontSize: 13, cursor: "pointer" }}>← Edit</button>
                </div>

                {batchParsed.map((b, i) => (
                  <div key={i} style={{ background: COLORS.card, borderRadius: 14, padding: "14px 16px", marginBottom: 10, border: `1px solid ${b.valid ? COLORS.border : "#FF4D4D40"}` }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                      <div>
                        <p style={{ color: b.valid ? COLORS.white : "#FF6B6B", fontSize: 14, fontWeight: 700, margin: "0 0 4px" }}>{b.buildingName}</p>
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: "0 0 2px" }}>{b.location || "No address"}</p>
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{b.units} units · {b.managerEmail || <span style={{ color: "#FF6B6B" }}>No email</span>}</p>
                      </div>
                      <span style={{ fontSize: 11, fontWeight: 700, color: b.valid ? COLORS.success : "#FF6B6B", background: b.valid ? `${COLORS.success}20` : "#FF4D4D20", borderRadius: 99, padding: "3px 10px" }}>{b.valid ? "Ready" : "Invalid"}</span>
                    </div>
                  </div>
                ))}

                {batchParsed.some(b => !b.valid) && (
                  <div style={{ background: "#FF4D4D15", border: "1px solid #FF4D4D40", borderRadius: 12, padding: "12px 16px", marginBottom: 16 }}>
                    <p style={{ color: "#FF6B6B", fontSize: 13, margin: 0 }}>⚠️ Fix invalid rows before activating. Each row needs: name, address, unit count &gt; 0, manager email.</p>
                  </div>
                )}

                <button
                  onClick={async () => {
                    const valid = batchParsed.filter(b => b.valid);
                    if (valid.length === 0) return;
                    setBatchActivating(true);
                    setBatchProgress({ done: 0, total: valid.length, current: "", errors: [] });
                    const errors: string[] = [];
                    const companyId = batchCompanyName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");

                    for (let i = 0; i < valid.length; i++) {
                      const sub = valid[i];
                      setBatchProgress(p => ({ ...p, current: sub.buildingName }));
                      try {
                        const slug = sub.buildingName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") + "-" + Math.random().toString(36).slice(2, 6);
                        const tempPassword = "AmenityFit" + Math.floor(1000 + Math.random() * 9000) + "!";
                        const { createUserWithEmailAndPassword: createUser } = await import("firebase/auth");
                        const userCredential = await createUser(auth, sub.managerEmail, tempPassword);
                        const uid = userCredential.user.uid;

                        await setDoc(doc(db, "users", uid), {
                          role: "manager",
                          buildingId: slug,
                          email: sub.managerEmail,
                          name: "",
                          passwordChangeRequired: true,
                          companyId,
                          companyName: batchCompanyName,
                          createdAt: serverTimestamp(),
                        });

                        await setDoc(doc(db, "buildings", slug), {
                          name: sub.buildingName,
                          programName: sub.buildingName,
                          location: sub.location,
                          units: sub.units,
                          managerEmail: sub.managerEmail,
                          managerUid: uid,
                          companyId,
                          companyName: batchCompanyName,
                          equipment: [],
                          equipmentProfile: "",
                          subscription: "active",
                          subscriptionTier: "Standard",
                          tier: "Standard",
                          renewalDate: "",
                          inviteCodesGenerated: sub.units,
                          inviteCodesRedeemed: 0,
                          activeUsersThisMonth: 0,
                          totalWorkoutsThisMonth: 0,
                          avgSessionsPerUserPerWeek: 0,
                          fitnessAssistantQuestionsThisMonth: 0,
                          weeksSinceLastActivity: 0,
                          popularTimes: [],
                          programWeekBreakdown: [],
                          milestones: [],
                          createdAt: serverTimestamp(),
                        });

                        const CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
                        const genCode = () => { let c = "AF-"; for (let j = 0; j < 6; j++) c += CHARS[Math.floor(Math.random() * CHARS.length)]; return c; };
                        const usedCodes = new Set<string>((await getDocs(collection(db, "inviteCodes"))).docs.map(d => d.id));
                        const generatedCodes: {code: string, unit: string}[] = [];
                        for (let u = 1; u <= sub.units; u++) {
                          let code = genCode();
                          let attempts = 0;
                          while (usedCodes.has(code) && attempts < 20) { code = genCode(); attempts++; }
                          usedCodes.add(code);
                          await setDoc(doc(db, "inviteCodes", code), { code, buildingId: slug, buildingName: sub.buildingName, unitNumber: String(u), status: "active", createdAt: serverTimestamp(), usedBy: [] });
                          generatedCodes.push({ code, unit: String(u) });
                        }

                        // Update building doc with actual generated code count
                        await setDoc(doc(db, "buildings", slug), { inviteCodesGenerated: generatedCodes.length }, { merge: true });

                        const codeListHtml = generatedCodes.map(c => `<tr><td style="padding:8px 16px;font-size:13px;color:#555;border-bottom:1px solid #f0f0f0;">Unit ${c.unit}</td><td style="padding:8px 16px;font-size:14px;font-weight:700;color:#111;letter-spacing:2px;border-bottom:1px solid #f0f0f0;">${c.code}</td></tr>`).join("");
                        const activationEmailHtml = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f5f5f7;font-family:-apple-system,'Helvetica Neue',Arial,sans-serif;"><div style="max-width:620px;margin:32px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,0.10);"><div style="background:linear-gradient(135deg,#1E5FBE,#6C63FF);padding:36px 40px 32px;"><p style="color:rgba(255,255,255,0.7);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;margin:0 0 10px;">AmenityFit Setup</p><h1 style="color:#fff;font-size:26px;font-weight:900;margin:0 0 6px;letter-spacing:-0.5px;">${sub.buildingName} is Live</h1><p style="color:rgba(255,255,255,0.75);font-size:14px;margin:0;">${sub.location}</p></div><div style="padding:32px 40px;"><p style="font-size:15px;color:#333;line-height:1.6;margin:0 0 28px;">Hi there,<br><br>Your building is activated and ready. Everything you need to get your residents started is below.</p><p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Manager Login</p><div style="border:1px solid #eee;border-radius:12px;overflow:hidden;margin-bottom:28px;"><table style="width:100%;border-collapse:collapse;"><tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Login URL</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#1E5FBE;border-bottom:1px solid #eee;"><a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> → Building Manager</td></tr><tr><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Email</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#111;border-bottom:1px solid #eee;">${sub.managerEmail}</td></tr><tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;">Temporary Password</td><td style="padding:13px 16px;font-size:15px;font-weight:900;color:#111;letter-spacing:2px;">${tempPassword}</td></tr></table></div><p style="font-size:12px;color:#aaa;margin:-20px 0 28px;padding:0 4px;">Change your password after your first login.</p><p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Before Sharing Codes — Set Your Equipment</p><div style="background:#fff8e1;border-radius:12px;padding:16px 20px;margin-bottom:28px;border:1px solid #f59e0b30;"><p style="font-size:13px;color:#333;margin:0 0 8px;line-height:1.6;font-weight:700;">Important: Log into your manager dashboard and set your building's gym equipment first.</p><p style="font-size:13px;color:#555;margin:0;line-height:1.6;">This ensures every resident gets a program that matches what's actually available in your gym. Once set, you can share the codes below.</p></div><p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Your Manager Dashboard</p><div style="background:#f5f5f7;border-radius:12px;padding:16px 20px;margin-bottom:28px;"><p style="font-size:13px;color:#333;margin:0 0 8px;line-height:1.6;">Track resident activity, workout completions, adoption rates, and monthly reports.</p><p style="font-size:13px;color:#333;margin:0;line-height:1.6;">Log in at <a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> → tap <strong>Building Manager</strong>.</p></div><p style="font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#aaa;margin:0 0 12px;">Resident Invite Codes (${generatedCodes.length} codes)</p><p style="font-size:13px;color:#555;margin:0 0 12px;line-height:1.6;">One code per unit. Share with the resident in that unit. Multiple residents in the same unit can each create their own profile using the same code.</p><div style="border:1px solid #eee;border-radius:12px;overflow:hidden;margin-bottom:28px;"><table style="width:100%;border-collapse:collapse;">${codeListHtml}</table></div><p style="font-size:13px;color:#555;line-height:1.6;margin:0 0 28px;">Your residents can download the AmenityFit app at <a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> and sign up using their invite code.</p><div style="background:#f5f5f7;border-radius:12px;padding:16px 20px;"><p style="font-size:13px;color:#333;margin:0;">Questions? <a href="mailto:support@fitmakesenz.com" style="color:#1E5FBE;">support@fitmakesenz.com</a></p></div></div><div style="background:#fafafa;border-top:1px solid #eee;padding:20px 40px;"><p style="font-size:11px;color:#aaa;margin:0;">Senz · AmenityFit · amenityfit.app</p></div></div></body></html>`;

                        try {
                          await fetch("https://us-central1-amenityfit-31276.cloudfunctions.net/sendActivationEmail", {
                            method: "POST",
                            headers: { "Content-Type": "application/json" },
                            body: JSON.stringify({ to: sub.managerEmail, subject: `Your AmenityFit Dashboard is Ready - ${sub.buildingName}`, html: activationEmailHtml, secret: "amenityfit-activation-2026" }),
                          });
                        } catch (emailErr) {
                          console.error("Email failed for", sub.buildingName, emailErr);
                        }

                        setBatchProgress(p => ({ ...p, done: p.done + 1 }));
                      } catch (e: any) {
                        errors.push(`${sub.buildingName}: ${e.message || "Unknown error"}`);
                        setBatchProgress(p => ({ ...p, done: p.done + 1, errors: [...p.errors, `${sub.buildingName}: ${e.message || "error"}`] }));
                      }
                    }

                    // Create PM exec user doc if email provided
                    if (batchPmEmail.trim()) {
                      const companyId = batchCompanyName.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
                      try {
                        // Check if PM user already exists for this company
                        const existingPmSnap = await getDocs(query(collection(db, "users"), where("role", "==", "property_manager"), where("companyId", "==", companyId)));
                        if (existingPmSnap.empty) {
                          // Create Firebase Auth account for PM exec
                          const { createUserWithEmailAndPassword: createPmUser } = await import("firebase/auth");
                          const pmTempPassword = "AmenityFit" + Math.floor(1000 + Math.random() * 9000) + "!";
                          const pmCredential = await createPmUser(auth, batchPmEmail.trim(), pmTempPassword);
                          await setDoc(doc(db, "users", pmCredential.user.uid), {
                            role: "property_manager",
                            companyId,
                            companyName: batchCompanyName,
                            email: batchPmEmail.trim(),
                            createdAt: serverTimestamp(),
                          });
                          // Send PM exec their login credentials
                          const pmEmailHtml = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f5f5f7;font-family:-apple-system,'Helvetica Neue',Arial,sans-serif;"><div style="max-width:620px;margin:32px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(0,0,0,0.10);"><div style="background:linear-gradient(135deg,#1E5FBE,#6C63FF);padding:36px 40px 32px;"><p style="color:rgba(255,255,255,0.7);font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;margin:0 0 10px;">AmenityFit Portfolio Access</p><h1 style="color:#fff;font-size:26px;font-weight:900;margin:0 0 6px;">${batchCompanyName} is Live</h1><p style="color:rgba(255,255,255,0.75);font-size:14px;margin:0;">${valid.length} properties activated</p></div><div style="padding:32px 40px;"><p style="font-size:15px;color:#333;line-height:1.6;margin:0 0 28px;">Your portfolio dashboard is ready. Use the credentials below to access your property overview.</p><div style="border:1px solid #eee;border-radius:12px;overflow:hidden;margin-bottom:28px;"><table style="width:100%;border-collapse:collapse;"><tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Login URL</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#1E5FBE;border-bottom:1px solid #eee;"><a href="https://amenityfit.app" style="color:#1E5FBE;">amenityfit.app</a> → Building Manager</td></tr><tr><td style="padding:13px 16px;font-size:13px;color:#555;border-bottom:1px solid #eee;">Email</td><td style="padding:13px 16px;font-size:13px;font-weight:700;color:#111;border-bottom:1px solid #eee;">${batchPmEmail.trim()}</td></tr><tr style="background:#fafafa;"><td style="padding:13px 16px;font-size:13px;color:#555;">Temporary Password</td><td style="padding:13px 16px;font-size:15px;font-weight:900;color:#111;letter-spacing:2px;">${pmTempPassword}</td></tr></table></div><p style="font-size:13px;color:#555;line-height:1.6;margin:0 0 28px;">You will receive a monthly portfolio summary on the 1st of each month covering all your properties.</p><div style="background:#f5f5f7;border-radius:12px;padding:16px 20px;"><p style="font-size:13px;color:#333;margin:0;">Questions? <a href="mailto:support@fitmakesenz.com" style="color:#1E5FBE;">support@fitmakesenz.com</a></p></div></div><div style="background:#fafafa;border-top:1px solid #eee;padding:20px 40px;"><p style="font-size:11px;color:#aaa;margin:0;">Senz · AmenityFit™ · amenityfit.app</p></div></div></body></html>`;
                          await fetch("https://us-central1-amenityfit-31276.cloudfunctions.net/sendActivationEmail", {
                            method: "POST",
                            headers: { "Content-Type": "application/json" },
                            body: JSON.stringify({ to: batchPmEmail.trim(), subject: `Your AmenityFit Portfolio Dashboard is Ready — ${batchCompanyName}`, html: pmEmailHtml, secret: "amenityfit-activation-2026" }),
                          });
                        }
                      } catch (pmErr: any) {
                        console.error("PM exec account creation failed:", pmErr.message);
                      }
                    }

                    setBatchActivating(false);
                    setBatchComplete(true);
                  }}
                  disabled={batchParsed.every(b => !b.valid)}
                  style={{ width: "100%", padding: "16px", borderRadius: 16, border: "none", background: `linear-gradient(135deg, ${COLORS.success}, #1a9e4a)`, color: COLORS.white, fontSize: 15, fontWeight: 700, cursor: "pointer", marginTop: 8 }}
                >
                  Activate All {batchParsed.filter(b => b.valid).length} Buildings →
                </button>
              </>
            )}

            {batchActivating && (
              <div style={{ textAlign: "center", padding: "40px 0" }}>
                <p style={{ color: COLORS.white, fontSize: 18, fontWeight: 700, margin: "0 0 8px" }}>Activating Buildings...</p>
                <p style={{ color: COLORS.accent, fontSize: 32, fontWeight: 900, margin: "0 0 8px" }}>{batchProgress.done}/{batchProgress.total}</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: "0 0 24px" }}>Current: {batchProgress.current}</p>
                <div style={{ background: COLORS.card, borderRadius: 99, height: 8, overflow: "hidden" }}>
                  <div style={{ background: `linear-gradient(90deg, ${COLORS.primary}, ${COLORS.accent})`, height: "100%", width: `${batchProgress.total > 0 ? (batchProgress.done / batchProgress.total) * 100 : 0}%`, transition: "width 0.3s ease", borderRadius: 99 }} />
                </div>
              </div>
            )}

            {batchComplete && (
              <div style={{ textAlign: "center", padding: "40px 0" }}>
                <p style={{ color: COLORS.success, fontSize: 40, margin: "0 0 12px" }}>✓</p>
                <p style={{ color: COLORS.white, fontSize: 20, fontWeight: 900, margin: "0 0 8px" }}>Batch Activation Complete</p>
                <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: "0 0 24px" }}>{batchProgress.total - batchProgress.errors.length} buildings activated · {batchProgress.errors.length} errors</p>
                {batchProgress.errors.length > 0 && (
                  <div style={{ background: "#FF4D4D15", border: "1px solid #FF4D4D40", borderRadius: 12, padding: "12px 16px", marginBottom: 20, textAlign: "left" }}>
                    {batchProgress.errors.map((e, i) => <p key={i} style={{ color: "#FF6B6B", fontSize: 12, margin: "0 0 4px" }}>{e}</p>)}
                  </div>
                )}
                <button
                  onClick={() => { setBatchInput(""); setBatchCompanyName(""); setBatchPmEmail(""); setBatchParsed([]); setBatchReviewMode(false); setBatchComplete(false); setBatchProgress({ done: 0, total: 0, current: "", errors: [] }); }}
                  style={{ padding: "14px 32px", borderRadius: 14, border: "none", background: COLORS.card, color: COLORS.white, fontSize: 14, fontWeight: 600, cursor: "pointer" }}
                >
                  Activate Another Batch
                </button>
              </div>
            )}
          </div>
        )}

        {activeTab === "revenue" && (() => {
          const getPricingTier = (units: number) => {
            if (units <= 50) return { label: "Starter", monthly: 599 };
            if (units <= 100) return { label: "Growth", monthly: 999 };
            if (units <= 200) return { label: "Scale", monthly: 1499 };
            if (units <= 300) return { label: "Pro", monthly: 1999 };
            if (units <= 500) return { label: "Enterprise", monthly: 2799 };
            if (units <= 1000) return { label: "Enterprise+", monthly: 3999 };
            return { label: "Custom", monthly: 0 };
          };

          const activeRevBuildings = allBuildings.filter(b =>
            b.subscription === "active" &&
            !(b.isTest || (b.name || "").toLowerCase().includes("test"))
          );

          const mrr = activeRevBuildings.reduce((sum, b) => {
            const tier = getPricingTier(b.units || 0);
            return sum + tier.monthly;
          }, 0);

          const arr = mrr * 12;

          // Upcoming renewals in next 60 days
          const now = new Date();
          const in60 = new Date(now.getTime() + 60 * 24 * 60 * 60 * 1000);
          const upcomingRenewals = allBuildings
            .filter(b => {
              if (!b.renewalDate) return false;
              const d = new Date(b.renewalDate);
              return d >= now && d <= in60;
            })
            .sort((a, b) => new Date(a.renewalDate).getTime() - new Date(b.renewalDate).getTime());

          return (
            <>
              {/* MRR / ARR cards */}
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Revenue Overview</p>
              <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
                <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                  <p style={{ color: COLORS.success, fontSize: 26, fontWeight: 900, margin: "0 0 4px" }}>${mrr.toLocaleString()}</p>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>MRR</p>
                </div>
                <div style={{ flex: 1, background: COLORS.card, borderRadius: 16, padding: "16px 14px", border: `1px solid ${COLORS.border}` }}>
                  <p style={{ color: COLORS.accent, fontSize: 26, fontWeight: 900, margin: "0 0 4px" }}>${arr.toLocaleString()}</p>
                  <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.8, margin: 0 }}>ARR</p>
                </div>
              </div>

              {/* Upcoming renewals */}
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Renewals in Next 60 Days</p>
              {upcomingRenewals.length === 0 ? (
                <div style={{ background: COLORS.card, borderRadius: 14, padding: "16px", border: `1px solid ${COLORS.border}`, marginBottom: 20 }}>
                  <p style={{ color: COLORS.textSecondary, fontSize: 13, margin: 0, textAlign: "center" }}>No renewals due in the next 60 days.</p>
                </div>
              ) : (
                <div style={{ background: COLORS.card, borderRadius: 18, padding: "4px 20px", border: `1px solid ${COLORS.border}`, marginBottom: 20 }}>
                  {upcomingRenewals.map((b, i) => {
                    const daysUntil = Math.ceil((new Date(b.renewalDate).getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
                    const isUrgent = daysUntil <= 7;
                    return (
                      <div key={b.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 0", borderBottom: i < upcomingRenewals.length - 1 ? `1px solid ${COLORS.border}` : "none" }}>
                        <div>
                          <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: "0 0 2px" }}>{b.name}</p>
                          <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{new Date(b.renewalDate).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</p>
                        </div>
                        <div style={{ background: isUrgent ? "#FF4D4D20" : `${COLORS.primary}20`, borderRadius: 99, padding: "4px 12px" }}>
                          <span style={{ color: isUrgent ? "#FF4D4D" : COLORS.accent, fontSize: 12, fontWeight: 700 }}>{daysUntil}d</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}

              {/* Per-building revenue breakdown */}
              <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 12px" }}>Buildings</p>
              <div style={{ background: COLORS.card, borderRadius: 18, padding: "4px 20px", border: `1px solid ${COLORS.border}` }}>
                {activeRevBuildings.length === 0 && (
                  <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", padding: "20px 0", margin: 0 }}>No active buildings yet.</p>
                )}
                {activeRevBuildings.map((b, i) => {
                  const tier = getPricingTier(b.units || 0);
                  const renewalDate = b.renewalDate ? new Date(b.renewalDate).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }) : "Not set";
                  return (
                    <div key={b.id} style={{ padding: "14px 0", borderBottom: i < activeRevBuildings.length - 1 ? `1px solid ${COLORS.border}` : "none" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 4 }}>
                        <p style={{ color: COLORS.white, fontSize: 14, fontWeight: 700, margin: 0 }}>{b.name}</p>
                        <p style={{ color: COLORS.success, fontSize: 14, fontWeight: 700, margin: 0 }}>${tier.monthly.toLocaleString()}/mo</p>
                      </div>
                      <div style={{ display: "flex", justifyContent: "space-between" }}>
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>{b.units || 0} units, {tier.label}</p>
                        <p style={{ color: COLORS.textSecondary, fontSize: 12, margin: 0 }}>Renews {renewalDate}</p>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          );
        })()}
      </div>
    </div>
  );
};
