const ManagerLoginScreen = ({ onLogin, onBack }: { onLogin: (profile: any) => void; onBack: () => void }) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!email || !password) { setError("Please enter your email and password."); return; }
    setError("");
    setLoading(true);
    try {
      const credential = await signInWithEmailAndPassword(auth, email.trim(), password);
      const uid = credential.user.uid;
      const profile = await loadUserProfile(uid);
      if (!profile) { setError("No manager account found. Contact support@fitmakesenz.com."); setLoading(false); return; }
      if (profile.role !== "manager" && profile.role !== "property_manager") { setError("This account does not have manager access."); setLoading(false); return; }
      // Check if building is churned and past cancellation date
      if (profile.buildingId) {
        try {
          const { getDoc, doc } = await import("firebase/firestore");
          const bSnap = await getDoc(doc(db, "buildings", profile.buildingId));
          if (bSnap.exists()) {
            const bData = bSnap.data();
            if (bData.subscription === "churned") {
              const cancelDate = bData.cancellationDate ? new Date(bData.cancellationDate) : null;
              const today = new Date();
              today.setHours(0, 0, 0, 0);
              if (!cancelDate || today >= cancelDate) {
                setError("Your building's AmenityFit subscription has ended. Contact support@fitmakesenz.com for assistance.");
                setLoading(false);
                return;
              }
            }
          }
        } catch (e) {
          console.error("Manager building status check error:", e);
        }
      }
      onLogin(profile);
    } catch (e: any) {
      setLoading(false);
      if (e.code === "auth/user-not-found" || e.code === "auth/wrong-password" || e.code === "auth/invalid-credential") {
        setError("Email or password is incorrect.");
      } else if (e.code === "auth/too-many-requests") {
        setError("Too many attempts. Please try again in a few minutes.");
      } else {
        setError("Sign in failed. Please check your connection and try again.");
      }
    }
  };

  const inputStyle = (filled: boolean) => ({
    width: "100%", padding: "16px 18px", borderRadius: 14,
    border: `1.5px solid ${filled ? COLORS.accent : COLORS.border}`,
    background: COLORS.card, color: COLORS.white, fontSize: 15,
    fontFamily: "'Inter', sans-serif", outline: "none",
    boxSizing: "border-box" as const, transition: "all 0.2s ease", marginBottom: 14,
  });

  return (
    <div style={{ height: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", overflowY: "auto" }}>
      <div style={{ padding: "52px 24px 32px", background: `linear-gradient(180deg, ${COLORS.primary}20 0%, transparent 100%)` }}>
        <button onClick={onBack} style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, width: 40, height: 40, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", marginBottom: 28 }}>
          <ArrowLeft size={18} color={COLORS.white} />
        </button>
        <div style={{ display: "inline-flex", alignItems: "center", background: `${COLORS.primary}25`, borderRadius: 99, padding: "5px 14px", marginBottom: 14 }}>
          <Building2 size={12} color={COLORS.accent} style={{ marginRight: 6 }} />
          <span style={{ color: COLORS.accent, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase" }}>Building Manager Portal</span>
        </div>
        <h1 style={{ color: COLORS.white, fontSize: 26, fontWeight: 900, margin: "0 0 6px", letterSpacing: -0.5 }}>Manager Login</h1>
        <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: 0 }}>Access your building's AmenityFit dashboard.</p>
      </div>

      <div style={{ padding: "24px 24px 40px" }}>
        <input type="email" placeholder="Manager email" value={email} onChange={e => setEmail(e.target.value)} style={inputStyle(!!email)} />
        <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} style={inputStyle(!!password)} />

        {error && (
          <div style={{ background: "#FF4D4D15", border: "1px solid #FF4D4D40", borderRadius: 12, padding: "12px 16px", marginBottom: 16 }}>
            <p style={{ color: "#FF6B6B", fontSize: 13, margin: 0 }}>{error}</p>
          </div>
        )}

<button onClick={handleLogin} disabled={loading} style={{ width: "100%", padding: "18px", borderRadius: 16, border: "none", background: loading ? COLORS.border : `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, color: loading ? COLORS.textSecondary : COLORS.white, fontSize: 16, fontWeight: 700, cursor: loading ? "not-allowed" : "pointer", boxShadow: loading ? "none" : `0 8px 30px ${COLORS.primary}40`, marginBottom: 16 }}>
          {loading ? "Signing in..." : "Sign In to Dashboard"}
        </button>

        <p style={{ color: COLORS.textSecondary, fontSize: 13, textAlign: "center", margin: 0, lineHeight: 1.6 }}>
          Manager accounts are set up by AmenityFit.<br />
          Contact <span style={{ color: COLORS.accent }}>support@fitmakesenz.com</span> for access.
        </p>
      </div>
    </div>
  );
};

