// Retention color thresholds — calibrated for building amenity context (not dedicated gym)
// Thresholds account for natural attrition across the 30-day window.
// A building performing consistently at each benchmark reads as green throughout.
// Orange = worth a proactive conversation. Red = intervention needed.
//
// Day 7:  Green 55%+  | Orange 35-54%  | Red <35%
// Day 14: Green 42%+  | Orange 25-41%  | Red <25%
// Day 30: Green 35%+  | Orange 20-34%  | Red <20%
//
// Logic: a building at exactly the green/orange boundary at Day 7 (55%)
// experiencing normal ~20% monthly attrition lands at ~44% by Day 14 (still green)
// and ~35% by Day 30 (still green). The curve tells a consistent story.
const getRetentionColor = (label: string, pct: number): string => {
  if (label === "Day 7")  return pct >= 55 ? COLORS.success : pct >= 35 ? "#F39C12" : "#E74C3C";
  if (label === "Day 14") return pct >= 42 ? COLORS.success : pct >= 25 ? "#F39C12" : "#E74C3C";
  if (label === "Day 30") return pct >= 35 ? COLORS.success : pct >= 20 ? "#F39C12" : "#E74C3C";
  return COLORS.success;
};

const ReportSendButton = ({ buildingId, managerEmail }: { buildingId: string; managerEmail?: string }) => {
  const [email, setEmail] = React.useState(managerEmail || "");
  const [sending, setSending] = React.useState(false);
  const [status, setStatus] = React.useState<"idle" | "sent" | "error">("idle");

  const handleSend = async () => {
    if (!email || !buildingId) return;
    setSending(true);
    setStatus("idle");
    try {
      const res = await fetch("https://us-central1-amenityfit-31276.cloudfunctions.net/sendBuildingReport", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ buildingId, managerEmail: email, secret: "amenityfit-report-2026" }),
      });
      const data = await res.json();
      if (data.success) {
        setStatus("sent");
      } else {
        setStatus("error");
      }
    } catch (e) {
      setStatus("error");
    }
    setSending(false);
  };

  return (
    <div style={{ marginTop: 8 }}>
      <p style={{ color: COLORS.textSecondary, fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", margin: "0 0 10px" }}>Send Report</p>
      <input
        type="email"
        placeholder="Manager email address"
        value={email}
        onChange={e => { setEmail(e.target.value); setStatus("idle"); }}
        style={{ width: "100%", padding: "14px 16px", borderRadius: 14, border: `1.5px solid ${status === "error" ? "#FF4D4D" : status === "sent" ? "#22C55E" : email ? COLORS.accent : COLORS.border}`, background: COLORS.card, color: COLORS.white, fontSize: 14, fontFamily: "'Inter', sans-serif", outline: "none", boxSizing: "border-box" as const, marginBottom: 10 }}
      />
      <button
        onClick={handleSend}
        disabled={sending || !email || !buildingId}
        style={{ width: "100%", padding: "16px", borderRadius: 16, border: "none", background: sending || !email ? COLORS.border : status === "sent" ? "#22C55E" : `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, color: sending || !email ? COLORS.textSecondary : COLORS.white, fontSize: 14, fontWeight: 700, cursor: sending || !email ? "not-allowed" : "pointer", transition: "all 0.2s ease" }}
      >
        {sending ? "Sending..." : status === "sent" ? "✓ Report Sent" : status === "error" ? "Send Failed — Retry" : "Send Report Now"}
      </button>
      {status === "sent" && (
        <p style={{ color: "#22C55E", fontSize: 12, textAlign: "center", margin: "10px 0 0", lineHeight: 1.5 }}>
          Report delivered to {email}. You received a copy at itmakesenzfitness@gmail.com.
        </p>
      )}
      {status === "error" && (
        <p style={{ color: "#FF6B6B", fontSize: 12, textAlign: "center", margin: "10px 0 0", lineHeight: 1.5 }}>
          Failed to send. Check your connection and try again.
        </p>
      )}
      <p style={{ color: COLORS.textSecondary, fontSize: 11, textAlign: "center", margin: "10px 0 0", lineHeight: 1.5 }}>
        Reports auto-deliver on the 1st of each month. Use this to send on demand.
      </p>
    </div>
  );
};

const ForcePasswordChangeScreen = ({ userProfile, onComplete, onSignOut }) => {
  const [newPassword, setNewPassword] = React.useState("");
  const [confirmPassword, setConfirmPassword] = React.useState("");
  const [error, setError] = React.useState("");
  const [saving, setSaving] = React.useState(false);
  const [showNew, setShowNew] = React.useState(false);
  const [showConfirm, setShowConfirm] = React.useState(false);

  const handleSubmit = async () => {
    setError("");
    if (newPassword.length < 8) { setError("Password must be at least 8 characters."); return; }
    if (newPassword !== confirmPassword) { setError("Passwords don't match."); return; }
    setSaving(true);
    try {
      const user = auth.currentUser;
      if (!user) throw new Error("No user");
      const { updatePassword } = await import("firebase/auth");
      await updatePassword(user, newPassword);
      await updateDoc(doc(db, "users", user.uid), { passwordChangeRequired: false });
      onComplete();
    } catch (e: any) {
      if (e.code === "auth/requires-recent-login") {
        setError("Session expired. Please sign out and log in again.");
      } else {
        setError("Failed to update password. Please try again.");
      }
    }
    setSaving(false);
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.background, fontFamily: "'Inter', sans-serif", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "24px" }}>
      <div style={{ width: "100%", maxWidth: 400 }}>
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <div style={{ width: 56, height: 56, borderRadius: 16, background: `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px", fontSize: 24 }}>🔐</div>
          <h1 style={{ color: COLORS.white, fontSize: 24, fontWeight: 900, margin: "0 0 8px", letterSpacing: -0.5 }}>Set Your Password</h1>
          <p style={{ color: COLORS.textSecondary, fontSize: 14, margin: 0, lineHeight: 1.5 }}>You're using a temporary password. Create a permanent one to continue.</p>
        </div>

        <div style={{ background: COLORS.card, borderRadius: 20, padding: 24, border: `1px solid ${COLORS.border}` }}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ color: COLORS.textSecondary, fontSize: 12, fontWeight: 600, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 8 }}>New Password</label>
            <div style={{ position: "relative" }}>
              <input
                type={showNew ? "text" : "password"}
                value={newPassword}
                onChange={e => setNewPassword(e.target.value)}
                placeholder="Min. 8 characters"
                style={{ width: "100%", padding: "14px 44px 14px 16px", borderRadius: 12, border: `1px solid ${COLORS.border}`, background: COLORS.background, color: COLORS.white, fontSize: 15, fontFamily: "'Inter', sans-serif", boxSizing: "border-box" as any, outline: "none" }}
              />
              <button onClick={() => setShowNew(p => !p)} style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: COLORS.textSecondary, cursor: "pointer", fontSize: 13 }}>{showNew ? "Hide" : "Show"}</button>
            </div>
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ color: COLORS.textSecondary, fontSize: 12, fontWeight: 600, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 8 }}>Confirm Password</label>
            <div style={{ position: "relative" }}>
              <input
                type={showConfirm ? "text" : "password"}
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="Repeat your password"
                onKeyDown={e => { if (e.key === "Enter") handleSubmit(); }}
                style={{ width: "100%", padding: "14px 44px 14px 16px", borderRadius: 12, border: `1px solid ${COLORS.border}`, background: COLORS.background, color: COLORS.white, fontSize: 15, fontFamily: "'Inter', sans-serif", boxSizing: "border-box" as any, outline: "none" }}
              />
              <button onClick={() => setShowConfirm(p => !p)} style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: COLORS.textSecondary, cursor: "pointer", fontSize: 13 }}>{showConfirm ? "Hide" : "Show"}</button>
            </div>
          </div>

          {error && <p style={{ color: "#FF6B6B", fontSize: 13, margin: "0 0 16px", textAlign: "center" }}>{error}</p>}

          <button
            onClick={handleSubmit}
            disabled={saving}
            style={{ width: "100%", padding: "16px", borderRadius: 14, border: "none", background: saving ? COLORS.border : `linear-gradient(135deg, ${COLORS.primary}, ${COLORS.accent})`, color: COLORS.white, fontSize: 16, fontWeight: 700, cursor: saving ? "not-allowed" : "pointer", fontFamily: "'Inter', sans-serif" }}
          >
            {saving ? "Saving..." : "Set Password & Continue"}
          </button>
        </div>

        <button onClick={onSignOut} style={{ display: "block", margin: "16px auto 0", background: "none", border: "none", color: COLORS.textSecondary, fontSize: 13, cursor: "pointer" }}>Sign out</button>
      </div>
    </div>
  );
};

